# ───────────────────────────── tiny helpers ─────────────────────────────
line() { printf '%s%s%s\n' "$C_DIM" '──────────────────────────────────────────────────────────────' "$C_RESET"; }
command_exists() { command -v "$1" >/dev/null 2>&1; }

# Copy stdin to the OS clipboard. 0 on success, 1 if no tool (headless). Never fails the caller.
copy_to_clipboard() {
  if command_exists pbcopy; then pbcopy
  elif command_exists wl-copy; then wl-copy
  elif command_exists xclip; then xclip -selection clipboard
  elif command_exists xsel; then xsel --clipboard --input
  else cat >/dev/null; return 1
  fi
}

safe_name() {
  printf '%s' "$1" | tr '[:upper:]' '[:lower:]' \
    | sed -E 's/[^a-z0-9]+/_/g; s/^_+//; s/_+$//; s/_+/_/g'
}

trim() { printf '%s' "$1" | sed -E 's/^[[:space:]]+//; s/[[:space:]]+$//'; }

prompt_printf() { printf "$@" >&2; }

read_user_line() {
  local __out_var="$1" __line=""
  IFS= read -r __line || true
  printf -v "$__out_var" '%s' "$__line"
}

# Read a secret twice without echo until the two entries are non-empty AND match, then
# assign it to the named variable. Prints a clear note on empty/mismatch instead of silently
# re-prompting. Shared by the admin password and the vault passphrase so both are confirmed.
read_secret_confirmed() {
  local __var="$1" __label="$2" __p1 __p2
  while true; do
    printf '  %s: ' "$__label"; stty -echo 2>/dev/null; IFS= read -r __p1 || true; stty echo 2>/dev/null; printf '\n'
    if [ -z "$__p1" ]; then printf '  %s%s%s\n' "$C_YELLOW" "$(t pw_empty)" "$C_RESET"; continue; fi
    printf '  %s: ' "$(t pw_repeat)"; stty -echo 2>/dev/null; IFS= read -r __p2 || true; stty echo 2>/dev/null; printf '\n'
    if [ "$__p1" = "$__p2" ]; then printf -v "$__var" '%s' "$__p1"; break; fi
    printf '  %s%s%s\n' "$C_YELLOW" "$(t pw_mismatch)" "$C_RESET"
  done
}

pause() {
  is_interactive || return 0
  printf '\n%s ' "$(t press_enter)" >&2
  IFS= read -r _ || true
}

# ask "<prompt>" "<default>" -> echoes the answer (or default).
ask() {
  local prompt="$1" default="${2:-}" value=""
  if [ "$NONINTERACTIVE" = "1" ]; then printf '%s' "$default"; return 0; fi
  if [ -n "$default" ]; then prompt_printf '%s [%s]: ' "$prompt" "$default"; else prompt_printf '%s: ' "$prompt"; fi
  read_user_line value
  value="$(trim "$value")"
  if [ -z "$value" ]; then printf '%s' "$default"; else printf '%s' "$value"; fi
}

# prompt_set VAR "<prompt>" "<default>" -> assigns the answer to VAR.
prompt_set() {
  local __var="$1" __prompt="$2" __default="${3:-}" __value=""
  if [ "$NONINTERACTIVE" = "1" ]; then printf -v "$__var" '%s' "$__default"; return 0; fi
  if [ -n "$__default" ]; then prompt_printf '%s [%s]: ' "$__prompt" "$__default"; else prompt_printf '%s: ' "$__prompt"; fi
  read_user_line __value
  __value="$(trim "$__value")"
  [ -z "$__value" ] && __value="$__default"
  printf -v "$__var" '%s' "$__value"
}

# confirm "<prompt>" "<Y|N default>" -> 0 yes / 1 no.
confirm() {
  local prompt="$1" default="${2:-Y}" suffix='[Y/n]' answer=''
  case "$default" in n|N|no|NO|нет|НЕТ) suffix='[y/N]' ;; *) suffix='[Y/n]' ;; esac
  if [ "$NONINTERACTIVE" = "1" ]; then
    case "$default" in y|Y|yes|YES|да|ДА) return 0 ;; *) return 1 ;; esac
  fi
  prompt_printf '%s%s%s %s: ' "$C_YELLOW" "$prompt" "$C_RESET" "$suffix"
  read_user_line answer
  answer="$(trim "$answer")"; [ -z "$answer" ] && answer="$default"
  answer="$(printf '%s' "$answer" | tr -d '[][:space:]')"
  case "$answer" in y|Y|yes|YES|Yes|д|Д|да|ДА|Да) return 0 ;; *) return 1 ;; esac
}

# bool_label true|false -> localized on/off.
bool_label() { [ "${1:-false}" = "true" ] && printf '%s' "$(t on)" || printf '%s' "$(t off)"; }

# ───────────────────────────── compact one-line menus ─────────────────────────────
# Display width: ANSI stripped, UTF-8 aware (one Cyrillic/box char = 1 column).
vwidth() {
  local s b cont
  s="$(printf '%s' "$1" | sed $'s/\033\\[[0-9;]*m//g')"
  b=$(printf '%s' "$s" | LC_ALL=C wc -c); b="${b//[[:space:]]/}"
  cont=$(printf '%s' "$s" | LC_ALL=C tr -dc $'\200-\277' | wc -c); cont="${cont//[[:space:]]/}"
  printf '%d' $(( b - cont ))
}

# inline_opt key label -> "[key] label" with a cyan key. No newline.
inline_opt() { printf '%s[%s]%s %s' "$C_CYAN" "$1" "$C_RESET" "$2"; }

# menu_line "<title>" key1 label1 key2 label2 ...  -> one aligned row:
#   Title     [a] one        [b] two        [c] three
# The dim title is padded to a fixed column; each option is padded so options line
# up in columns across rows (the two-column / grid layout).
MENU_LABEL_W="${MENU_LABEL_W:-10}"
MENU_OPT_W="${MENU_OPT_W:-16}"
menu_line() {
  local title="$1"; shift
  local pad; pad=$(( MENU_LABEL_W - $(vwidth "$title") )); [ "$pad" -lt 1 ] && pad=1
  printf '  %s%s%s%*s' "$C_DIM" "$title" "$C_RESET" "$pad" ''
  local opt ow
  while [ $# -ge 2 ]; do
    opt="$(inline_opt "$1" "$2")"; ow=$(( MENU_OPT_W - $(vwidth "$opt") )); [ "$ow" -lt 1 ] && ow=1
    printf '%s%*s' "$opt" "$ow" ''
    shift 2
  done
  printf '\n'
}

# ───────────────────────────── step spinner ─────────────────────────────
SPIN_FRAMES='⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏'
STEP_NUM=0
STEP_TOTAL=0

# run_step "<label>" cmd args... -> spinner while running, ✔/✖ at the end.
run_step() {
  local label="$1"; shift
  local prefix=""
  if [ "$STEP_TOTAL" -gt 0 ]; then
    STEP_NUM=$((STEP_NUM + 1))
    prefix="$(printf '%s[%d/%d]%s ' "$C_DIM" "$STEP_NUM" "$STEP_TOTAL" "$C_RESET")"
  fi
  if ! is_tty; then
    printf '%s%s …\n' "$prefix" "$label"
    "$@"; return $?
  fi
  local logf rc i frame pid
  logf="$(mktemp)"
  ("$@") >"$logf" 2>&1 &
  pid=$!
  i=0
  while kill -0 "$pid" 2>/dev/null; do
    frame="${SPIN_FRAMES:$((i % ${#SPIN_FRAMES})):1}"
    printf '\r%s%s%s%s %s ' "$prefix" "$C_CYAN" "$frame" "$C_RESET" "$label" >&2
    i=$((i + 1)); sleep 0.1
  done
  rc=0; wait "$pid" || rc=$?
  if [ "$rc" -eq 0 ]; then
    printf '\r%s%s✔%s %s\033[K\n' "$prefix" "$C_GREEN" "$C_RESET" "$label" >&2
  else
    printf '\r%s%s✖%s %s\033[K\n' "$prefix" "$C_RED" "$C_RESET" "$label" >&2
    printf '%s\n' "${C_DIM}--- output ---${C_RESET}" >&2
    tail -n 40 "$logf" >&2
  fi
  rm -f "$logf"
  return $rc
}
# ───────────────────────────── screen / os ─────────────────────────────
clear_screen() { if is_tty; then clear 2>/dev/null || true; fi; return 0; }

detect_arch() {
  case "$(uname -m 2>/dev/null)" in
    arm64|aarch64) ARCH_TYPE="arm64" ;;
    x86_64|amd64)  ARCH_TYPE="x64" ;;
    i386|i686)     ARCH_TYPE="x86" ;;
    *)             ARCH_TYPE="unknown" ;;
  esac
}

detect_os() {
  case "$(uname -s)" in
    Darwin) OS_TYPE="macos" ;;
    Linux)  OS_TYPE="linux" ;;
    *)      OS_TYPE="unknown" ;;
  esac
  detect_arch
}

os_pretty() {
  case "$OS_TYPE" in
    macos) printf 'macOS %s (%s)' "$(sw_vers -productVersion 2>/dev/null)" "$(uname -m)";;
    linux)
      if [ -r /etc/os-release ]; then
        # shellcheck disable=SC1091
        . /etc/os-release; printf '%s (%s)' "${PRETTY_NAME:-Linux}" "$(uname -m)"
      else printf 'Linux (%s)' "$(uname -m)"; fi ;;
    *) printf '%s' "$(uname -srm)";;
  esac
}

host_ip() {
  local ip=""
  case "$OS_TYPE" in
    macos)
      ip="$(ipconfig getifaddr en0 2>/dev/null || true)"
      [ -z "$ip" ] && ip="$(ipconfig getifaddr en1 2>/dev/null || true)" ;;
    linux)
      ip="$(hostname -I 2>/dev/null | awk '{print $1}')"
      [ -z "$ip" ] && ip="$(ip route get 1.1.1.1 2>/dev/null | awk '/src/ {print $7; exit}')" ;;
  esac
  [ -z "$ip" ] && ip="n/a"
  printf '%s' "$ip"
}

# ───────────────────────────── runtime metrics ─────────────────────────────
ncpu() { sysctl -n hw.ncpu 2>/dev/null || nproc 2>/dev/null || echo 1; }
sys_disk_pct() { df -P / 2>/dev/null | awk 'NR==2{gsub(/%/,"",$5); print $5}'; }
sys_ram_pct() {
  case "$OS_TYPE" in
    macos)
      local ps total f="" i="" sp=""
      ps=$(sysctl -n hw.pagesize 2>/dev/null || echo 4096)
      total=$(sysctl -n hw.memsize 2>/dev/null || echo 0)
      [ "${total:-0}" -gt 0 ] 2>/dev/null || return 0
      eval "$(vm_stat 2>/dev/null | awk -F: '
        /Pages free/        {gsub(/[ .]/,"",$2); print "f="$2}
        /Pages inactive/    {gsub(/[ .]/,"",$2); print "i="$2}
        /Pages speculative/ {gsub(/[ .]/,"",$2); print "sp="$2}')"
      local avail=$(( ( ${f:-0} + ${i:-0} + ${sp:-0} ) * ps ))
      printf '%d' $(( (total - avail) * 100 / total )) ;;
    linux) free 2>/dev/null | awk '/^Mem:/{ if($2>0) printf "%d", $3/$2*100; exit }' ;;
  esac
}
sys_cpu_pct() {
  local la nc; nc="$(ncpu)"
  la="$(uptime 2>/dev/null | sed -n 's/.*load average[s]*:[ ]*\([0-9.]*\).*/\1/p')"
  [ -n "$la" ] || return 0
  awk -v l="$la" -v n="$nc" 'BEGIN{ if(n<1)n=1; v=l/n*100; if(v>100)v=100; printf "%d", v }'
}
docker_server_version() { docker version --format '{{.Server.Version}}' 2>/dev/null; }
docker_vm_info() {
  local raw nc mem; raw="$(docker info --format '{{.NCPU}}|{{.MemTotal}}' 2>/dev/null)" || raw=""
  [ -n "$raw" ] || return 0
  nc="${raw%%|*}"; mem="${raw##*|}"
  awk -v c="$nc" -v m="$mem" 'BEGIN{ printf "%s vCPU / %.1f GB", c, m/1073741824 }'
}
pct_or_dash() { case "${1:-}" in ''|-) printf '—' ;; *) printf '%s%%' "$1" ;; esac; }
status_dot() { printf '%s●%s' "${1:-$C_GREEN}" "$C_RESET"; }

RT_HOST="" RT_IP="" RT_RAM="" RT_CPU="" RT_DISK="" RT_DVER="" RT_DVM=""
collect_runtime() {
  RT_HOST="$(hostname 2>/dev/null)"
  # shellcheck disable=SC2034
  RT_IP="$(host_ip)"
  RT_DISK="$(pct_or_dash "$(sys_disk_pct)")"
  RT_RAM="$(pct_or_dash "$(sys_ram_pct)")"
  RT_CPU="$(pct_or_dash "$(sys_cpu_pct)")"
  if command_exists docker && docker info >/dev/null 2>&1; then
    RT_DVER="$(docker_server_version || true)"; [ -n "$RT_DVER" ] || RT_DVER="—"
    RT_DVM="$(docker_vm_info || true)";         [ -n "$RT_DVM" ]  || RT_DVM="—"
  else RT_DVER="—"; RT_DVM="—"; fi
}

# Dashboard section header: a bold-cyan title with a dim horizontal rule beneath it, so the
# Host / Components / Network / Secrets blocks read as cleanly separated sections.
section_header() {
  # shellcheck disable=SC2046
  printf '\n  %s%s%s\n  %s%s%s\n' "$C_B$C_CYAN" "$1" "$C_RESET" \
    "$C_DIM" "$(printf '─%.0s' $(seq 1 50))" "$C_RESET"
}

render_runtime() {
  local hc="$C_GREEN" dc="$C_GREEN"
  [ "${UPDATE_AVAILABLE:-false}" = "true" ] && hc="$C_YELLOW"
  [ "$RT_DVER" = "—" ] && dc="$C_RED"
  section_header "$(t sec_runtime)"
  printf '    %s %s%-8s%s %s%-16s%s  %sRAM:%s %-5s %sCPU:%s %-5s %sDISK:%s %-5s\n' \
    "$(status_dot "$hc")" "$C_DIM" "HOST:" "$C_RESET" "$C_B" "$RT_HOST" "$C_RESET" \
    "$C_DIM" "$C_RESET" "$RT_RAM" "$C_DIM" "$C_RESET" "$RT_CPU" "$C_DIM" "$C_RESET" "$RT_DISK"
  printf '    %s %s%-8s%s %s%-16s%s  %sVM:%s %s\n' \
    "$(status_dot "$dc")" "$C_DIM" "DOCKER:" "$C_RESET" "$C_B" "$RT_DVER" "$C_RESET" \
    "$C_DIM" "$C_RESET" "$RT_DVM"
}

# ───────────────────────────── headers ─────────────────────────────
header_install() {
  clear_screen
  banner_install
  collect_runtime
  render_runtime
  printf '\n'
}

# Light header for sub-screens (breadcrumb only).
sub_header() {
  clear_screen
  printf '%s%s%s %s›%s %s%s%s\n\n' \
    "$C_B" "$PRODUCT_NAME" "$C_RESET" "$C_DIM" "$C_RESET" "$C_B$C_CYAN" "$1" "$C_RESET"
}

# ───────────────────────────── language ─────────────────────────────
load_lang() {
  if [ -n "$UI_LANG" ]; then return 0; fi
  if [ -f "$LANG_STORE" ]; then UI_LANG="$(tr -d '[:space:]' < "$LANG_STORE" 2>/dev/null)"; fi
  case "$UI_LANG" in ru|en) ;; *) UI_LANG="" ;; esac
}
save_lang() {
  mkdir -p "$(dirname "$LANG_STORE")" 2>/dev/null || true
  printf '%s\n' "$UI_LANG" > "$LANG_STORE" 2>/dev/null || true
}
choose_lang() {
  if [ "$NONINTERACTIVE" = "1" ]; then [ -z "$UI_LANG" ] && UI_LANG="en"; return 0; fi
  clear_screen; banner_install; printf '\n'
  printf '  %s\n\n' "$(t lang_pick)"
  printf '   %s[1]%s English\n' "$C_B" "$C_RESET"
  printf '   %s[2]%s Русский\n\n' "$C_B" "$C_RESET"
  local c=""; printf '  > '; read_user_line c; c="$(trim "$c")"
  case "$c" in 2|ru|RU|р|Р) UI_LANG="ru" ;; *) UI_LANG="en" ;; esac
  save_lang
}
saved_lang_from_stack() {
  local envf v
  for envf in "$SCRIPT_DIR/.stack.env" "$SCRIPT_DIR/../.stack.env" "${STACK_DIR:-/nonexistent}/.stack.env"; do
    [ -f "$envf" ] || continue
    v="$(sed -n 's/^UI_LANG_SAVED="\(.*\)"$/\1/p' "$envf" 2>/dev/null | head -1)"
    case "$v" in ru|en) printf '%s' "$v"; return 0 ;; esac
  done
  return 1
}
ensure_lang() {
  if [ "${LANG_FROM_ENV:-0}" != "1" ]; then
    local s; s="$(saved_lang_from_stack || true)"; [ -n "$s" ] && UI_LANG="$s"
  fi
  load_lang
  [ -z "$UI_LANG" ] && UI_LANG="$(saved_lang_from_stack || true)"
  if [ -z "$UI_LANG" ]; then choose_lang; fi
  case "$UI_LANG" in ru|en) ;; *) UI_LANG="en" ;; esac
}
# ───────────────────────────── privilege detection ─────────────────────────────
is_admin() {
  detect_os
  case "$OS_TYPE" in
    macos)
      id -Gn 2>/dev/null | tr ' ' '\n' | grep -qx admin && return 0
      dscl . -read /Groups/admin GroupMembership 2>/dev/null | tr ' ' '\n' | grep -qx "$(id -un)" && return 0
      return 1 ;;
    linux)
      id -Gn 2>/dev/null | tr ' ' '\n' | grep -Eqx 'sudo|wheel|root' && return 0
      [ "$(id -u)" = "0" ] && return 0
      return 1 ;;
    *) return 1 ;;
  esac
}

# Can we actually run sudo? True if root, passwordless sudo, or an admin user on a TTY.
can_use_sudo() {
  command_exists sudo || { [ "$(id -u)" = "0" ] && return 0 || return 1; }
  sudo -n true >/dev/null 2>&1 && return 0
  if is_admin && [ -t 0 ]; then return 0; fi
  return 1
}

# ───────────────────────────── docker / path ─────────────────────────────
ensure_path_brew() {
  case ":$PATH:" in
    *":/opt/homebrew/bin:"*) ;;
    *) [ -d /opt/homebrew/bin ] && PATH="/opt/homebrew/bin:$PATH" ;;
  esac
  case ":$PATH:" in
    *":/usr/local/bin:"*) ;;
    *) [ -d /usr/local/bin ] && PATH="/usr/local/bin:$PATH" ;;
  esac
  export PATH
  # Pin docker to the context recorded at install, so a host running both Colima and
  # Docker Desktop can't have the installer manage the wrong daemon between runs.
  [ -n "${DOCKER_CONTEXT_PIN:-}" ] && export DOCKER_CONTEXT="$DOCKER_CONTEXT_PIN"
  return 0
}

# Record the docker context actually in use (after Colima is up) so future runs target the
# same daemon. An explicit PSAI_DOCKER_CONTEXT wins; "default" isn't worth pinning (it's the
# ambient single daemon, e.g. on Linux).
capture_docker_context() {
  [ -n "${DOCKER_CONTEXT_PIN:-}" ] && { export DOCKER_CONTEXT="$DOCKER_CONTEXT_PIN"; return 0; }
  command_exists docker || return 0
  local ctx; ctx="$(docker context show 2>/dev/null || true)"
  if [ -n "$ctx" ] && [ "$ctx" != "default" ]; then
    DOCKER_CONTEXT_PIN="$ctx"; export DOCKER_CONTEXT="$ctx"
  fi
  return 0
}

detect_docker_sock() {
  if [ -S /var/run/docker.sock ] || [ -L /var/run/docker.sock ]; then
    DOCKER_SOCK="/var/run/docker.sock"; return 0
  fi
  local host=""
  command_exists docker && host="$(docker context inspect --format '{{.Endpoints.docker.Host}}' 2>/dev/null || true)"
  case "$host" in
    unix://*) DOCKER_SOCK="${host#unix://}" ;;
    *)        DOCKER_SOCK="/var/run/docker.sock" ;;
  esac
  [ -n "$DOCKER_SOCK" ] || DOCKER_SOCK="/var/run/docker.sock"
  return 0
}

# OpenHands socket: rootless mode uses the user runtime socket; otherwise the resolved one.
resolve_openhands_socket() {
  case "$OPENHANDS_DOCKER_MODE" in
    rootless) DOCKER_SOCK="${XDG_RUNTIME_DIR:-/run/user/$(id -u)}/docker.sock" ;;
    *)        detect_docker_sock ;;
  esac
}

nvidia_host_detected() {
  detect_os
  [ "$OS_TYPE" = "linux" ] || return 1
  command_exists nvidia-smi && nvidia-smi -L >/dev/null 2>&1
}

nvidia_docker_runtime_ready() {
  command_exists docker || return 1
  docker info 2>/dev/null | grep -qiE 'nvidia'
}

# Can docker give a container a GPU for Ollama? Prints: nvidia | none.
# macOS: the Linux VM (colima/Docker Desktop) has NO GPU passthrough — CPU only, even on Apple
# Silicon (Metal isn't visible inside the Linux container). Linux: needs an NVIDIA GPU + the
# nvidia container toolkit so `docker --gpus` works.
gpu_runtime() {
  if nvidia_host_detected && nvidia_docker_runtime_ready; then
    printf 'nvidia'; return 0
  fi
  printf 'none'
}
# A model that runs acceptably given the detected OS/arch/hardware.
gpu_default_model() {
  { [ "$(gpu_runtime)" = "nvidia" ] || nvidia_host_detected; } && { printf 'gemma3:4b'; return 0; }
  detect_os 2>/dev/null || true
  case "${OS_TYPE:-}:$(uname -m 2>/dev/null)" in
    macos:arm64|macos:aarch64) printf 'gemma4:e2b-it-q4_K_M' ;;
    *)                         printf 'gemma3:1b' ;;
  esac
}

# Interactive default for RAG-plus. Linux/x64 can run the Infinity embed+rerank
# image natively. macOS and Linux/arm64 default to plus only when Ollama is in
# the plan, because the installer will use Ollama embeddings there instead.
rag_plus_default_answer() {
  detect_os
  case "${OS_TYPE:-unknown}:${ARCH_TYPE:-unknown}" in
    linux:x64) printf 'Y' ;;
    macos:*|linux:arm64)
      [ "${LOCAL_LLM:-none}" = "ollama" ] && printf 'Y' || printf 'N' ;;
    *) printf 'N' ;;
  esac
}

start_colima_if_needed() {
  [ "$OS_TYPE" = "macos" ] || return 0
  command_exists docker || return 0
  docker info >/dev/null 2>&1 && return 0
  if command_exists colima; then
    printf '%s\n' "$(t env_colima)"
    colima status >/dev/null 2>&1 || colima start --cpu 4 --memory 8 --disk 60 || colima start || true
  fi
}

# ───────────────────────────── compose plumbing ─────────────────────────────
sevenzip_detect() {
  if command_exists 7zz; then SEVENZIP_BIN="7zz"
  elif command_exists 7z; then SEVENZIP_BIN="7z"
  elif command_exists 7za; then SEVENZIP_BIN="7za"
  else SEVENZIP_BIN=""; fi
}

# A single generated compose file lives in $STACK_DIR/compose/ (no upstream repo).
compose() { (cd "$STACK_DIR/compose" && docker compose -f docker-compose.yml "$@"); }
validate_compose() { compose config >/dev/null; }

docker_state() {
  if ! command_exists docker; then printf '%s' "$(t st_not_installed)"; return; fi
  if docker info >/dev/null 2>&1; then printf '%s' "$(t st_running)"; else printf '%s ✗' "$(t st_stopped)"; fi
}
# ───────────────────────────── domains ─────────────────────────────
# No-domain local mode: services answer on http://localhost:PORT instead of vhosts.
no_domain() { [ "$NO_DOMAIN" = "true" ] && [ "$DEPLOY_PROFILE" != "public" ]; }

normalize_zone() {
  local zone="$1"
  zone="$(trim "$zone")"
  zone="$(printf '%s' "$zone" | sed -E 's#^https?://##; s#/$##; s/^[.]+//; s/[.]+$//')"
  [ -z "$zone" ] && zone="local"
  printf '%s' "$zone"
}

set_domain_base_from_zone() {
  DOMAIN_ZONE="$(normalize_zone "${DOMAIN_ZONE:-$DEFAULT_DOMAIN_ZONE}")"
  DOMAIN_BASE="$DOMAIN_ZONE"
}

make_service_domain() {
  local prefix="$1"
  set_domain_base_from_zone
  printf '%s.%s' "$prefix" "$DOMAIN_BASE"
}

set_default_domains() {
  set_domain_base_from_zone
  PSAI_DOMAIN="$(make_service_domain psai)"          # Open WebUI — primary entry
  AGENTS_DOMAIN="$(make_service_domain agents)"  # OpenHands
  GIT_DOMAIN="$(make_service_domain git)"        # Forgejo web
  GIT_SSH_HOST="$GIT_DOMAIN"
  QDRANT_DOMAIN="$(make_service_domain qdrant)"  # Qdrant dashboard
}

# Public domain: edit only the SUBDOMAIN label (base zone is fixed). Local: full host.
dom_edit_default() {
  if [ "$DEPLOY_PROFILE" = "public" ] && [ -n "${PUBLIC_DOMAIN:-}" ]; then printf '%s' "${1%%.*}"; else printf '%s' "$1"; fi
}
resolve_domain_input() {
  local value current
  value="$(printf '%s' "$1" | tr -d '[:space:]')"; current="$2"
  [ -z "$value" ] && { printf '%s' "$current"; return; }
  if [ "$DEPLOY_PROFILE" = "public" ] && [ -n "${PUBLIC_DOMAIN:-}" ]; then
    case "$value" in *.*) : ;; *) value="$value.$PUBLIC_DOMAIN" ;; esac
  fi
  printf '%s' "$value"
}

default_stack_dir_for() { printf '%s/%s' "$HOME" "$1"; }

print_active_domains() {
  printf '\n%s%s%s\n' "$C_B" "$(t dom_header)" "$C_RESET"
  if no_domain; then
    [ "$ENABLE_OPENWEBUI" = "true" ] && printf '  %-18s http://localhost:%s\n' "$(t dom_psai)"     "$PORT_PSAI"
    [ "$ENABLE_AGENTS"   = "true" ] && printf '  %-18s http://localhost:%s\n' "$(t dom_agents)" "$PORT_AGENTS"
    if [ "$ENABLE_GIT" = "true" ]; then
      printf '  %-18s http://localhost:%s\n' "$(t dom_gitweb)" "$PORT_GIT"
      printf '  %-18s localhost:%s\n'        "$(t dom_gitssh)" "$GIT_SSH_PORT"
    fi
    [ "$ENABLE_QDRANT" = "true" ] && printf '  %-18s http://localhost:%s\n' "$(t dom_qdrant)" "$PORT_QDRANT"
    return 0
  fi
  [ "$ENABLE_OPENWEBUI" = "true" ] && printf '  %s[1]%s %-18s https://%s\n' "$C_CYAN" "$C_RESET" "$(t dom_psai)"     "$PSAI_DOMAIN"
  [ "$ENABLE_AGENTS"   = "true" ] && printf '  %s[2]%s %-18s https://%s\n' "$C_CYAN" "$C_RESET" "$(t dom_agents)" "$AGENTS_DOMAIN"
  if [ "$ENABLE_GIT" = "true" ]; then
    printf '  %s[3]%s %-18s https://%s\n' "$C_CYAN" "$C_RESET" "$(t dom_gitweb)"  "$GIT_DOMAIN"
    printf '  %s[4]%s %-18s %s\n'          "$C_CYAN" "$C_RESET" "$(t dom_gitssh)"  "$GIT_SSH_HOST"
    printf '  %s[5]%s %-18s %s\n'          "$C_CYAN" "$C_RESET" "$(t dom_gitport)" "$GIT_SSH_PORT"
  fi
  [ "$ENABLE_QDRANT" = "true" ] && printf '  %s[6]%s %-18s https://%s\n' "$C_CYAN" "$C_RESET" "$(t dom_qdrant)" "$QDRANT_DOMAIN"
  return 0
}

edit_single_domain() {
  local choice="$1" value=""
  choice="$(printf '%s' "$choice" | tr -d '[][:space:]')"
  case "$choice" in
    1) [ "$ENABLE_OPENWEBUI" = "true" ] || return 0; prompt_set value "$(t dom_psai)" "$(dom_edit_default "$PSAI_DOMAIN")"; PSAI_DOMAIN="$(resolve_domain_input "$value" "$PSAI_DOMAIN")" ;;
    2) [ "$ENABLE_AGENTS" = "true" ] || return 0; prompt_set value "$(t dom_agents)" "$(dom_edit_default "$AGENTS_DOMAIN")"; AGENTS_DOMAIN="$(resolve_domain_input "$value" "$AGENTS_DOMAIN")" ;;
    3) [ "$ENABLE_GIT" = "true" ] || return 0; prompt_set value "$(t dom_gitweb)" "$(dom_edit_default "$GIT_DOMAIN")"; GIT_DOMAIN="$(resolve_domain_input "$value" "$GIT_DOMAIN")" ;;
    4) [ "$ENABLE_GIT" = "true" ] || return 0; prompt_set value "$(t dom_gitssh)" "$(dom_edit_default "$GIT_SSH_HOST")"; GIT_SSH_HOST="$(resolve_domain_input "$value" "$GIT_SSH_HOST")" ;;
    5) [ "$ENABLE_GIT" = "true" ] || return 0
       prompt_set value "$(t dom_gitport)" "$GIT_SSH_PORT"
       if printf '%s' "$value" | grep -Eq '^[0-9]{1,5}$' && [ "$value" -ge 1 ] && [ "$value" -le 65535 ]; then GIT_SSH_PORT="$value"; else echo "$(t port_bad)"; fi ;;
    6) [ "$ENABLE_QDRANT" = "true" ] || return 0; prompt_set value "$(t dom_qdrant)" "$(dom_edit_default "$QDRANT_DOMAIN")"; QDRANT_DOMAIN="$(resolve_domain_input "$value" "$QDRANT_DOMAIN")" ;;
    *) echo "$(t no_such_item)" ;;
  esac
}

# Show the list, then: Enter a number to edit, 0 to continue. (Step 5 UX.)
confirm_domains_loop() {
  while true; do
    print_active_domains
    printf '\n%s\n  %s[0]%s %s\n' "$(t dom_edit_hint)" "$C_CYAN" "$C_RESET" "$(t dom_continue)"
    printf '%s: ' "$(t menu_choice)"
    local choice=""; read_user_line choice
    choice="$(printf '%s' "$(trim "$choice")" | tr -d '[][:space:]')"; [ -z "$choice" ] && choice="0"
    [ "$choice" = "0" ] && break
    edit_single_domain "$choice"
  done
}
# ───────────────────────────── step 0 · environment ─────────────────────────────
# Required host tooling. Docker is the big one; the rest are tiny CLIs.
REQUIRED_DEPS="docker git curl openssl 7z"

dep_present() {
  case "$1" in
    docker) command_exists docker ;;
    7z)     sevenzip_detect; [ -n "$SEVENZIP_BIN" ] ;;
    *)      command_exists "$1" ;;
  esac
}

# One status row: ● name  state
env_row() {
  local name="$1" ok="$2" note="$3" dot="$C_GREEN" state
  if [ "$ok" = "true" ]; then state="$note"; else dot="$C_RED"; state="$(t env_missing)"; fi
  printf '    %s %-16s %s%s%s\n' "$(status_dot "$dot")" "$name" "$C_DIM" "$state" "$C_RESET"
}

# Print the environment status table (to STDERR, so the caller can capture the return
# value cleanly) and return ONLY the space-separated missing list on stdout. NOTE: the
# table MUST go to stderr — `missing="$(env_status)"` captures stdout, and if the table
# went there too, `missing` would never be empty and the installer would always think a
# package is missing (then `brew install` on the whole table text → hang on auto-update).
env_status() {
  detect_os; ensure_path_brew; sevenzip_detect
  printf '  %s%s%s\n' "$C_B$C_CYAN" "$(t env_checking)" "$C_RESET" >&2
  local missing="" d ok note
  for d in $REQUIRED_DEPS; do
    if dep_present "$d"; then ok="true"; else ok="false"; missing="$missing $d"; fi
    note="$(t env_ok)"
    [ "$d" = "docker" ] && [ "$ok" = "true" ] && { docker info >/dev/null 2>&1 && note="$(t st_running)" || note="$(t st_stopped)"; }
    env_row "$d" "$ok" "$note" >&2
  done
  # docker present but compose plugin missing?
  if command_exists docker && ! docker compose version >/dev/null 2>&1; then
    missing="$missing docker-compose"; env_row "docker compose" "false" "" >&2
  fi
  printf '%s' "$(trim "$missing")"
}

# Step 0 entry. Show the table; if anything is missing, install (asks password); re-check.
step0_env() {
  printf '\n%s%s%s\n' "$C_B" "$(t step0_title)" "$C_RESET"
  local missing; missing="$(env_status)"
  if [ -z "$missing" ]; then
    start_colima_if_needed
    ensure_nvidia_container_toolkit || return 1
    printf '  %s%s%s\n' "$C_GREEN" "$(t env_ready)" "$C_RESET"
    return 0
  fi
  install_missing_deps "$missing"
}

# Install Docker CE from Docker's official apt repository with a pinned, signed-by GPG key,
# instead of piping get.docker.com straight into a root shell (arbitrary unverified code).
# apt then verifies every package against the pinned key. Debian/Ubuntu (apt) only.
apt_install_docker_ce() {
  local S="${1:-}"
  command_exists docker && return 0
  # shellcheck disable=SC1091
  . /etc/os-release 2>/dev/null || return 1
  local id="${ID:-debian}" code="${VERSION_CODENAME:-}"
  $S install -m 0755 -d /etc/apt/keyrings || return 1
  curl -fsSL "https://download.docker.com/linux/$id/gpg" | $S tee /etc/apt/keyrings/docker.asc >/dev/null || return 1
  $S chmod a+r /etc/apt/keyrings/docker.asc
  printf 'deb [arch=%s signed-by=/etc/apt/keyrings/docker.asc] https://download.docker.com/linux/%s %s stable\n' \
    "$(dpkg --print-architecture)" "$id" "$code" | $S tee /etc/apt/sources.list.d/docker.list >/dev/null
  $S apt-get update -qq
  $S apt-get install -y -qq docker-ce docker-ce-cli containerd.io docker-buildx-plugin docker-compose-plugin
}

apt_install_nvidia_container_toolkit() {
  local S="${1:-}"
  command_exists apt-get || return 1
  # shellcheck disable=SC2086
  $S apt-get install -y -qq ca-certificates curl gnupg2 || return 1
  # shellcheck disable=SC2086
  $S install -m 0755 -d /usr/share/keyrings /etc/apt/sources.list.d || return 1
  # shellcheck disable=SC2086
  $S rm -f /usr/share/keyrings/nvidia-container-toolkit-keyring.gpg
  # shellcheck disable=SC2086
  curl -fsSL https://nvidia.github.io/libnvidia-container/gpgkey \
    | $S gpg --dearmor -o /usr/share/keyrings/nvidia-container-toolkit-keyring.gpg || return 1
  # shellcheck disable=SC2086
  curl -fsSL https://nvidia.github.io/libnvidia-container/stable/deb/nvidia-container-toolkit.list \
    | sed 's#deb https://#deb [signed-by=/usr/share/keyrings/nvidia-container-toolkit-keyring.gpg] https://#g' \
    | $S tee /etc/apt/sources.list.d/nvidia-container-toolkit.list >/dev/null || return 1
  # shellcheck disable=SC2086
  $S apt-get update -qq || return 1
  # shellcheck disable=SC2086
  $S apt-get install -y -qq nvidia-container-toolkit || return 1
  # shellcheck disable=SC2086
  $S nvidia-ctk runtime configure --runtime=docker || return 1
  # shellcheck disable=SC2086
  $S systemctl restart docker 2>/dev/null || $S service docker restart 2>/dev/null || true
}

ensure_nvidia_container_toolkit() {
  detect_os
  [ "$OS_TYPE" = "linux" ] || return 0
  nvidia_host_detected || return 0
  nvidia_docker_runtime_ready && return 0
  command_exists apt-get || { printf '  %s\n' "$(t dep_nvidia_manual)"; return 1; }
  local S=""
  if [ "$(id -u)" != "0" ]; then
    can_use_sudo || { printf '  %s\n' "$(t dep_need_root)"; return 1; }
    S="sudo"
  fi
  printf '  %s%s%s\n' "$C_YELLOW" "$(t dep_nvidia_install)" "$C_RESET"
  apt_install_nvidia_container_toolkit "$S" || { printf '  %s\n' "$(t dep_nvidia_failed)"; return 1; }
  if ! nvidia_docker_runtime_ready; then
    printf '  %s\n' "$(t dep_nvidia_failed)"
    return 1
  fi
}

# Install whatever is missing (brew on macOS, apt on Linux), then re-verify.
install_missing_deps() {
  local missing="$1"
  printf '\n  %s%s%s%s\n' "$C_YELLOW" "$(t env_need)" "$C_RESET" " $missing"

  if [ "$OS_TYPE" = "macos" ] && ! is_admin; then
    printf '  %s%s%s\n' "$C_YELLOW" "$(t env_need_admin)" "$C_RESET"
    printf '  %s\n' '/bin/bash -c "$(curl -fsSL https://raw.githubusercontent.com/Homebrew/install/HEAD/install.sh)"'
    printf '  %s\n' 'brew install colima docker docker-compose git openssl sevenzip'
    return 1
  fi
  confirm "$(t env_install_q)" 'Y' || { printf '  %s\n' "$(t env_manual)"; return 1; }

  case "$OS_TYPE" in
    macos)
      command_exists brew || { printf '  %s\n' "$(t env_no_brew)"; return 1; }
      local pkgs=""
      printf '%s' "$missing" | grep -q 'git'     && pkgs="$pkgs git"
      printf '%s' "$missing" | grep -q 'curl'    && pkgs="$pkgs curl"
      printf '%s' "$missing" | grep -q 'openssl' && pkgs="$pkgs openssl@3"
      printf '%s' "$missing" | grep -q '7z'      && pkgs="$pkgs sevenzip"
      printf '%s' "$missing" | grep -q 'docker'  && pkgs="$pkgs colima docker docker-compose"
      # shellcheck disable=SC2086
      [ -n "$(trim "$pkgs")" ] && brew install $pkgs
      start_colima_if_needed ;;
    linux)
      command_exists apt-get || { printf '  %s\n' "$(t dep_apt_only)"; return 1; }
      local S=""
      if [ "$(id -u)" != "0" ]; then can_use_sudo || { printf '  %s\n' "$(t dep_need_root)"; return 1; }; S="sudo"; fi
      # shellcheck disable=SC2086
      $S apt-get update
      # shellcheck disable=SC2086
      $S apt-get install -y git curl ca-certificates openssl p7zip-full gnupg2
      if printf '%s' "$missing" | grep -q 'docker'; then
        apt_install_docker_ce "$S" || { printf '  %s\n' "$(t dep_docker_failed)"; return 1; }
        $S systemctl enable --now docker 2>/dev/null || true
        if [ "$(id -u)" != "0" ]; then
          $S usermod -aG docker "$USER" 2>/dev/null || true
          printf '  %s\n' "$(t dep_docker_group)"
        fi
      fi ;;
    *) printf '  %s\n' "$(t dep_unknown_os)"; return 1 ;;
  esac

  # Re-verify so install never proceeds half-provisioned.
  ensure_path_brew; sevenzip_detect
  local still="" d
  for d in $REQUIRED_DEPS; do dep_present "$d" || still="$still $d"; done
  if [ -n "$(trim "$still")" ]; then
    printf '\n  %s%s%s%s\n' "$C_YELLOW" "$(t env_still)" "$C_RESET" " $still"; return 1
  fi
  if ! docker info >/dev/null 2>&1; then
    printf '\n  %s%s%s\n' "$C_YELLOW" "$(t env_docker_down)" "$C_RESET"; return 1
  fi
  ensure_nvidia_container_toolkit || return 1
  printf '\n  %s%s%s\n' "$C_GREEN" "$(t env_ready)" "$C_RESET"
  return 0
}

# Back-compat name used by lifecycle/reconfig paths.
check_dependencies() {
  detect_os; ensure_path_brew; start_colima_if_needed; sevenzip_detect
  local missing="" d
  for d in $REQUIRED_DEPS; do dep_present "$d" || missing="$missing $d"; done
  command_exists docker && ! docker compose version >/dev/null 2>&1 && missing="$missing docker-compose"
  missing="$(trim "$missing")"
  [ -z "$missing" ] || install_missing_deps "$missing" || return 1
  ensure_nvidia_container_toolkit
}
# ───────────────────────────── config (.stack.env) ─────────────────────────────
load_config() {
  if [ -f "$SCRIPT_DIR/.stack.env" ]; then CONFIG_FILE="$SCRIPT_DIR/.stack.env"
  elif [ -f "$SCRIPT_DIR/../.stack.env" ]; then CONFIG_FILE="$(cd "$SCRIPT_DIR/.." && pwd)/.stack.env"
  elif [ -n "${STACK_DIR:-}" ] && [ -f "$STACK_DIR/.stack.env" ]; then CONFIG_FILE="$STACK_DIR/.stack.env"
  else return 1; fi
  # shellcheck disable=SC1090
  . "$CONFIG_FILE"
  # Backfill defaults for keys added across versions (forward/backward compatible).
  : "${NODE_MODE:=single}"; : "${DEPLOY_PROFILE:=local}"; : "${OPENHANDS_IMAGE:=}"
  : "${ENABLE_OPENWEBUI:=true}"; : "${ENABLE_AGENTS:=true}"; : "${ENABLE_SEARCH:=true}"
  : "${ENABLE_GIT:=true}"; : "${ENABLE_QDRANT:=false}"; : "${ENABLE_MCP:=false}"; : "${ENABLE_EMBEDDINGS:=false}"; : "${ENABLE_PENTEST:=false}"
  : "${RAG_MODE:=off}"; : "${ENABLE_EMBED_SVC:=false}"; : "${ENABLE_INGEST:=false}"; : "${RAG_HYBRID:=false}"
  : "${EMBED_SVC_MODEL:=BAAI/bge-m3}"; : "${RERANK_MODEL:=BAAI/bge-reranker-v2-m3}"
  : "${EMBED_URL:=}"; : "${EMBED_MODEL:=}"; : "${EMBED_API_KEY:=}"; : "${EMBED_SVC_PORT:=7997}"
  : "${MEMORY_MODE:=stub}"; : "${MEMORY_LLM_URL:=}"; : "${MEMORY_LLM_KEY:=}"; : "${MEMORY_LLM_MODEL:=gpt-4o-mini}"
  : "${MEM0_API_KEY:=}"; : "${MEM0_MCP_URL:=}"; : "${MEMORY_PORT:=8000}"
  : "${LOCAL_LLM:=none}"; : "${OLLAMA_MODEL:=llama3.2:3b}"; : "${OLLAMA_EMBED_MODEL:=nomic-embed-text}"; : "${OLLAMA_PULL_VIA_PROXY:=false}"; : "${GPU_MODE:=}"
  : "${MCP_GATEWAY:=false}"; : "${MCP_GATEWAY_SERVERS:=fetch,context7}"; : "${MCP_GATEWAY_PORT:=8811}"
  : "${LLM_GATEWAY:=false}"; : "${ENABLE_EVAL:=false}"
  : "${AGENTS_DOCKER:=false}"; : "${AGENT_WEB:=true}"; : "${OPENHANDS_DOCKER_MODE:=host}"
  : "${SECURITY_PROFILE:=default}"
  : "${SEC_SEAL:=}"; : "${SEC_FIREWALL:=}"; : "${SEC_WATCHDOG:=}"; : "${SEC_CIS:=}"; : "${SEC_NOSSH:=}"; : "${SEC_FAIL2BAN:=}"; : "${SEC_TPM:=}"
  : "${SEAL_ENABLED:=false}"; : "${SEAL_MODE:=auto}"
  : "${EGRESS_STACK:=none}"; : "${EGRESS_WEB:=none}"; : "${STACK_VIA_PROXY:=true}"; : "${WEB_VIA_PROXY:=true}"; : "${ROUTE_LOCAL_LLM:=false}"
  : "${LOG_RETENTION:=6m}"; : "${TLS_MODE:=le}"; : "${OWN_CERT_PATH:=}"; : "${OWN_KEY_PATH:=}"
  : "${PUBLIC_DOMAIN:=}"; : "${ACME_EMAIL:=}"; : "${ENABLE_FAIL2BAN:=false}"
  : "${ISOLATE_AGENTS:=false}"; : "${ISOLATE_GIT:=false}"; : "${SHARED_MEMORY:=false}"
  : "${KMS_HOST:=}"; : "${KMS_SSH_USER:=}"; : "${KMS_SSH_KEY:=}"
  : "${QDRANT_DOMAIN:=}"; : "${OPENHANDS_LLM_MODEL:=}"
  # Backfill NO_DOMAIN (added later): if it was never persisted, infer it from the saved
  # zone — a no-domain install records DOMAIN_ZONE=localhost. Prevents a rebuild from
  # silently switching a localhost-ports stack back to a domain/80/443 Caddy.
  : "${NO_DOMAIN:=false}"; : "${DUAL_ACCESS:=false}"
  [ "${DOMAIN_ZONE:-}" = "localhost" ] && NO_DOMAIN="true"
  : "${DOCKER_CONTEXT_PIN:=}"
  if [ "${LANG_FROM_ENV:-0}" != "1" ] && [ -n "${UI_LANG_SAVED:-}" ]; then UI_LANG="$UI_LANG_SAVED"; fi
  return 0
}

# Single-quote-escape a value so `.stack.env` is safe to source: every value becomes a
# literal single-quoted string, and any embedded `'` is rewritten as the `'\''` idiom.
# Without this, a value containing ", $(...), backticks or a newline would execute (or
# corrupt the config) when load_config sources the file.
shq() {
  case $1 in
    *\'*) printf "'%s'" "$(printf '%s' "$1" | sed "s/'/'\\\\''/g")" ;;
    *)    printf "'%s'" "$1" ;;
  esac
}
# kv KEY VALUE -> `KEY='escaped-value'` (safe to source).
kv() { printf '%s=%s\n' "$1" "$(shq "$2")"; }

