# ───────────────────────────── secrets ─────────────────────────────
random_secret() { openssl rand -base64 32 | tr -d '\n'; }
searxng_secret_gen() { openssl rand -hex 48; }
api_key_gen() { printf 'sk-%s' "$(openssl rand -hex 32)"; }
# Alphanumeric admin password (easy to type). Finite source (openssl) + a bash slice —
# NOT `tr </dev/urandom | head -c`, which SIGPIPEs tr and aborts install under set -e.
admin_pw_gen() { local s; s="$(openssl rand -base64 48 | LC_ALL=C tr -dc 'A-Za-z0-9')"; printf '%s' "${s:0:20}"; }

secrets_file() { printf '%s/secrets/passwords.txt' "$STACK_DIR"; }

# secret_get <key> [generator] -> returns a named secret, creating it idempotently.
# When stack-vault is up it is the store (secrets live in RAM, not in a file on disk);
# otherwise fall back to the file-based secrets/passwords.txt.
secret_get() {
  local key="$1" gen="${2:-random_secret}" file val
  if vault_enabled && vault_up; then
    val="$(vault_get "$key")"
    if [ -z "$val" ]; then val="$($gen)"; printf '%s' "$val" | vault_put "$key"; fi
    printf '%s' "$val"; return 0
  fi
  file="$(secrets_file)"; mkdir -p "$(dirname "$file")"
  [ -f "$file" ] || ( umask 077; printf '# psai — generated secrets. Keep this file safe.\n' > "$file" )
  val="$(sed -n "s/^${key}=//p" "$file" | head -1)"
  if [ -z "$val" ]; then val="$($gen)"; printf '%s=%s\n' "$key" "$val" >> "$file"; fi
  chmod 600 "$file" 2>/dev/null || true
  printf '%s' "$val"
}

# secret_set <key> : store/overwrite a named secret (value on stdin). Routes to the vault
# when it's up (RAM/secretmem) exactly like secret_get, otherwise the 0600 passwords.txt —
# so a later `rebuild` reads back the same value. Used to pin an operator-chosen password.
secret_set() {
  local key="$1" val file tmp; val="$(cat)"
  if vault_enabled && vault_up; then printf '%s' "$val" | vault_put "$key"; return 0; fi
  file="$(secrets_file)"; mkdir -p "$(dirname "$file")"
  [ -f "$file" ] || ( umask 077; printf '# psai — generated secrets. Keep this file safe.\n' > "$file" )
  tmp="$file.tmp.$$"
  grep -v "^${key}=" "$file" > "$tmp" 2>/dev/null || true
  printf '%s=%s\n' "$key" "$val" >> "$tmp"
  mv "$tmp" "$file"
  chmod 600 "$file" 2>/dev/null || true
}

# bcrypt hash for Caddy basic_auth. The plaintext is fed on STDIN (htpasswd -i), never as a
# command-line argument — `caddy hash-password --plaintext "$pass"` and `htpasswd -nb … "$pass"`
# both leak the password into `ps` / docker events for the life of the container. Cost 12.
# Normalize the htpasswd `$2y$` prefix to `$2b$` — Go's bcrypt (Caddy) rejects `$2y$`.
hash_password() {
  local pass="$1" h
  h="$(printf '%s' "$pass" | docker run -i --rm "$HTTPD_IMAGE" htpasswd -niBC 12 x 2>/dev/null | sed 's/^x://')"
  printf '%s' "${h/\$2y\$/\$2b\$}"
}

prepare_dirs_and_secrets() {
  mkdir -p \
    "$STACK_DIR/bin" "$STACK_DIR/compose" "$STACK_DIR/backups" \
    "$STACK_DIR/secrets" "$STACK_DIR/secrets/certificates" "$STACK_DIR/secrets/wg" \
    "$STACK_DIR/data/openwebui" "$STACK_DIR/data/openhands-state" "$STACK_DIR/data/projects" \
    "$STACK_DIR/data/searxng" "$STACK_DIR/data/forgejo" "$STACK_DIR/data/qdrant" "$STACK_DIR/data/embeddings" "$STACK_DIR/data/pentest" \
    "$STACK_DIR/data/embed" "$STACK_DIR/data/ingest" "$STACK_DIR/data/ingest/tmp" "$STACK_DIR/data/memory" "$STACK_DIR/data/ollama" "$STACK_DIR/data/langfuse-db" \
    "$STACK_DIR/data/logs" "$STACK_DIR/data/tailscale" \
    "$STACK_DIR/data/agents" "$STACK_DIR/data/ai_agents_public" \
    "$STACK_DIR/caddy/data" "$STACK_DIR/caddy/data/logs/caddy" "$STACK_DIR/caddy/config" \
    "$STACK_DIR/gateway-stack" "$STACK_DIR/gateway-web" \
    "$STACK_DIR/openhands-sandbox" "$STACK_DIR/openhands-config" "$STACK_DIR/mcp"
  chmod 700 "$STACK_DIR/secrets" 2>/dev/null || true
  chmod 1777 "$STACK_DIR/data/ingest/tmp" 2>/dev/null || true
  # Caddy basic-auth creds are typed into a browser prompt → generate them alphanumeric
  # (admin_pw_gen) so they're typeable; app-account secrets stay full-entropy base64.
  secret_get searxng_secret searxng_secret_gen >/dev/null
  [ "$ENABLE_AGENTS"   = "true" ] && secret_get agents_basic_auth admin_pw_gen >/dev/null
  [ "$ENABLE_OPENWEBUI" = "true" ] && secret_get webui_basic_auth admin_pw_gen >/dev/null
  [ "$ENABLE_QDRANT"   = "true" ] && secret_get qdrant_basic_auth admin_pw_gen >/dev/null
  [ "$ENABLE_GIT"      = "true" ] && secret_get forgejo_admin     >/dev/null
  ollama_enabled && secret_get ollama_api_key api_key_gen >/dev/null
  # If the operator chose their own admin password, make it the actual basic-auth gate for
  # the web UIs (Open WebUI/OpenHands/Qdrant) instead of a generated one. It overwrites the
  # generated basic_auth secret in the same store (the vault when sealed) — never written
  # in plaintext next to the config. Without this the chosen password was collected and
  # silently dropped.
  if [ -n "${ADMIN_PASSWORD_PLAIN:-}" ]; then
    [ "$ENABLE_OPENWEBUI" = "true" ] && printf '%s' "$ADMIN_PASSWORD_PLAIN" | secret_set webui_basic_auth
    [ "$ENABLE_AGENTS"    = "true" ] && printf '%s' "$ADMIN_PASSWORD_PLAIN" | secret_set agents_basic_auth
    [ "$ENABLE_QDRANT"    = "true" ] && printf '%s' "$ADMIN_PASSWORD_PLAIN" | secret_set qdrant_basic_auth
  fi
  return 0
}

# Open WebUI CORS / allowed origins (used by some integrations).
build_allowed_origins() {
  local origins="https://$PSAI_DOMAIN,http://localhost,http://127.0.0.1"
  [ "$ENABLE_AGENTS" = "true" ] && origins="$origins,https://$AGENTS_DOMAIN"
  [ "$ENABLE_GIT" = "true" ] && origins="$origins,https://$GIT_DOMAIN"
  printf '%s' "$origins"
}
# ───────────────────────────── security profile ─────────────────────────────
# strict / default / none. Each capability (SEC_*) is individually toggleable here
# and from the dashboard later. choose_security_profile() picks a profile, shows the
# resolved defaults, then offers "apply defaults" or "configure manually".

is_public_or_multi() { [ "$DEPLOY_PROFILE" = "public" ] || [ "$NODE_MODE" = "multi" ]; }

# OS gating for the hardening capabilities. Some are Linux-only: the CIS kernel sysctls +
# sshd hardening + unattended-upgrades, fail2ban, TPM auto-unseal (tpm2-tools), and the
# WG-only-SSH lockdown. macOS applies only the cross-platform set — the secrets vault, the
# application firewall (socketfilterfw), and the watchdog (launchd). So on macOS the
# Linux-only rows are hidden from the preview/tuner and forced off, instead of showing as a
# misleading "off" that would never take effect.
sec_os()    { detect_os 2>/dev/null || true; printf '%s' "${OS_TYPE:-}"; }
sec_linux() { [ "$(sec_os)" = "linux" ]; }
cis_applies()   { sec_linux; }
# Disabling public SSH is MULTI-ONLY (master reaches agents over WG, so the WG channel
# survives) and Linux-only. On a single host there is no WG fallback — dropping SSH would
# be a lockout — so we never offer it there.
nossh_applies() { [ "$NODE_MODE" = "multi" ] && sec_linux; }
f2b_applies()   { [ "$DEPLOY_PROFILE" = "public" ] && sec_linux; }
# TPM auto-unseal only makes sense when the vault is on (it seals the passphrase) and needs
# tpm2-tools — Linux only (macOS Secure Enclave would need a native helper).
tpm_applies()   { [ "$SEC_SEAL" = "true" ] && sec_linux; }

# Secrets have exactly two modes: SEC_SEAL=false → plaintext .env on disk; SEC_SEAL=true
# → stack-vault (secrets in the daemon's RAM, MANUAL passphrase on every start, nothing
# stored but the AES-GCM blob). There is no auto-unseal. Only strict turns the vault on.
resolve_security_profile() {
  # TPM auto-unseal is opt-in; seed from the env, preserve across profile switches.
  SEC_TPM="${SEC_TPM:-${VAULT_TPM:-false}}"
  case "$SECURITY_PROFILE" in
    strict)
      SEC_SEAL="true"; SEC_FIREWALL="true"; SEC_WATCHDOG="true"
      cis_applies   && SEC_CIS="true"      || SEC_CIS="false"
      nossh_applies && SEC_NOSSH="true"    || SEC_NOSSH="false"
      f2b_applies   && SEC_FAIL2BAN="true" || SEC_FAIL2BAN="false" ;;
    none)
      SEC_SEAL="false"; SEC_CIS="false"; SEC_FIREWALL="false"
      SEC_WATCHDOG="false"; SEC_NOSSH="false"; SEC_FAIL2BAN="false"; SEC_TPM="false" ;;
    *)  # default — secrets in plaintext .env (no vault)
      SECURITY_PROFILE="default"
      SEC_SEAL="false"; SEC_FIREWALL="false"; SEC_WATCHDOG="false"
      cis_applies && SEC_CIS="true" || SEC_CIS="false"
      SEC_NOSSH="false"; SEC_FAIL2BAN="false" ;;
  esac
  tpm_applies || SEC_TPM="false"   # no vault / not Linux → no TPM seal
  apply_security_bindings
}

# Map the SEC_* toggles onto the concrete runtime flags consumed elsewhere.
apply_security_bindings() {
  SEAL_ENABLED="$SEC_SEAL"   # legacy alias; the vault is the only encryption path
  SEAL_MODE="manual"          # the only mode — no auto-unseal
  ENABLE_FAIL2BAN="$SEC_FAIL2BAN"
  VAULT_TPM="${SEC_TPM:-false}"   # TPM auto-unseal (consumed by vault_start)
  # If TPM was turned off, drop any seal blob so the vault reverts to manual unseal.
  [ "${SEC_TPM:-false}" = "true" ] || { type tpm_forget >/dev/null 2>&1 && tpm_forget; }
}

# One row of the preview: "● label  on/off".
sec_row() {
  local on="$1" label="$2" dot="$C_GREEN" val
  [ "$on" = "true" ] && val="$(t on)" || { dot="$C_DIM"; val="$(t off)"; }
  printf '    %s %-26s %s%s%s\n' "$(status_dot "$dot")" "$label" "$dot" "$val" "$C_RESET"
}

security_preview() {
  printf '\n  %s%s%s\n' "$C_B$C_CYAN" "$(t sec_preview)" "$C_RESET"
  printf '    %s %-26s %s%s%s\n' "$(status_dot "$C_GREEN")" "Container hardening" "$C_GREEN" "$(t on)" "$C_RESET"
  local seal_lbl
  if [ "$SEC_SEAL" = "true" ]; then seal_lbl="$(t sec_seal_l) — stack-vault (manual)"; else seal_lbl="$(t sec_seal_l) — .env"; fi
  sec_row "$SEC_SEAL"     "$seal_lbl"
  tpm_applies   && sec_row "$SEC_TPM"  "$(t sec_tpm_l)"
  cis_applies   && sec_row "$SEC_CIS"  "$(t sec_cis_l)"
  sec_row "$SEC_FIREWALL" "$(t sec_fw_l)"
  sec_row "$SEC_WATCHDOG" "$(t sec_wd_l)"
  nossh_applies && sec_row "$SEC_NOSSH"  "$(t sec_nossh_l)"
  f2b_applies   && sec_row "$SEC_FAIL2BAN" "$(t sec_f2b_l)"
  sec_linux || printf '    %s%s%s\n' "$C_DIM" "$(t sec_macos_note)" "$C_RESET"
  return 0   # the trailing `cond && …` may be false → keep this function returning 0 so it
             # never aborts callers running under `set -e`.
}

# Manual tuning: toggle capabilities by number, Enter to apply.
security_tune() {
  while true; do
    security_preview
    printf '\n'
    if cis_applies; then menu_line "" 1 "$(t sec_seal_l)" 2 "$(t sec_cis_l)" 3 "$(t sec_fw_l)" 4 "$(t sec_wd_l)"
    else                 menu_line "" 1 "$(t sec_seal_l)" 3 "$(t sec_fw_l)" 4 "$(t sec_wd_l)"; fi
    { nossh_applies || f2b_applies; } && menu_line "" 5 "$(t sec_nossh_l)" 6 "$(t sec_f2b_l)"
    tpm_applies && menu_line "" 7 "$(t sec_tpm_l)"
    printf '  %s%s%s\n%s: ' "$C_DIM" "$(t sec_toggle_hint)" "$C_RESET" "$(t menu_choice)"
    local line n; read_user_line line; line="$(trim "$line")"
    [ -z "$line" ] && break
    for n in $line; do
      case "$n" in
        1) [ "$SEC_SEAL" = "true" ] && SEC_SEAL="false" || SEC_SEAL="true" ;;
        2) cis_applies && { [ "$SEC_CIS" = "true" ] && SEC_CIS="false" || SEC_CIS="true"; } ;;
        3) [ "$SEC_FIREWALL" = "true" ] && SEC_FIREWALL="false" || SEC_FIREWALL="true" ;;
        4) [ "$SEC_WATCHDOG" = "true" ] && SEC_WATCHDOG="false" || SEC_WATCHDOG="true" ;;
        5) nossh_applies && { [ "$SEC_NOSSH" = "true" ] && SEC_NOSSH="false" || SEC_NOSSH="true"; } ;;
        6) f2b_applies   && { [ "$SEC_FAIL2BAN" = "true" ] && SEC_FAIL2BAN="false" || SEC_FAIL2BAN="true"; } ;;
        7) tpm_applies   && { [ "$SEC_TPM" = "true" ] && SEC_TPM="false" || SEC_TPM="true"; } ;;
        *) : ;;
      esac
    done
    tpm_applies || SEC_TPM="false"   # turning the vault off also drops TPM
    apply_security_bindings
  done
}

# Vault mode needs a passphrase (prompted on every start). Collect it once at install.
ask_seal_pass() {
  [ "$SEC_SEAL" = "true" ] || return 0
  [ "$NONINTERACTIVE" = "1" ] && return 0
  printf '  %s%s%s\n' "$C_DIM" "$(t vault_passhint)" "$C_RESET"
  read_secret_confirmed SEAL_PASS_PLAIN "$(t vault_pass)"
  return 0
}

# Step 4 entry: pick profile (one line), preview, then apply or tune.
choose_security_profile() {
  menu_line "$(t sec_q)" s "$(t sec_strict)" d "$(t sec_default)" n "$(t sec_none)"
  printf '    %s[s]%s %s%s%s\n' "$C_CYAN" "$C_RESET" "$C_DIM" "$(t sec_strict_d)"  "$C_RESET"
  printf '    %s[d]%s %s%s%s\n' "$C_CYAN" "$C_RESET" "$C_DIM" "$(t sec_default_d)" "$C_RESET"
  printf '    %s[n]%s %s%s%s\n' "$C_CYAN" "$C_RESET" "$C_DIM" "$(t sec_none_d)"    "$C_RESET"
  local c; c="$(ask "$(t sec_q)" 'd')"
  case "$(printf '%s' "$c" | tr -d '[][:space:]' | tr 'A-Z' 'a-z')" in
    s|strict) SECURITY_PROFILE="strict" ;;
    n|none)   SECURITY_PROFILE="none" ;;
    *)        SECURITY_PROFILE="default" ;;
  esac
  resolve_security_profile
  security_preview
  printf '\n'
  menu_line "" a "$(t sec_apply)" c "$(t sec_tune)"
  local d; d="$(ask "$(t menu_choice)" 'a')"
  case "$(printf '%s' "$d" | tr -d '[][:space:]' | tr 'A-Z' 'a-z')" in
    c|tune|manual) security_tune ;;
    *) : ;;
  esac
  ask_seal_pass
  return 0   # never let a trailing non-zero abort the installer under set -e
}
# ───────────────────────────── host hardening ─────────────────────────────
# Firewall + CIS/CISA kernel sysctls + unattended security upgrades + conservative
# sshd hardening. Fully reversible (`psai harden --off`). The firewall ALWAYS
# allows the live SSH port before enabling, so it can never lock you out. Password
# SSH auth is left untouched.

harden_sudo() { if [ "$(id -u)" = "0" ]; then printf ''; else printf 'sudo'; fi; }

current_ssh_port() {
  local p; p="$(printf '%s' "${SSH_CONNECTION:-}" | awk '{print $4}')"
  [ -n "$p" ] || p="$(grep -iE '^[[:space:]]*Port[[:space:]]+[0-9]+' /etc/ssh/sshd_config 2>/dev/null | awk '{print $2}' | head -1)"
  [ -n "$p" ] || p=22
  printf '%s' "$p"
}

firewall_status() {
  detect_os
  case "$OS_TYPE" in
    linux) command -v ufw >/dev/null 2>&1 && ufw status 2>/dev/null | grep -qiE 'Status: active' && printf 'on' || printf 'off' ;;
    macos) /usr/libexec/ApplicationFirewall/socketfilterfw --getglobalstate 2>/dev/null | grep -qiE 'enabled' && printf 'on' || printf 'off' ;;
    *) printf 'off' ;;
  esac
}

# CIS/CISA kernel sysctl baseline (shared by local harden + agent-server hardening).
# ip_forward is intentionally left alone — Docker needs it.
cis_sysctl_lines() {
  cat <<'EOF'
net.ipv4.conf.all.rp_filter=1
net.ipv4.conf.default.rp_filter=1
net.ipv4.tcp_syncookies=1
net.ipv4.conf.all.accept_redirects=0
net.ipv4.conf.default.accept_redirects=0
net.ipv6.conf.all.accept_redirects=0
net.ipv4.conf.all.send_redirects=0
net.ipv4.conf.all.accept_source_route=0
net.ipv4.conf.all.log_martians=1
kernel.randomize_va_space=2
kernel.kptr_restrict=2
kernel.dmesg_restrict=1
fs.protected_hardlinks=1
fs.protected_symlinks=1
kernel.yama.ptrace_scope=1
EOF
}
# Strict-only: fully block ptrace (even for root) so nobody can inject code into the
# stack-vault process and read its secrets. ptrace_scope=3 is irreversible until reboot
# and disables ALL debugging, so it's opt-in via the strict firewall step, not the
# default CIS baseline (which uses level 1).
ptrace_lockdown_lines() { printf 'kernel.yama.ptrace_scope=3\n'; }
cis_sshd_lines() {
  cat <<'EOF'
MaxAuthTries 4
LoginGraceTime 30
X11Forwarding no
ClientAliveInterval 300
ClientAliveCountMax 2
EOF
}

harden_linux() {
  local S sshp gitp; S="$(harden_sudo)"; sshp="$(current_ssh_port)"; gitp="${GIT_SSH_PORT:-2222}"
  # CIS sysctls + sshd hardening + unattended-upgrades (the "default" baseline).
  cis_sysctl_lines | $S tee /etc/sysctl.d/99-psai.conf >/dev/null
  $S sysctl --system >/dev/null 2>&1 || true
  $S apt-get install -y -qq unattended-upgrades >/dev/null 2>&1 || true
  $S tee /etc/apt/apt.conf.d/20auto-upgrades >/dev/null <<'EOF'
APT::Periodic::Update-Package-Lists "1";
APT::Periodic::Unattended-Upgrade "1";
EOF
  # Optional: fully block ptrace (even root) to protect the vault from code injection.
  if [ "${VAULT_PTRACE_LOCKDOWN:-false}" = "true" ]; then
    ptrace_lockdown_lines | $S tee /etc/sysctl.d/99-psai-ptrace.conf >/dev/null
    $S sysctl --system >/dev/null 2>&1 || true
  fi
  $S mkdir -p /etc/ssh/sshd_config.d
  cis_sshd_lines | $S tee /etc/ssh/sshd_config.d/99-psai.conf >/dev/null
  $S systemctl reload ssh 2>/dev/null || $S systemctl reload sshd 2>/dev/null || true
  # Firewall (strict only): ALLOW the live SSH + stack ports BEFORE enabling.
  if [ "${SEC_FIREWALL:-false}" = "true" ]; then
    command -v ufw >/dev/null 2>&1 || { $S apt-get update -qq >/dev/null 2>&1; $S apt-get install -y -qq ufw >/dev/null 2>&1; }
    $S ufw allow "${sshp}/tcp" >/dev/null 2>&1 || true
    $S ufw allow 80/tcp  >/dev/null 2>&1 || true
    $S ufw allow 443/tcp >/dev/null 2>&1 || true
    [ "${ENABLE_GIT:-false}" = "true" ] && $S ufw allow "${gitp}/tcp" >/dev/null 2>&1 || true
    $S ufw default deny incoming  >/dev/null 2>&1 || true
    $S ufw default allow outgoing >/dev/null 2>&1 || true
    $S ufw --force enable >/dev/null 2>&1 || true
  fi
}

harden_macos() {
  [ "${SEC_FIREWALL:-false}" = "true" ] || return 0
  local S fw; S="$(harden_sudo)"; fw=/usr/libexec/ApplicationFirewall/socketfilterfw
  $S "$fw" --setglobalstate on    >/dev/null 2>&1 || true
  $S "$fw" --setstealthmode on    >/dev/null 2>&1 || true
  $S "$fw" --setallowsigned on    >/dev/null 2>&1 || true
  $S "$fw" --setallowsignedapp on >/dev/null 2>&1 || true
}

harden_off() {
  detect_os; local S; S="$(harden_sudo)"
  case "$OS_TYPE" in
    linux) $S ufw --force disable >/dev/null 2>&1 || true
           $S rm -f /etc/sysctl.d/99-psai.conf /etc/ssh/sshd_config.d/99-psai.conf
           $S systemctl reload ssh 2>/dev/null || $S systemctl reload sshd 2>/dev/null || true ;;
    macos) local fw=/usr/libexec/ApplicationFirewall/socketfilterfw
           $S "$fw" --setstealthmode off >/dev/null 2>&1 || true
           $S "$fw" --setglobalstate off >/dev/null 2>&1 || true ;;
  esac
}

# Entry point (CLI / install / dashboard). Applies whatever SEC_* flags are set.
harden_host() {
  load_config 2>/dev/null || true
  detect_os
  case "${1:-}" in --off|off|disable) harden_off; printf '%s\n' "$(t done_word)"; return 0 ;; esac
  [ "${SEC_CIS:-false}" = "true" ] || [ "${SEC_FIREWALL:-false}" = "true" ] || return 0
  if ! can_use_sudo; then printf '%s%s%s\n' "$C_YELLOW" "$(t env_need_admin)" "$C_RESET"; return 0; fi
  case "$OS_TYPE" in
    linux) harden_linux ;;
    macos) harden_macos ;;
    *) return 0 ;;
  esac
  printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
}
# ───────────────────────────── watchdog daemon ─────────────────────────────
# Tiny health watchdog: every couple of minutes it checks the stack and brings any
# stopped container back up. Scheduled via launchd (macOS) or cron (Linux).
WATCHDOG_INTERVAL="${WATCHDOG_INTERVAL:-120}"   # seconds

write_watchdog_script() {
  local f="$STACK_DIR/bin/watchdog.sh"
  mkdir -p "$STACK_DIR/bin" "$STACK_DIR/data/logs"
  cat > "$f" <<EOF
#!/usr/bin/env bash
# Auto-generated stack health watchdog.
export PATH="/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:\$PATH"
LOG="$STACK_DIR/data/logs/watchdog.log"
cd "$STACK_DIR/compose" 2>/dev/null || exit 0
command -v colima >/dev/null 2>&1 && { docker info >/dev/null 2>&1 || colima start >/dev/null 2>&1 || true; }
# No auto-unseal: the watchdog only restarts existing containers (their env was
# rendered at the last start). If the vault is sealed it does not re-render secrets.
DC=(docker compose -f docker-compose.yml)
bad="\$("\${DC[@]}" ps -a --format '{{.Service}}={{.State}}' 2>/dev/null | grep -v '=running\$' || true)"
if [ -n "\$bad" ]; then
  echo "\$(date '+%F %T') unhealthy -> up -d : \$bad" >> "\$LOG"
  "\${DC[@]}" up -d >/dev/null 2>&1 || true
fi
EOF
  chmod +x "$f"
  printf '%s' "$f"
}

watchdog_label() { printf 'com.psai.%s.watchdog' "$SAFE_STACK_NAME"; }
watchdog_plist() { printf '%s/Library/LaunchAgents/%s.plist' "$HOME" "$(watchdog_label)"; }

watchdog_enable() {
  load_config || { echo "$(t no_env)"; return 1; }
  local f; f="$(write_watchdog_script)"; detect_os
  case "$OS_TYPE" in
    macos)
      local plist; plist="$(watchdog_plist)"; mkdir -p "$HOME/Library/LaunchAgents"
      cat > "$plist" <<EOF
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0"><dict>
  <key>Label</key><string>$(watchdog_label)</string>
  <key>ProgramArguments</key><array><string>/bin/bash</string><string>$f</string></array>
  <key>StartInterval</key><integer>$WATCHDOG_INTERVAL</integer>
  <key>RunAtLoad</key><true/>
</dict></plist>
EOF
      launchctl unload "$plist" 2>/dev/null || true
      launchctl load "$plist" 2>/dev/null || true ;;
    linux)
      local every=$(( WATCHDOG_INTERVAL / 60 )); [ "$every" -lt 1 ] && every=1
      ( crontab -l 2>/dev/null | grep -v "psai-watchdog:${SAFE_STACK_NAME}"; \
        printf '*/%s * * * * %s # psai-watchdog:%s\n' "$every" "$f" "$SAFE_STACK_NAME" ) | crontab - ;;
    *) echo 'Watchdog unsupported on this OS.'; return 1 ;;
  esac
  SEC_WATCHDOG="true"; save_config 2>/dev/null || true
  printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
}

watchdog_disable() {
  load_config || { echo "$(t no_env)"; return 1; }
  detect_os
  case "$OS_TYPE" in
    macos) local plist; plist="$(watchdog_plist)"; launchctl unload "$plist" 2>/dev/null || true; rm -f "$plist" ;;
    linux) crontab -l 2>/dev/null | grep -v "psai-watchdog:${SAFE_STACK_NAME}" | crontab - 2>/dev/null || true ;;
  esac
  SEC_WATCHDOG="false"; save_config 2>/dev/null || true
  printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
}

watchdog_state() {
  detect_os
  case "$OS_TYPE" in
    macos) launchctl list 2>/dev/null | grep -q "$(watchdog_label)" && printf '%s' "$(t st_running)" || printf '%s' "$(t st_stopped)" ;;
    linux) crontab -l 2>/dev/null | grep -q "psai-watchdog:${SAFE_STACK_NAME}" && printf '%s' "$(t st_running)" || printf '%s' "$(t st_stopped)" ;;
    *) printf '%s' "$(t st_stopped)" ;;
  esac
}
# ───────────────────────────── seal / unseal ─────────────────────────────
# At-rest encryption for secrets/. The encrypted blob (secrets.enc) is the source
# of truth, refreshed after every secret-changing op. When sealed, the plaintext
# secrets/ is wiped — the stack cannot run until unsealed.
#   auto   : passphrase in a host keyfile -> start auto-unseals.
#   manual : passphrase prompted on start; never stored. (strict profile)
# strict + manual + Linux + privilege -> RAM-unseal (plaintext lives in tmpfs only;
# a reboot wipes it). AES-256-CBC + PBKDF2 600k (openssl), no extra dependency.

seal_enabled() { [ "${SEAL_ENABLED:-false}" = "true" ]; }
seal_blob()    { printf '%s/secrets.enc' "$STACK_DIR"; }
seal_keyfile() { printf '%s/.config/psai/%s.sealkey' "$HOME" "$SAFE_STACK_NAME"; }
is_sealed()    { [ -f "$(seal_blob)" ] && [ ! -f "$STACK_DIR/secrets/passwords.txt" ]; }

seal_pass_auto() {
  local kf; kf="$(seal_keyfile)"; mkdir -p "$(dirname "$kf")"
  [ -s "$kf" ] || ( umask 077; openssl rand -base64 48 | tr -d '\n' > "$kf" )
  chmod 600 "$kf" 2>/dev/null || true
  cat "$kf"
}
seal_pass_prompt() {
  local p; printf '%s: ' "$(t d_seal)" >&2
  stty -echo 2>/dev/null; IFS= read -r p; stty echo 2>/dev/null; printf '\n' >&2
  printf '%s' "$p"
}
seal_pass() {
  if [ "${SEAL_MODE:-auto}" = "manual" ]; then
    [ -n "${SEAL_PASS_PLAIN:-}" ] && { printf '%s' "$SEAL_PASS_PLAIN"; return; }
    seal_pass_prompt
  else
    seal_pass_auto
  fi
}

seal_blob_write() {
  local pp="$1" tmp; tmp="$(seal_blob).tmp"
  [ -f "$STACK_DIR/secrets/passwords.txt" ] || return 0
  if tar -czf - -C "$STACK_DIR" secrets 2>/dev/null \
       | openssl enc -aes-256-cbc -pbkdf2 -iter 600000 -salt -pass "pass:$pp" -out "$tmp" 2>/dev/null; then
    mv "$tmp" "$(seal_blob)"; chmod 600 "$(seal_blob)" 2>/dev/null || true; return 0
  fi
  rm -f "$tmp"; return 1
}

# NOTE: the old tmpfs RAM-unseal is gone — stack-vault (lib/77-vault.sh) now keeps the
# plaintext in a daemon's mlock'd RAM for the strict/manual path. This openssl-blob
# seal remains only as the fallback when the vault can't be built.

seal_wipe() {
  vault_present && return 0
  [ -f "$(seal_blob)" ] || return 1
  find "$STACK_DIR/secrets" -type f 2>/dev/null | while IFS= read -r ff; do
    rm -P "$ff" 2>/dev/null || shred -u "$ff" 2>/dev/null || rm -f "$ff" 2>/dev/null || true
  done
  rm -rf "$STACK_DIR/secrets" 2>/dev/null || true
}

seal_decrypt() {
  local pp="$1"
  openssl enc -d -aes-256-cbc -pbkdf2 -iter 600000 -pass "pass:$pp" -in "$(seal_blob)" 2>/dev/null \
    | tar -xzf - -C "$STACK_DIR" 2>/dev/null
  [ -f "$STACK_DIR/secrets/passwords.txt" ]
}

reseal_blob() {
  vault_present && return 0
  seal_enabled || return 0
  is_sealed && return 0
  seal_blob_write "$(seal_pass)" || { printf 'seal: blob refresh failed\n' >&2; return 1; }
}

ensure_unsealed() {
  vault_present && return 0
  seal_enabled || return 0
  is_sealed || return 0
  local pp; pp="$(seal_pass)"
  if seal_decrypt "$pp"; then printf '%s\n' "$(t seal_unsealed)" >&2; return 0; fi
  printf '%s%s%s\n' "$C_RED" "seal: unseal failed" "$C_RESET" >&2; return 1
}

seal_now() {
  load_config || { echo "$(t no_env)"; return 1; }
  if vault_enabled; then vault_seal; printf '%s%s%s\n' "$C_GREEN" "$(t seal_sealed)" "$C_RESET"; return 0; fi
  seal_enabled || { echo "$(t disabled)"; return 0; }
  is_sealed && { echo "$(t seal_sealed)"; return 0; }
  reseal_blob || return 1
  ensure_path_brew; compose down >/dev/null 2>&1 || true
  seal_wipe
  printf '%s%s%s\n' "$C_GREEN" "$(t seal_sealed)" "$C_RESET"
}
unseal_now() {
  load_config || { echo "$(t no_env)"; return 1; }
  if vault_enabled; then vault_start && printf '%s%s%s\n' "$C_GREEN" "$(t seal_unsealed)" "$C_RESET"; return 0; fi
  seal_enabled || { echo "$(t disabled)"; return 0; }
  is_sealed || { echo "$(t seal_unsealed)"; return 0; }
  ensure_unsealed && printf '%s%s%s\n' "$C_GREEN" "$(t seal_unsealed)" "$C_RESET"
}

seal_status_label() {
  if ! seal_enabled; then printf '%s' "$(t seal_off)"
  elif is_sealed;     then printf '%s' "$(t seal_sealed)"
  else                     printf '%s' "$(t seal_unsealed)"; fi
}
# ───────────────────────────── stack-vault (secrets daemon) ─────────────────────────────
# When secrets encryption is on (SEC_SEAL), stack-vault becomes the secret store: all
# generated secrets live in the daemon's mlock'd RAM, served over a peer-cred-gated
# Unix socket. The only disk artifact is an AES-256-GCM blob (vault.enc).
#   Single node  → the local "stack vault" (manual passphrase).
#   Multi node   → the "KMS vault": the keys store + KMS server that unseals the agents,
#                  running on the master or on a separate KMS node (PSAI_KMS_HOST).
vault_enabled()  { [ "${SEC_SEAL:-false}" = "true" ]; }
# Display name for the vault by deployment role (single = stack vault, multi = KMS vault).
vault_role_label() {
  if [ "${NODE_MODE:-single}" = "multi" ]; then
    if [ -n "${KMS_HOST:-}" ]; then printf 'KMS vault · node %s' "$KMS_HOST"; else printf 'KMS vault'; fi
  else printf 'stack vault'; fi
}
vault_bin()      { printf '%s/bin/stack-vault' "$STACK_DIR"; }
vault_sock()     { printf '%s/vault.sock' "$STACK_DIR"; }
vault_blob()     { printf '%s/vault.enc' "$STACK_DIR"; }
vault_log()      { printf '%s/data/logs/vault.log' "$STACK_DIR"; }

vault_present()  { [ -x "$(vault_bin)" ]; }
vault_up()       { vault_present && "$(vault_bin)" ping --socket "$(vault_sock)" >/dev/null 2>&1; }
vault_sealed()   { ! vault_up; }
vault_serve_pids() {
  vault_present || return 0
  pgrep -f "$(vault_bin) serve --socket $(vault_sock) --blob $(vault_blob)" 2>/dev/null || true
}
vault_socket_pid() {
  command_exists lsof || return 0
  lsof -t "$(vault_sock)" 2>/dev/null | sed -n '1p'
}
vault_reap_duplicate_serves() {
  local pids="" pid keep="" count=0
  pids="$(vault_serve_pids)"
  for pid in $pids; do count=$((count + 1)); keep="$pid"; done
  [ "$count" -le 1 ] && return 0
  keep="$(vault_socket_pid)"
  if [ -z "$keep" ]; then
    for pid in $pids; do keep="$pid"; done
  fi
  for pid in $pids; do [ "$pid" = "$keep" ] || kill "$pid" 2>/dev/null || true; done
}
# Kill orphaned stack-vault serve daemons whose stack directory is gone — e.g. one left
# over after the stack was renamed or its dir removed (its --blob no longer matches the
# current vault path, so vault_reap_duplicate_serves never sees it). Safe by design: a
# live stack's blob directory still exists, so a running deployment is never touched.
vault_reap_orphan_serves() {
  command_exists pgrep || return 0
  local pid cmd blob dir
  for pid in $(pgrep -f 'stack-vault serve' 2>/dev/null); do
    cmd="$(ps -o command= -p "$pid" 2>/dev/null)" || continue
    case "$cmd" in *--blob*) blob="${cmd#*--blob }"; blob="${blob%% *}" ;; *) continue ;; esac
    [ -n "$blob" ] || continue
    dir="$(dirname "$blob" 2>/dev/null)"
    [ -n "$dir" ] && [ ! -d "$dir" ] && kill "$pid" 2>/dev/null || true
  done
}

# Build stack-vault from source (vault/ next to the installer). Needs cargo; if it
# can't be built, the caller falls back to the file-based path and warns.
# Map uname -m to the release arch tag used in prebuilt filenames.
vault_arch_tag() {
  case "$(uname -m)" in
    x86_64|amd64) printf 'x86_64' ;;
    aarch64|arm64) printf 'aarch64' ;;
    *) uname -m ;;
  esac
}
# A release-shipped prebuilt for this OS/arch (vault/dist/stack-vault-<os>-<arch>), so a
# node without a Rust toolchain (e.g. a fresh agent) needs no cargo build.
vault_prebuilt() {
  detect_os 2>/dev/null || true
  local os tag d
  case "${OS_TYPE:-}" in linux) os=linux ;; macos) os=macos ;; *) os="$(uname -s | tr 'A-Z' 'a-z')" ;; esac
  tag="$(vault_arch_tag)"
  for d in "${PSAI_VAULT_DIST:-}" "$SCRIPT_DIR/vault/dist" "$SCRIPT_DIR/../vault/dist" "$SCRIPT_DIR/dist" "$STACK_DIR/vault-dist"; do
    [ -n "$d" ] && [ -x "$d/stack-vault-${os}-${tag}" ] && { printf '%s/stack-vault-%s-%s' "$d" "$os" "$tag"; return 0; }
  done
  return 1
}

build_vault() {
  vault_present && return 0
  # A prebuilt binary (from the release, verified via versions.json) wins if present.
  if [ -n "${PSAI_VAULT_BIN:-}" ] && [ -x "$PSAI_VAULT_BIN" ]; then
    mkdir -p "$STACK_DIR/bin"; cp "$PSAI_VAULT_BIN" "$(vault_bin)"; chmod +x "$(vault_bin)"; return 0
  fi
  local pre; if pre="$(vault_prebuilt)"; then
    mkdir -p "$STACK_DIR/bin"; cp "$pre" "$(vault_bin)"; chmod +x "$(vault_bin)"; return 0
  fi
  local src=""
  for d in "${PSAI_VAULT_SRC:-}" "$SCRIPT_DIR/vault" "$SCRIPT_DIR/../vault" "$STACK_DIR/vault-src"; do
    [ -n "$d" ] && [ -f "$d/Cargo.toml" ] && { src="$d"; break; }
  done
  [ -n "$src" ] || return 1
  ensure_path_brew
  if ! command_exists cargo; then
    detect_os
    case "$OS_TYPE" in
      macos) command_exists brew && brew install rust >/dev/null 2>&1 || true ;;
      linux) local S=""; [ "$(id -u)" = 0 ] || S=sudo; $S apt-get install -y -qq cargo >/dev/null 2>&1 || true ;;
    esac
    export PATH="$HOME/.cargo/bin:$PATH"
  fi
  command_exists cargo || return 1
  ( cd "$src" && cargo build --release >/dev/null 2>&1 ) || return 1
  mkdir -p "$STACK_DIR/bin"
  cp "$src/target/release/stack-vault" "$(vault_bin)" && chmod +x "$(vault_bin)"
}

# ── TPM auto-unseal (Linux, tpm2-tools) — optional, VAULT_TPM=true ──
# Seal the vault passphrase to THIS machine's TPM so the vault auto-unseals on this
# hardware only; the sealed blob is useless on any other machine (no passphrase on disk
# in plaintext). The owner-hierarchy primary is deterministic per-TPM, so the sealed
# objects re-load after reboot. macOS Secure Enclave needs a native helper (not bash) —
# tracked in TODO.md.
tpm_dir()            { printf '%s/secrets/tpm' "$STACK_DIR"; }
tpm_available()      { command_exists tpm2_createprimary && { [ -e /dev/tpmrm0 ] || [ -e /dev/tpm0 ]; }; }
tpm_sealed_present() { [ -f "$(tpm_dir)/seal.priv" ] && [ -f "$(tpm_dir)/seal.pub" ]; }
tpm_forget()         { rm -rf "$(tpm_dir)" 2>/dev/null || true; }   # disable TPM auto-unseal
tpm_seal_pass() {     # $1 = passphrase
  tpm_available || return 1
  local d; d="$(tpm_dir)"; mkdir -p "$d"; chmod 700 "$d"
  ( cd "$d" && tpm2_createprimary -Q -C o -c primary.ctx >/dev/null 2>&1 \
    && printf '%s' "$1" | tpm2_create -Q -C primary.ctx -i - -u seal.pub -r seal.priv >/dev/null 2>&1 ) \
    || { rm -f "$d"/seal.pub "$d"/seal.priv; return 1; }
  chmod 600 "$d"/seal.pub "$d"/seal.priv "$d"/primary.ctx 2>/dev/null || true
  printf '%sTPM: vault passphrase sealed to this machine%s\n' "$C_DIM" "$C_RESET" >&2
}
tpm_unseal_pass() {
  { tpm_available && tpm_sealed_present; } || return 1
  local d; d="$(tpm_dir)"
  ( cd "$d" && tpm2_createprimary -Q -C o -c primary.ctx >/dev/null 2>&1 \
    && tpm2_load -Q -C primary.ctx -u seal.pub -r seal.priv -c seal.ctx >/dev/null 2>&1 \
    && tpm2_unseal -Q -c seal.ctx 2>/dev/null )
}

# Unseal: start the daemon. The passphrase comes from the install (SEAL_PASS_PLAIN), the
# PSAI_VAULT_PASS env, the TPM (VAULT_TPM, auto-unseal to this machine), or a prompt.
# Nothing is stored on disk but the encrypted blob; without TPM a reboot loses the
# in-RAM key (sealed until re-entered).
vault_start() {
  vault_enabled || return 0
  vault_present || { build_vault || { printf '%svault unavailable — using file secrets%s\n' "$C_YELLOW" "$C_RESET" >&2; return 1; }; }
  vault_reap_orphan_serves
  vault_reap_duplicate_serves
  vault_up && return 0
  mkdir -p "$(dirname "$(vault_log)")"
  local sock blob; sock="$(vault_sock)"; blob="$(vault_blob)"
  local kmsconf="$STACK_DIR/secrets/kms.conf"
  if [ -f "$kmsconf" ]; then
    # KMS-unseal (agent): fetch the key from the master vault over WG. No passphrase
    # and no key on the agent's disk — the token in kms.conf only authenticates.
    local KMS_ADDR="" KMS_ID="" KMS_TOKEN=""
    # shellcheck disable=SC1090
    . "$kmsconf"
    nohup "$(vault_bin)" serve --socket "$sock" --blob "$blob" \
      --kms "$KMS_ADDR" --kms-id "$KMS_ID" --kms-token "$KMS_TOKEN" >>"$(vault_log)" 2>&1 &
  else
    local p; p="${SEAL_PASS_PLAIN:-${PSAI_VAULT_PASS:-}}"
    # TPM auto-unseal: recover the passphrase sealed to this machine's TPM.
    if [ -z "$p" ] && [ "${VAULT_TPM:-false}" = "true" ] && tpm_sealed_present; then
      p="$(tpm_unseal_pass 2>/dev/null)"
    fi
    if [ -z "$p" ]; then
      if [ "$NONINTERACTIVE" = "1" ]; then printf '%s%s%s\n' "$C_RED" "$(t vault_need_pass)" "$C_RESET" >&2; return 1; fi
      printf '%s: ' "$(t vault_pass)" >&2; stty -echo 2>/dev/null; IFS= read -r p; stty echo 2>/dev/null; printf '\n' >&2
    fi
    PSAI_VAULT_PASS="$p" nohup "$(vault_bin)" serve --socket "$sock" --blob "$blob" >>"$(vault_log)" 2>&1 &
  fi
  local i=0; while [ "$i" -lt 25 ]; do
    if vault_up; then
      vault_reap_duplicate_serves
      # First successful unseal with VAULT_TPM: seal the passphrase to the TPM for next time.
      if [ "${VAULT_TPM:-false}" = "true" ] && [ -n "${p:-}" ] && ! tpm_sealed_present; then
        tpm_seal_pass "$p" 2>/dev/null || true
      fi
      return 0
    fi
    sleep 0.2; i=$((i + 1))
  done
  printf '%svault failed to start (wrong passphrase / KMS unreachable? see %s)%s\n' "$C_YELLOW" "$(vault_log)" "$C_RESET" >&2
  return 1
}

# KMS: serve agent unseal keys to WireGuard peers (bound to a WG IP only).
vault_kms_port()    { printf '%s' "${PSAI_KMS_PORT:-51821}"; }
vault_kms_running() { pgrep -f 'stack-vault kms' >/dev/null 2>&1; }
# Address that callers (master/agents) fetch unseal from. An external KMS node
# (PSAI_KMS_HOST) takes precedence; otherwise the KMS is co-located on the master.
vault_kms_addr() {
  if [ -n "${KMS_HOST:-}" ]; then printf '%s:%s' "$KMS_HOST" "$(vault_kms_port)"
  elif type master_wg_ip >/dev/null 2>&1; then printf '%s:%s' "$(master_wg_ip)" "$(vault_kms_port)"
  fi
}
# Start the local KMS service. Skipped when the KMS lives on its own node
# (PSAI_KMS_HOST set) — that host runs the daemon and holds the keys store.
vault_kms_start() {
  vault_enabled || return 0
  [ -n "${KMS_HOST:-}" ] && return 0          # external KMS node owns this
  vault_present && vault_up || return 0
  vault_kms_running && return 0
  type master_wg_ip >/dev/null 2>&1 || return 0
  local wg; wg="$(master_wg_ip)"; [ -n "$wg" ] || return 0
  nohup "$(vault_bin)" kms --listen "${wg}:$(vault_kms_port)" --socket "$(vault_sock)" >>"$(vault_log)" 2>&1 &
  printf '%sstack-vault KMS on %s:%s%s\n' "$C_DIM" "$wg" "$(vault_kms_port)" "$C_RESET" >&2
}
vault_kms_stop() { pkill -f 'stack-vault kms' 2>/dev/null || true; }

# Keys-store access. With an external KMS node (KMS_HOST) the agent keys
# (agent_unseal_<id> / kms_token_<id> / agent_fp_<id>) live on that node's vault, reached
# over WireGuard+SSH; otherwise they live in the local master vault. This is what lets a
# compromised master not expose every agent's key.
kms_node_ssh() {
  # Pin the KMS node's host key on first contact (TOFU) via the persisted known_hosts,
  # instead of StrictHostKeyChecking=no which silently trusted any key on every connect.
  local h="${KMS_SSH_USER:-root}@${KMS_HOST}" kh; kh="$(ra_known_hosts)"
  if [ -n "${KMS_SSH_KEY:-}" ]; then ssh -i "$KMS_SSH_KEY" -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$h" "$@"
  elif [ -n "${RA_PASSFILE:-}" ]; then sshpass -f "$RA_PASSFILE" ssh -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$h" "$@"
  else ssh -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$h" "$@"; fi
}
kms_store_put() {   # $1=key, value on stdin
  if [ -n "${KMS_HOST:-}" ]; then kms_node_ssh "psai/bin/stack-vault put $1 --socket psai/vault.sock"
  else vault_put "$1"; fi
}
kms_store_get() {   # $1=key
  if [ -n "${KMS_HOST:-}" ]; then kms_node_ssh "psai/bin/stack-vault get $1 --socket psai/vault.sock" 2>/dev/null || true
  else vault_get "$1"; fi
}

# Seal: tell the daemon to persist + wipe memory + exit.
vault_seal() {
  vault_enabled || return 0
  vault_up || return 0
  "$(vault_bin)" seal --socket "$(vault_sock)" >/dev/null 2>&1 || true
}

# get exits 1 on a missing key — '|| true' keeps `set -e` from aborting the caller.
vault_get() { "$(vault_bin)" get "$1" --socket "$(vault_sock)" 2>/dev/null || true; }
vault_put() { "$(vault_bin)" put "$1" --socket "$(vault_sock)" >/dev/null 2>&1; }   # value on stdin

vault_status_label() {
  if ! vault_enabled; then printf '%s' "$(t seal_off)"
  elif vault_up;       then printf '%s' "$(t seal_unsealed)"
  else                      printf '%s' "$(t seal_sealed)"; fi
}
# ───────────────────────────── egress proxies ─────────────────────────────
# Two independent HTTP-proxy gateways, both default 'none' (DIRECT):
#   proxy-stack : the apps' LLM API egress (cloud + local) + component pulls.
#                 Internal-only — apps reach it by name (proxy-stack:<port>).
#   proxy-web   : the web worker — search + the OpenHands sandbox's browsing.
#                 Published on host loopback so the sandbox (separate net) can reach it.
# Modes: tor | vless use an HTTP listener on 8118; wireguard/adguardvpn/tailscale
# tunnel via a tinyproxy sidecar on 8888 that shares the tunnel container's netns.

egress_stack_enabled() { [ -n "${EGRESS_STACK:-}" ] && [ "$EGRESS_STACK" != "none" ]; }
egress_web_enabled()   { [ -n "${EGRESS_WEB:-}" ]   && [ "$EGRESS_WEB" != "none" ]; }
stack_via_proxy() { [ "${STACK_VIA_PROXY:-true}" = "true" ]; }
web_via_proxy()   { [ "${WEB_VIA_PROXY:-true}"   = "true" ]; }

eg_mode_port() { case "$1" in tor|vless) printf '8118' ;; *) printf '8888' ;; esac; }

# Host bind address for proxy-web's published port. The OpenHands sandbox is a SEPARATE
# container that reaches the proxy via host.docker.internal. On Docker Desktop (macOS/
# Windows) that maps to the host and 127.0.0.1 is reachable; on native Linux it resolves to
# the docker bridge gateway, so a 127.0.0.1-only publish is unreachable from the sandbox —
# browsing then fails CLOSED (the proxy env points at a dead address). Bind to the bridge
# gateway on Linux: reachable by containers via host-gateway, NOT exposed off-host.
eg_web_bind() {
  detect_os 2>/dev/null || true
  if [ "${OS_TYPE:-}" = "linux" ]; then
    local gw; gw="$(docker network inspect bridge -f '{{range .IPAM.Config}}{{.Gateway}}{{end}}' 2>/dev/null | head -1)"
    [ -n "$gw" ] && { printf '%s' "$gw"; return 0; }
  fi
  printf '127.0.0.1'
}

compute_egress_endpoints() {
  EGRESS_STACK_HTTP=""; EGRESS_WEB_HTTP=""; EG_SANDBOX_HTTP=""
  egress_stack_enabled && EGRESS_STACK_HTTP="http://proxy-stack:$(eg_mode_port "$EGRESS_STACK")"
  if egress_web_enabled; then
    EGRESS_WEB_HTTP="http://proxy-web:$(eg_mode_port "$EGRESS_WEB")"
    EG_SANDBOX_HTTP="http://host.docker.internal:${EG_HOST_WEB_PORT}"
  fi
}

# NO_PROXY for the apps. Local model endpoint (host.docker.internal) is excluded
# UNLESS PSAI_ROUTE_LOCAL_LLM=true (then local model calls also flow via proxy-stack).
egress_no_proxy() {
  local np="localhost,127.0.0.1,::1,openwebui,openhands,searxng,qdrant,mcp,mcp-gateway,memory,embed,ollama,litellm,langfuse,langfuse-db,ingest-docling,ingest-tika,falkordb,forgejo,caddy,proxy-stack,proxy-web,.${DOMAIN_BASE}"
  [ "${ROUTE_LOCAL_LLM:-false}" = "true" ] || np="$np,host.docker.internal"
  printf '%s' "$np"
}

# Proxy env lines for the APPS (openwebui/openhands) — their LLM API egress via proxy-stack.
stack_env_lines() {
  egress_stack_enabled || return 0
  stack_via_proxy || return 0
  compute_egress_endpoints
  local np; np="$(egress_no_proxy)"
  cat <<EOF
      - HTTP_PROXY=$EGRESS_STACK_HTTP
      - HTTPS_PROXY=$EGRESS_STACK_HTTP
      - http_proxy=$EGRESS_STACK_HTTP
      - https_proxy=$EGRESS_STACK_HTTP
      - NO_PROXY=$np
      - no_proxy=$np
EOF
}

# Sandbox Dockerfile proxy ENV — the OpenHands sandbox browses via proxy-web.
sandbox_proxy_env_lines() {
  egress_web_enabled || return 0
  web_via_proxy || return 0
  compute_egress_endpoints
  cat <<EOF
ENV HTTP_PROXY=$EG_SANDBOX_HTTP HTTPS_PROXY=$EG_SANDBOX_HTTP http_proxy=$EG_SANDBOX_HTTP https_proxy=$EG_SANDBOX_HTTP
ENV NO_PROXY=localhost,127.0.0.1,host.docker.internal no_proxy=localhost,127.0.0.1,host.docker.internal
EOF
}

# SearXNG settings.yml (we own it now): json format for Open WebUI + optional
# search-engine egress via proxy-web. Written directly into data/searxng.
write_searxng_settings() {
  [ "$ENABLE_SEARCH" = "true" ] || return 0
  mkdir -p "$STACK_DIR/data/searxng"
  compute_egress_endpoints
  local proxied="false" sx
  egress_web_enabled && web_via_proxy && proxied="true"
  # Real session key, taken from the secret store (stack-vault when sealed, else the
  # 0600 passwords.txt). The base searxng/searxng image only randomizes secret_key when
  # it CREATES settings.yml from its template (if [ ! -f ]) and never reads SEARXNG_SECRET
  # — so a pre-written file left as "ultrasecretkey" would ship a world-known key. We
  # inject the generated secret directly; the file itself is 0600.
  sx="$(secret_get searxng_secret searxng_secret_gen)"
  ( umask 077; {
    printf 'use_default_settings: true\n'
    printf 'server:\n  secret_key: "%s"\n  limiter: false\n  image_proxy: true\n' "$sx"
    printf 'search:\n  formats:\n    - html\n    - json\n'
    if [ "$proxied" = "true" ]; then
      printf 'outgoing:\n  request_timeout: 15.0\n  proxies:\n    all://:\n      - %s\n' "$EGRESS_WEB_HTTP"
    fi
  } > "$STACK_DIR/data/searxng/settings.yml" )
  chmod 600 "$STACK_DIR/data/searxng/settings.yml" 2>/dev/null || true
}

# ── provider config ─────────────────────────────────────────────────────────
vless_q() { printf '%s' "$1" | tr '&' '\n' | sed -n "s/^$2=//p" | head -1; }

write_xray_config() {
  local uri="$1" dir="$2" rest uuid hostport host port query
  rest="${uri#vless://}"; rest="${rest%%#*}"
  query="${rest#*\?}"; [ "$query" = "$rest" ] && query=""
  rest="${rest%%\?*}"
  uuid="${rest%@*}"; hostport="${rest#*@}"; host="${hostport%%:*}"; port="${hostport#*:}"
  local typ sec sni pbk sid flow fp
  typ="$(vless_q "$query" type)"; sec="$(vless_q "$query" security)"; sni="$(vless_q "$query" sni)"
  pbk="$(vless_q "$query" pbk)"; sid="$(vless_q "$query" sid)"; flow="$(vless_q "$query" flow)"; fp="$(vless_q "$query" fp)"
  [ -n "$typ" ] || typ="tcp"; [ -n "$sec" ] || sec="none"; [ -n "$fp" ] || fp="chrome"
  local reality=""
  [ "$sec" = "reality" ] && reality="\"realitySettings\": { \"serverName\": \"$sni\", \"fingerprint\": \"$fp\", \"publicKey\": \"$pbk\", \"shortId\": \"$sid\" },"
  mkdir -p "$dir"
  cat > "$dir/xray-config.json" <<EOF
{
  "log": {"loglevel": "warning"},
  "inbounds": [
    {"listen": "0.0.0.0", "port": 1080, "protocol": "socks", "settings": {"udp": true}},
    {"listen": "0.0.0.0", "port": 8118, "protocol": "http"}
  ],
  "outbounds": [
    {
      "protocol": "vless",
      "settings": {"vnext": [{"address": "$host", "port": ${port:-443}, "users": [{"id": "$uuid", "encryption": "none", "flow": "$flow"}]}]},
      "streamSettings": {"network": "$typ", "security": "$sec", $reality "tlsSettings": {"serverName": "$sni", "fingerprint": "$fp"}}
    }
  ]
}
EOF
}

# Resolve a hostname's IPv4 A records (best-effort; dig/getent/host). Used to expand
# the FQDN allow-list into /32 entries at config-generation time.
proxy_resolve_a() {
  local h="$1"
  if command_exists dig;    then dig +short A "$h" 2>/dev/null | grep -E '^[0-9.]+$'
  elif command_exists getent; then getent ahostsv4 "$h" 2>/dev/null | awk '{print $1}' | sort -u
  elif command_exists host;   then host -t A "$h" 2>/dev/null | awk '/has address/{print $NF}'
  fi
}

# Turn a user-supplied WireGuard conf into a firewall/router: pin DNS, add a
# kill-switch (reject any egress not leaving via the tunnel — no leak if it drops),
# and an optional allow-list (drop everything else) of CIDRs plus FQDNs resolved to /32
# at config time (re-run egress config to refresh). Idempotent; wg-quick runs PostUp/PreDown.
harden_wg_conf() {
  local f="$1"; [ -f "$f" ] || return 0
  grep -q 'psai-fw' "$f" 2>/dev/null && return 0
  local dns="${PROXY_DNS:-}" ks="" allow="${PROXY_ALLOW_CIDR:-}"
  if [ -n "${PROXY_ALLOW_FQDN:-}" ]; then
    local d ip
    # shellcheck disable=SC2086
    for d in $PROXY_ALLOW_FQDN; do
      for ip in $(proxy_resolve_a "$d"); do allow="$allow ${ip}/32"; done
    done
    allow="$(printf '%s' "$allow" | tr -s ' ' | sed 's/^ //;s/ $//')"
  fi
  [ "${PROXY_KILLSWITCH:-true}" = "true" ] && ks=1
  awk -v dns="$dns" -v ks="$ks" -v allow="$allow" '
    /^\[Interface\]/ && ins==0 {
      print; print "# psai-fw"
      if (dns != "") print "DNS = " dns
      if (allow != "") { n=split(allow,a," "); for(i=1;i<=n;i++){
        print "PostUp = iptables -I OUTPUT -d " a[i] " -j ACCEPT" } }
      if (ks != "") {
        print "PostUp = iptables -I OUTPUT ! -o %i -m mark ! --mark $(wg show %i fwmark) -m addrtype ! --dst-type LOCAL -j REJECT || true"
        print "PreDown = iptables -D OUTPUT ! -o %i -m mark ! --mark $(wg show %i fwmark) -m addrtype ! --dst-type LOCAL -j REJECT || true"
      }
      ins=1; next
    }
    { print }
  ' "$f" > "$f.tmp" && mv "$f.tmp" "$f"
  chmod 600 "$f" 2>/dev/null || true
}

# configure_egress_secrets <slot>  (slot = stack | web). Collects provider config into
# the slot's gateway dir; falls back to tor if required config is missing.
configure_egress_secrets() {
  local slot="$1" mode dir
  case "$slot" in
    stack) mode="$EGRESS_STACK"; dir="$STACK_DIR/gateway-stack" ;;
    web)   mode="$EGRESS_WEB";   dir="$STACK_DIR/gateway-web" ;;
    *) return 0 ;;
  esac
  [ "$mode" != "none" ] || return 0
  mkdir -p "$dir"
  case "$mode" in
    vless)
      local uri; uri="$(cat "$dir/vless-uri.txt" 2>/dev/null || true)"
      [ -z "$uri" ] && [ "$NONINTERACTIVE" != "1" ] && uri="$(ask "$(t q_vless_uri)" '')"
      if [ -z "$uri" ] && [ ! -f "$dir/xray-config.json" ]; then egress_fallback_tor "$slot"; return 0; fi
      [ -n "$uri" ] && { ( umask 077; printf '%s\n' "$uri" > "$dir/vless-uri.txt" ); write_xray_config "$uri" "$dir"; } ;;
    wireguard)
      local src; src="$(cat "$dir/wg-path.txt" 2>/dev/null || true)"
      [ -z "$src" ] && [ "$NONINTERACTIVE" != "1" ] && src="$(ask "$(t q_wg_conf)" '')"
      mkdir -p "$dir/wg_confs"
      if [ -n "$src" ] && [ -f "${src/#\~/$HOME}" ]; then
        cp "${src/#\~/$HOME}" "$dir/wg_confs/wg0.conf"
        ( umask 077; printf '%s\n' "$src" > "$dir/wg-path.txt" )
      fi
      [ -f "$dir/wg_confs/wg0.conf" ] || { egress_fallback_tor "$slot"; return 0; }
      harden_wg_conf "$dir/wg_confs/wg0.conf" ;;
    adguardvpn)
      local u p; u="$(cat "$dir/ag-user.txt" 2>/dev/null || true)"
      if [ -z "$u" ] && [ "$NONINTERACTIVE" != "1" ]; then
        u="$(ask "$(t q_ag_user)" '')"
        printf '  %s: ' "$(t pw_label)"; stty -echo 2>/dev/null; IFS= read -r p || true; stty echo 2>/dev/null; printf '\n'
        [ -n "$u" ] && ( umask 077; printf '%s\n' "$u" > "$dir/ag-user.txt"; printf '%s\n' "$p" > "$dir/ag-pass.txt" )
      fi
      [ -s "$dir/ag-user.txt" ] || { egress_fallback_tor "$slot"; return 0; } ;;
    tailscale)
      local key; key="$(cat "$dir/ts-authkey.txt" 2>/dev/null || true)"
      [ -z "$key" ] && [ "$NONINTERACTIVE" != "1" ] && key="$(ask "$(t q_ts_key)" '')"
      [ -n "$key" ] && ( umask 077; printf '%s\n' "$key" > "$dir/ts-authkey.txt" )
      key="$(cat "$dir/ts-authkey.txt" 2>/dev/null || true)"
      [ -z "$key" ] && { egress_fallback_tor "$slot"; return 0; }
      ( umask 077; printf 'TS_AUTHKEY=%s\nTS_EXTRA_ARGS=\n' "$key" > "$dir/tailscale.env" ) ;;
  esac
}

egress_fallback_tor() {
  printf '%s%s%s\n' "$C_YELLOW" "$(t px_need_cfg)" "$C_RESET"
  case "$1" in stack) EGRESS_STACK="tor" ;; web) EGRESS_WEB="tor" ;; esac
  compute_egress_endpoints
}

# ── compose service emitter ──────────────────────────────────────────────────
# append_proxy_service <slot>  — appends the proxy (and its sidecar) to the compose
# file. proxy-web is published on host loopback; proxy-stack is internal-only.
append_proxy_service() {
  local slot="$1" name mode dir hostport f nets=""
  f="$STACK_DIR/compose/docker-compose.yml"
  case "$slot" in
    stack) name="proxy-stack"; mode="$EGRESS_STACK"; dir="../gateway-stack"; hostport="" ;;
    web)   name="proxy-web";   mode="$EGRESS_WEB";   dir="../gateway-web";   hostport="$EG_HOST_WEB_PORT" ;;
    *) return 0 ;;
  esac
  [ "$mode" != "none" ] || return 0
  # NOTE: proxy-stack stays on the default app network only. It is deliberately NOT joined
  # to ollama-private: bridging it there would give app containers a forward-proxy hop to
  # raw Ollama. Pulling models through the proxy is handled by the one-shot ollama-pull
  # (see append_ollama_service), which runs on the app network instead.
  local iport; iport="$(eg_mode_port "$mode")"; local sc="${name}-http"
  local ports=""; [ -n "$hostport" ] && ports="    ports:
      - \"$(eg_web_bind):${hostport}:${iport}\""
  case "$mode" in
    tor)
      cat >> "$f" <<EOF

  $name:
    image: $TOR_IMAGE
    container_name: ${SAFE_STACK_NAME}-$name
    restart: unless-stopped
$ports
$nets
EOF
      ;;
    vless)
      cat >> "$f" <<EOF

  $name:
    image: $XRAY_IMAGE
    container_name: ${SAFE_STACK_NAME}-$name
    restart: unless-stopped
    command: ["run", "-c", "/etc/xray/config.json"]
    volumes:
      - $dir/xray-config.json:/etc/xray/config.json:ro
$ports
$nets
EOF
      ;;
    wireguard)
      cat >> "$f" <<EOF

  $name:
    image: $WIREGUARD_IMAGE
    container_name: ${SAFE_STACK_NAME}-$name
    restart: unless-stopped
    cap_add: [NET_ADMIN, SYS_MODULE]
    sysctls:
      - net.ipv4.conf.all.src_valid_mark=1
    volumes:
      - $dir/wg_confs:/config/wg_confs:ro
$ports
$nets

  $sc:
    image: $HTTP_SIDECAR_IMAGE
    container_name: ${SAFE_STACK_NAME}-$sc
    restart: unless-stopped
    command: ["ANY"]
    network_mode: "service:$name"
    depends_on: [$name]
EOF
      ;;
    adguardvpn)
      cat >> "$f" <<EOF

  $name:
    image: $ADGUARDVPN_IMAGE
    container_name: ${SAFE_STACK_NAME}-$name
    restart: unless-stopped
    cap_add: [NET_ADMIN]
    devices:
      - /dev/net/tun
    volumes:
      - $dir/adguardvpn:/opt/adguardvpn_cli
$ports
$nets

  $sc:
    image: $HTTP_SIDECAR_IMAGE
    container_name: ${SAFE_STACK_NAME}-$sc
    restart: unless-stopped
    command: ["ANY"]
    network_mode: "service:$name"
    depends_on: [$name]
EOF
      ;;
    tailscale)
      cat >> "$f" <<EOF

  $name:
    image: $TAILSCALE_IMAGE
    container_name: ${SAFE_STACK_NAME}-$name
    restart: unless-stopped
    cap_add: [NET_ADMIN, SYS_MODULE]
    devices:
      - /dev/net/tun
    environment:
      - TS_STATE_DIR=/var/lib/tailscale
      - TS_USERSPACE=false
    env_file:
      - $dir/tailscale.env
    volumes:
      - ../data/tailscale:/var/lib/tailscale
$ports
$nets

  $sc:
    image: $HTTP_SIDECAR_IMAGE
    container_name: ${SAFE_STACK_NAME}-$sc
    restart: unless-stopped
    command: ["ANY"]
    network_mode: "service:$name"
    depends_on: [$name]
EOF
      ;;
  esac
}

# ── install-time prompts ──────────────────────────────────────────────────────
choose_egress_slot() {
  local slot="$1" def="$2" c
  menu_line "$(t px_mode)" 0 "$(t px_none)" 1 "$(t px_tor)" 2 "$(t px_wireguard)" 3 "$(t px_vless)"
  menu_line "" 4 "$(t px_adguard)" 5 "$(t px_tailscale)"
  c="$(ask "$(t px_pick)" "$def")"
  local mode
  case "$(printf '%s' "$c" | tr -d '[][:space:]' | tr 'A-Z' 'a-z')" in
    1|tor) mode="tor" ;; 2|wireguard|wg) mode="wireguard" ;; 3|vless) mode="vless" ;;
    4|adguardvpn|adguard) mode="adguardvpn" ;; 5|tailscale|ts) mode="tailscale" ;;
    *) mode="none" ;;
  esac
  case "$slot" in stack) EGRESS_STACK="$mode" ;; web) EGRESS_WEB="$mode" ;; esac
}

# Both proxies are OFFERED at install; default DIRECT (none). Presets when enabled:
# proxy-stack → Tor, proxy-web → WireGuard.
ask_proxies() {
  printf '\n%s%s%s\n' "$C_B" "$(t px_title)" "$C_RESET"
  printf '  %s%s%s\n  %s%s%s\n' "$C_DIM" "$(t px_stack)" "$C_RESET" "$C_DIM" "$(t px_web)" "$C_RESET"
  if confirm "$(t px_stack_q)" 'N'; then
    choose_egress_slot stack '1'; configure_egress_secrets stack
    if confirm "$(t px_local_q)" 'N'; then ROUTE_LOCAL_LLM="true"; else ROUTE_LOCAL_LLM="false"; fi
  else EGRESS_STACK="none"; fi
  if confirm "$(t px_web_q)" 'N'; then
    choose_egress_slot web '2'; configure_egress_secrets web
  else EGRESS_WEB="none"; fi
  compute_egress_endpoints
  return 0   # never let a trailing non-zero abort the installer under set -e
}
# ───────────────────────────── /etc/hosts + CA trust ─────────────────────────────
# Local profile only: map the service domains to 127.0.0.1 and trust the local CA
# so HTTPS works in the browser. Public profile uses real DNS + a public/own cert.

active_domains_list() {
  local d="$PSAI_DOMAIN"
  [ "$ENABLE_AGENTS" = "true" ] && d="$d $AGENTS_DOMAIN"
  [ "$ENABLE_GIT" = "true" ]    && d="$d $GIT_DOMAIN $GIT_SSH_HOST"
  [ "$ENABLE_QDRANT" = "true" ] && d="$d $QDRANT_DOMAIN"
  printf '%s' "$d"
}

hosts_marker() { printf '# psai:%s' "$SAFE_STACK_NAME"; }

add_hosts_entries() {
  [ "$DEPLOY_PROFILE" = "public" ] && return 0
  no_domain && return 0   # localhost ports — no /etc/hosts mapping needed
  load_config 2>/dev/null || true
  detect_os
  local marker line d; marker="$(hosts_marker)"
  line="127.0.0.1 $(active_domains_list) $marker"
  can_use_sudo || { print_hosts_command; return 0; }
  local S=""; [ "$(id -u)" = "0" ] || S="sudo"
  $S sh -c "grep -v '$marker' /etc/hosts > /etc/hosts.psai.tmp 2>/dev/null; printf '%s\n' '$line' >> /etc/hosts.psai.tmp; cat /etc/hosts.psai.tmp > /etc/hosts; rm -f /etc/hosts.psai.tmp" 2>/dev/null || true
  printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
}

print_hosts_command() {
  printf '  %s/etc/hosts:%s\n    127.0.0.1 %s %s\n' "$C_DIM" "$C_RESET" "$(active_domains_list)" "$(hosts_marker)"
}

remove_hosts_entries() {
  [ "$DEPLOY_PROFILE" = "public" ] && return 0
  no_domain && return 0
  detect_os
  local marker; marker="$(hosts_marker)"
  grep -q "$marker" /etc/hosts 2>/dev/null || return 0
  if ! can_use_sudo; then print_remove_hosts_command; return 0; fi
  local S=""; [ "$(id -u)" = "0" ] || S="sudo"
  $S sh -c "grep -v '$marker' /etc/hosts > /etc/hosts.psai.tmp 2>/dev/null; cat /etc/hosts.psai.tmp > /etc/hosts; rm -f /etc/hosts.psai.tmp" 2>/dev/null || true
}

print_remove_hosts_command() {
  printf '  sudo sh -c %s\n' "$(shq "grep -v '$(hosts_marker)' /etc/hosts > /etc/hosts.psai.tmp && cat /etc/hosts.psai.tmp > /etc/hosts && rm -f /etc/hosts.psai.tmp")"
}

do_trust_ca() {
  detect_os
  local crt="$STACK_DIR/secrets/certificates/root.crt"
  [ -f "$crt" ] || return 1
  case "$OS_TYPE" in
    macos) sudo security add-trusted-cert -d -r trustRoot -k /Library/Keychains/System.keychain "$crt" ;;
    linux) sudo cp "$crt" "/usr/local/share/ca-certificates/${SAFE_STACK_NAME}_root.crt" && sudo update-ca-certificates ;;
    *) return 1 ;;
  esac
}

trust_ca() {
  load_config 2>/dev/null || true
  caddy_use_acme && { printf '%s\n' "ACME — no local CA to trust."; return 0; }
  if do_trust_ca; then printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
  else print_trust_ca_command; fi
}

print_trust_ca_command() {
  detect_os
  local crt="$STACK_DIR/secrets/certificates/root.crt"
  case "$OS_TYPE" in
    macos) printf '  sudo security add-trusted-cert -d -r trustRoot -k /Library/Keychains/System.keychain %s\n' "$crt" ;;
    linux) printf '  sudo cp %s /usr/local/share/ca-certificates/%s_root.crt && sudo update-ca-certificates\n' "$crt" "$SAFE_STACK_NAME" ;;
  esac
}

# Best-effort DNS A-record check for the public profile.
check_arecord() {
  local domain="$1" ip
  command_exists dig && ip="$(dig +short A "$domain" 2>/dev/null | head -1)"
  [ -z "${ip:-}" ] && command_exists host && ip="$(host -t A "$domain" 2>/dev/null | awk '/has address/{print $NF; exit}')"
  [ -z "${ip:-}" ] && command_exists getent && ip="$(getent hosts "$domain" 2>/dev/null | awk '{print $1; exit}')"
  printf '%s' "${ip:-}"
}
# ───────────────────────────── caddy / TLS ─────────────────────────────
# TLS source:
#   local profile            -> local CA (we issue + the host trusts root.crt)
#   public + domain + le     -> ACME (Let's Encrypt)
#   public + domain + own    -> bring-your-own cert files
#   public + no domain (self)-> self-signed for the host IP (reach the stack by IP)
caddy_use_acme()     { [ "$DEPLOY_PROFILE" = "public" ] && [ -n "${PUBLIC_DOMAIN:-}" ] && [ "${TLS_MODE:-le}" = "le" ]; }
caddy_use_own_cert() { [ "$DEPLOY_PROFILE" = "public" ] && [ -n "${PUBLIC_DOMAIN:-}" ] && [ "${TLS_MODE:-le}" = "own" ]; }
caddy_use_self()     { [ "$DEPLOY_PROFILE" = "public" ] && [ -z "${PUBLIC_DOMAIN:-}" ]; }

# The primary backend behind the main vhost: Open WebUI, or OpenHands if WebUI is off.
main_backend() {
  if [ "$ENABLE_OPENWEBUI" = "true" ]; then printf 'openwebui:8080'
  elif [ "$ENABLE_AGENTS" = "true" ]; then printf 'openhands:3000'
  else printf 'openwebui:8080'; fi
}
# The host the main vhost answers on.
main_host() {
  if caddy_use_self; then host_ip; else printf '%s' "$PSAI_DOMAIN"; fi
}

generate_local_ca_and_cert() {
  no_domain && return 0   # localhost ports over http — no certs needed
  caddy_use_acme && return 0
  caddy_use_own_cert && { install_own_cert; return 0; }
  local pki days leaf_days san i domains domain
  pki="$STACK_DIR/secrets/certificates"; mkdir -p "$pki"
  days=$(( ${CERT_YEARS:-3} * 365 )); [ "$days" -lt 365 ] && days=365
  leaf_days="$days"; [ "$leaf_days" -gt 397 ] && leaf_days=397   # Apple caps server certs at 398d
  domains="$PSAI_DOMAIN"
  [ "$ENABLE_AGENTS" = "true" ] && domains="$domains $AGENTS_DOMAIN"
  [ "$ENABLE_GIT" = "true" ]    && domains="$domains $GIT_DOMAIN $GIT_SSH_HOST"
  [ "$ENABLE_QDRANT" = "true" ] && domains="$domains $QDRANT_DOMAIN"

  if [ ! -f "$pki/root.key" ] || [ ! -f "$pki/root.crt" ]; then
    openssl genrsa -out "$pki/root.key" 4096 >/dev/null 2>&1
    openssl req -x509 -new -nodes -key "$pki/root.key" -sha256 -days "$days" \
      -subj "/CN=${STACK_NAME} Local Root CA/O=psai" -out "$pki/root.crt" >/dev/null 2>&1
    chmod 600 "$pki/root.key"
  fi
  san="$pki/san.cnf"
  {
    printf '[req]\ndistinguished_name=req\n[v3_req]\n'
    printf 'keyUsage = digitalSignature, keyEncipherment\nextendedKeyUsage = serverAuth\nsubjectAltName = @alt_names\n[alt_names]\n'
    i=1
    # shellcheck disable=SC2086
    for domain in $domains localhost; do printf 'DNS.%s = %s\n' "$i" "$domain"; i=$((i + 1)); done
    printf 'IP.1 = 127.0.0.1\nIP.2 = ::1\n'
    caddy_use_self && printf 'IP.3 = %s\n' "$(host_ip)"
  } > "$san"
  openssl genrsa -out "$pki/local.key" 2048 >/dev/null 2>&1
  openssl req -new -key "$pki/local.key" -subj "/CN=$(main_host)" -out "$pki/local.csr" >/dev/null 2>&1
  openssl x509 -req -in "$pki/local.csr" -CA "$pki/root.crt" -CAkey "$pki/root.key" -CAcreateserial \
    -out "$pki/local.crt" -days "$leaf_days" -sha256 -extfile "$san" -extensions v3_req >/dev/null 2>&1
  chmod 600 "$pki/local.key"
}

install_own_cert() {
  local pki="$STACK_DIR/secrets/certificates"; mkdir -p "$pki"
  [ -f "${OWN_CERT_PATH/#\~/$HOME}" ] && cp "${OWN_CERT_PATH/#\~/$HOME}" "$pki/own.crt"
  [ -f "${OWN_KEY_PATH/#\~/$HOME}" ]  && cp "${OWN_KEY_PATH/#\~/$HOME}"  "$pki/own.key"
  chmod 600 "$pki/own.key" 2>/dev/null || true
}

# Dual access: append plain loopback-port vhosts (localhost-only, no TLS/auth) so the stack is
# reachable on http://localhost:PORT in addition to the .lan HTTPS domains. Local profile only.
write_caddy_dual_loopback() {
  dual_access || return 0
  local f="$STACK_DIR/compose/Caddyfile" mb; mb="$(main_backend)"
  {
    printf '\n(loop) {\n    encode zstd gzip\n    header -Server\n}\n'
    [ "$ENABLE_OPENWEBUI" = "true" ] && printf '\n:%s {\n    import loop\n    reverse_proxy %s\n}\n' "$PORT_PSAI" "$mb"
    [ "$ENABLE_OPENWEBUI" != "true" ] && [ "$ENABLE_AGENTS" = "true" ] && printf '\n:%s {\n    import loop\n    reverse_proxy openhands:3000\n}\n' "$PORT_PSAI"
    [ "$ENABLE_OPENWEBUI" = "true" ] && [ "$ENABLE_AGENTS" = "true" ] && printf '\n:%s {\n    import loop\n    reverse_proxy openhands:3000\n}\n' "$PORT_AGENTS"
    [ "$ENABLE_GIT" = "true" ]    && printf '\n:%s {\n    import loop\n    reverse_proxy forgejo:3000\n}\n' "$PORT_GIT"
    [ "$ENABLE_QDRANT" = "true" ] && printf '\n:%s {\n    import loop\n    reverse_proxy qdrant:6333\n}\n' "$PORT_QDRANT"
  } >> "$f"
}

write_caddyfile() {
  local f="$STACK_DIR/compose/Caddyfile"
  local webui_hash="" agents_hash="" qdrant_hash=""
  [ "$ENABLE_AGENTS" = "true" ]   && agents_hash="$(hash_password "$(secret_get agents_basic_auth)")"
  [ "$ENABLE_QDRANT" = "true" ]   && qdrant_hash="$(hash_password "$(secret_get qdrant_basic_auth)")"
  # Open WebUI has its own login; add a Caddy gate only on public deployments.
  [ "$ENABLE_OPENWEBUI" = "true" ] && [ "$DEPLOY_PROFILE" = "public" ] && webui_hash="$(hash_password "$(secret_get webui_basic_auth)")"

  # No-domain local mode: each service on its own loopback HTTP port, no TLS/host match.
  if no_domain; then
    {
      printf '{\n    admin off\n}\n\n'
      printf '(common_http) {\n    encode zstd gzip\n    header {\n'
      printf '        X-Content-Type-Options "nosniff"\n        X-Frame-Options "SAMEORIGIN"\n        -Server\n    }\n}\n\n'
      if [ "$ENABLE_OPENWEBUI" = "true" ]; then
        printf ':%s {\n    import common_http\n    reverse_proxy %s\n}\n\n' "$PORT_PSAI" "$(main_backend)"
      elif [ "$ENABLE_AGENTS" = "true" ]; then
        printf ':%s {\n    import common_http\n    basic_auth {\n        %s %s\n    }\n    reverse_proxy openhands:3000\n}\n\n' "$PORT_PSAI" "$ADMIN_USER" "$(hash_password "$(secret_get agents_basic_auth)")"
      fi
      if [ "$ENABLE_OPENWEBUI" = "true" ] && [ "$ENABLE_AGENTS" = "true" ]; then
        printf ':%s {\n    import common_http\n    basic_auth {\n        %s %s\n    }\n    reverse_proxy openhands:3000\n}\n\n' "$PORT_AGENTS" "$ADMIN_USER" "$(hash_password "$(secret_get agents_basic_auth)")"
      fi
      [ "$ENABLE_GIT" = "true" ]    && printf ':%s {\n    import common_http\n    reverse_proxy forgejo:3000\n}\n\n' "$PORT_GIT"
      [ "$ENABLE_QDRANT" = "true" ] && printf ':%s {\n    import common_http\n    basic_auth {\n        %s %s\n    }\n    reverse_proxy qdrant:6333\n}\n\n' "$PORT_QDRANT" "$ADMIN_USER" "$(hash_password "$(secret_get qdrant_basic_auth)")"
    } > "$f"
    return 0
  fi

  # global options
  {
    printf '{\n    admin off\n'
    caddy_use_acme && [ -n "${ACME_EMAIL:-}" ] && printf '    email %s\n' "$ACME_EMAIL"
    printf '}\n\n'
  } > "$f"

  # shared snippet
  {
    printf '(common) {\n'
    if caddy_use_own_cert; then printf '    tls /certs/own.crt /certs/own.key\n'
    elif ! caddy_use_acme;  then printf '    tls /certs/local.crt /certs/local.key\n'; fi
    printf '    encode zstd gzip\n'
    printf '    header {\n'
    printf '        Strict-Transport-Security "max-age=31536000"\n'
    printf '        X-Content-Type-Options "nosniff"\n'
    printf '        X-Frame-Options "SAMEORIGIN"\n'
    printf '        Referrer-Policy "strict-origin-when-cross-origin"\n        -Server\n    }\n'
    if [ "$DEPLOY_PROFILE" = "public" ]; then
      printf '    log {\n        output file /data/logs/caddy/access.log {\n            roll_size 10MiB\n            roll_keep 5\n        }\n        format json\n    }\n'
    fi
    printf '}\n\n'
  } >> "$f"

  local mb auth=""
  mb="$(main_backend)"
  # OpenHands as the main backend (no WebUI) gets basic_auth; WebUI gets it only on public.
  if [ "$ENABLE_OPENWEBUI" != "true" ] && [ "$ENABLE_AGENTS" = "true" ]; then
    auth="    basic_auth {
        $ADMIN_USER $agents_hash
    }
"
  elif [ -n "$webui_hash" ]; then
    auth="    basic_auth {
        $ADMIN_USER $webui_hash
    }
"
  fi

  # localhost vhost only with the local CA (local profile).
  if [ "$DEPLOY_PROFILE" != "public" ]; then
    cat >> "$f" <<EOF
localhost, 127.0.0.1 {
    import common
$auth    reverse_proxy $mb
}

EOF
  fi

  cat >> "$f" <<EOF
$(main_host) {
    import common
$auth    reverse_proxy $mb
}
EOF

  # OpenHands on its own vhost (when WebUI is the main backend).
  if [ "$ENABLE_AGENTS" = "true" ] && [ "$ENABLE_OPENWEBUI" = "true" ] && ! caddy_use_self; then
    cat >> "$f" <<EOF

$AGENTS_DOMAIN {
    import common
    basic_auth {
        $ADMIN_USER $agents_hash
    }
    reverse_proxy openhands:3000
}
EOF
  fi

  if [ "$ENABLE_GIT" = "true" ] && ! caddy_use_self; then
    cat >> "$f" <<EOF

$GIT_DOMAIN {
    import common
    reverse_proxy forgejo:3000
}
EOF
  fi

  if [ "$ENABLE_QDRANT" = "true" ] && ! caddy_use_self; then
    cat >> "$f" <<EOF

$QDRANT_DOMAIN {
    import common
    basic_auth {
        $ADMIN_USER $qdrant_hash
    }
    reverse_proxy qdrant:6333
}
EOF
  fi
  write_caddy_dual_loopback
}
# ───────────────────────────── compose generator ─────────────────────────────
# One self-contained docker-compose.yml (no upstream repo). Services are appended
# conditionally so disabled components never appear.

COMPOSE_FILE() { printf '%s/compose/docker-compose.yml' "$STACK_DIR"; }

compose_header() {
  cat > "$(COMPOSE_FILE)" <<EOF
# Generated by psai — do not edit by hand (regenerated on rebuild/reconfig).
name: $SAFE_STACK_NAME
services:
EOF
}

# Dual access = domains AND loopback ports (local only). Loopback port publishes for Caddy.
dual_access() { [ "${DUAL_ACCESS:-false}" = "true" ] && ! no_domain; }
caddy_loopback_ports() {
  local p=""
  { [ "$ENABLE_OPENWEBUI" = "true" ] || [ "$ENABLE_AGENTS" = "true" ]; } && p="$p
      - \"127.0.0.1:${PORT_PSAI}:${PORT_PSAI}\""
  [ "$ENABLE_OPENWEBUI" = "true" ] && [ "$ENABLE_AGENTS" = "true" ] && p="$p
      - \"127.0.0.1:${PORT_AGENTS}:${PORT_AGENTS}\""
  [ "$ENABLE_GIT" = "true" ]    && p="$p
      - \"127.0.0.1:${PORT_GIT}:${PORT_GIT}\""
  [ "$ENABLE_QDRANT" = "true" ] && p="$p
      - \"127.0.0.1:${PORT_QDRANT}:${PORT_QDRANT}\""
  printf '%s' "$p"
}

compose_caddy() {
  local dep=""
  [ "$ENABLE_OPENWEBUI" = "true" ] && dep="$dep
      - openwebui"
  [ "$ENABLE_AGENTS" = "true" ]    && dep="$dep
      - openhands"
  [ "$ENABLE_GIT" = "true" ]       && dep="$dep
      - forgejo"
  [ "$ENABLE_QDRANT" = "true" ]    && dep="$dep
      - qdrant"
  [ -n "$dep" ] && dep="    depends_on:$dep"
  local ports='      - "80:80"
      - "443:443"'
  if no_domain; then
    ports="$(caddy_loopback_ports)"          # loopback ports only; no 80/443
  elif dual_access; then
    ports="$ports$(caddy_loopback_ports)"    # domains (80/443) AND loopback ports
  fi
  cat >> "$(COMPOSE_FILE)" <<EOF
  caddy:
    image: $CADDY_IMAGE
    container_name: ${SAFE_STACK_NAME}-caddy
    restart: unless-stopped
    security_opt: [ "no-new-privileges:true" ]
    ports:
$ports
    volumes:
      - ./Caddyfile:/etc/caddy/Caddyfile:ro
      - ../caddy/data:/data
      - ../caddy/config:/config
      - ../secrets/certificates:/certs:ro
$dep
EOF
}

compose_openwebui() {
  [ "$ENABLE_OPENWEBUI" = "true" ] || return 0
  local search="" vec=""
  if [ "$ENABLE_SEARCH" = "true" ]; then
    search="      - ENABLE_WEB_SEARCH=True
      - WEB_SEARCH_ENGINE=searxng
      - SEARXNG_QUERY_URL=http://searxng:8080/search?q=<query>
      - WEB_SEARCH_RESULT_COUNT=4
      - WEB_SEARCH_CONCURRENT_REQUESTS=10"
  fi
  if [ "$ENABLE_QDRANT" = "true" ]; then
    vec="      - VECTOR_DB=qdrant
      - QDRANT_URI=http://qdrant:6333"
    if [ -n "${EMBED_URL:-}" ]; then
      # External semantic embeddings: OpenAI-compatible endpoint.
      vec="$vec
      - RAG_EMBEDDING_ENGINE=openai
      - RAG_OPENAI_API_BASE_URL=$EMBED_URL
      - RAG_EMBEDDING_MODEL=${EMBED_MODEL:-$EMBEDDINGS_MODEL}"
    elif [ "$ENABLE_EMBEDDINGS" = "true" ]; then
      # Built-in sentence-transformers (runs in this container; arm64 + x86, no separate
      # image, offline). RAG_EMBEDDING_ENGINE empty = local.
      vec="$vec
      - RAG_EMBEDDING_ENGINE=
      - RAG_EMBEDDING_MODEL=$EMBEDDINGS_MODEL"
    fi
    # RAG-plus: a CrossEncoder reranker (the biggest precision lever) + optional hybrid
    # (dense+BM25). Hybrid is opt-in — its validity is debated and Open WebUI's hybrid path
    # has been flaky across releases — so reranking carries the win on its own by default.
    if [ "${RAG_MODE:-off}" = "plus" ] || [ "${ENABLE_EMBED_SVC:-false}" = "true" ]; then
      [ -n "${RERANK_MODEL:-}" ] && vec="$vec
      - RAG_RERANKING_MODEL=$RERANK_MODEL"
      [ "${RAG_HYBRID:-false}" = "true" ] && vec="$vec
      - ENABLE_RAG_HYBRID_SEARCH=true"
    fi
  fi
  # Document extraction via Docling (structure/tables/formulas/OCR) when the ingest layer is on.
  local extract=""
  if ingest_enabled; then
    extract="      - CONTENT_EXTRACTION_ENGINE=docling
      - DOCLING_SERVER_URL=http://ingest-docling:5001"
  fi
  # Bundled Ollama is exposed through an auth proxy. Prefer OpenAI-compatible
  # /v1 so Authorization is attached consistently; native Ollama clients differ
  # on whether they send OLLAMA_API_KEY.
  local ollama_env=""
  ollama_enabled && ! llm_gateway_enabled && ollama_env="      - OPENAI_API_BASE_URL=http://ollama:11434/v1"
  # LiteLLM gateway → chat's OpenAI endpoint routes through it (cloud routing/fallback/budgets).
  local gateway_env=""
  llm_gateway_enabled && gateway_env="      - OPENAI_API_BASE_URL=http://litellm:4000/v1
      - OPENAI_API_KEY=sk-$(secret_get litellm_master_key admin_pw_gen)"
  # Auto-register the MCP server as an Open WebUI OpenAPI tool server (best-effort: the
  # env is read on first run by Open WebUI versions that support tool-server connections).
  local owui_tools=""
  if owui_bridge_enabled; then
    # Memory + gateway tools, bridged to OpenAPI by mcpo, registered as chat tool servers.
    owui_tools="      - 'TOOL_SERVER_CONNECTIONS=$(owui_tool_server_connections)'"
  elif [ "$ENABLE_MCP" = "true" ]; then
    owui_tools='      - '"'"'TOOL_SERVER_CONNECTIONS=[{"url":"http://mcp:9000","path":"openapi.json","auth_type":"none","key":"","config":{"enable":true}}]'"'"''
  fi
  cat >> "$(COMPOSE_FILE)" <<EOF

  openwebui:
    image: $OPENWEBUI_IMAGE
    container_name: ${SAFE_STACK_NAME}-openwebui
    restart: unless-stopped
    cap_drop: [ ALL ]
    security_opt: [ "no-new-privileges:true" ]
    env_file:
      - .runtime.env
    environment:
      - WEBUI_URL=https://$PSAI_DOMAIN
      - ANONYMIZED_TELEMETRY=false
      - DO_NOT_TRACK=true
      - SCARF_NO_ANALYTICS=true
$search
$vec
$extract
$ollama_env
$gateway_env
$owui_tools
$(stack_env_lines)
    volumes:
      - ../data/openwebui:/app/backend/data
EOF
}

compose_searxng() {
  [ "$ENABLE_SEARCH" = "true" ] || return 0
  cat >> "$(COMPOSE_FILE)" <<EOF

  searxng:
    image: $SEARXNG_IMAGE
    container_name: ${SAFE_STACK_NAME}-searxng
    restart: unless-stopped
    security_opt: [ "no-new-privileges:true" ]
    env_file:
      - .runtime.env
    environment:
      - SEARXNG_BASE_URL=http://searxng:8080/
    volumes:
      - ../data/searxng:/etc/searxng
EOF
}

compose_forgejo() {
  [ "$ENABLE_GIT" = "true" ] || return 0
  # In no-domain (pure localhost) mode bind git-SSH to loopback only; with domains (LAN/
  # public) it must stay reachable on all interfaces for git-over-SSH.
  local gitbind=""; no_domain && gitbind="127.0.0.1:"
  cat >> "$(COMPOSE_FILE)" <<EOF

  forgejo:
    image: $FORGEJO_IMAGE
    container_name: ${SAFE_STACK_NAME}-forgejo
    restart: unless-stopped
    security_opt: [ "no-new-privileges:true" ]
    environment:
      - USER_UID=$(id -u)
      - USER_GID=$(id -g)
      - FORGEJO____APP_NAME=$STACK_NAME Git
      - FORGEJO__server__DOMAIN=$GIT_DOMAIN
      - FORGEJO__server__SSH_DOMAIN=$GIT_SSH_HOST
      - FORGEJO__server__ROOT_URL=https://$GIT_DOMAIN/
      - FORGEJO__server__SSH_PORT=$GIT_SSH_PORT
      - FORGEJO__service__DISABLE_REGISTRATION=true
      - FORGEJO__service__REQUIRE_SIGNIN_VIEW=true
      - FORGEJO__session__COOKIE_SECURE=true
      - FORGEJO__repository__DEFAULT_PRIVATE=private
      - FORGEJO__actions__ENABLED=false
    volumes:
      - ../data/forgejo:/data
      - /etc/localtime:/etc/localtime:ro
    ports:
      - "${gitbind}$GIT_SSH_PORT:22"
EOF
}

# Resolve the effective OpenHands docker mode. An explicit PSAI_OH_MODE always wins; otherwise
# untrusted deployments (public or multi-node) default to 'dind' (a nested daemon) instead of
# handing OpenHands the host's docker socket — host mode is effectively host-level control by
# the agent runtime. Single + local stays 'host' (simplest). Decided once at install and saved.
resolve_oh_mode() {
  [ "${OH_MODE_FROM_ENV:-0}" = "1" ] && return 0
  case "$OPENHANDS_DOCKER_MODE" in dind|rootless) return 0 ;; esac
  if [ "$DEPLOY_PROFILE" = "public" ] || [ "$NODE_MODE" = "multi" ]; then
    OPENHANDS_DOCKER_MODE="dind"
    printf '%sopenhands: untrusted deployment → docker mode = dind (nested daemon, not the host socket)%s\n' "$C_DIM" "$C_RESET" >&2
  fi
}

# Resolve PSAI_RAG into concrete component flags. plus = Qdrant + the local embed/rerank
# service + Docling/Tika ingest, with Open WebUI RAG and the MCP memory pointed at the local
# OpenAI-compatible embedder (replacing Open WebUI's built-in encoder and the MCP stub's
# keyword-only hash vectorizer). basic = Qdrant + Open WebUI's built-in embeddings. Decided
# at install and persisted, like resolve_oh_mode.
rag_uses_ollama_embeddings_default() {
  ollama_enabled || return 1
  [ -z "${PSAI_EMBED_URL:-}" ] || return 1
  [ -z "${PSAI_EMBED_SVC_MODEL:-}" ] || return 1
  [ -z "${PSAI_RERANK_MODEL:-}" ] || return 1
  detect_os 2>/dev/null || true
  case "${OS_TYPE:-unknown}:${ARCH_TYPE:-unknown}" in
    macos:*|linux:arm64) return 0 ;;
  esac
  return 1
}

resolve_rag_mode() {
  case "${RAG_MODE:-off}" in
    plus)
      ENABLE_QDRANT="true"; ENABLE_INGEST="true"
      if rag_uses_ollama_embeddings_default; then
        # Infinity's common image path is amd64-oriented; on macOS/arm64 and
        # Linux/arm64 it can end up behind emulation or unavailable. Use the
        # bundled Ollama OpenAI-compatible /v1/embeddings endpoint instead.
        ENABLE_EMBED_SVC="false"
        RERANK_MODEL=""
        [ -n "${EMBED_URL:-}" ]   || EMBED_URL="http://ollama:11434/v1"
        [ -n "${EMBED_MODEL:-}" ] || EMBED_MODEL="$OLLAMA_EMBED_MODEL"
      else
        ENABLE_EMBED_SVC="true"
      fi
      [ -n "${EMBED_URL:-}" ]   || EMBED_URL="http://embed:${EMBED_SVC_PORT:-7997}/v1"
      [ -n "${EMBED_MODEL:-}" ] || EMBED_MODEL="$EMBED_SVC_MODEL"
      if [ "${ENABLE_EMBED_SVC:-false}" = "true" ]; then
        printf '%s%s (%s)%s\n' "$C_DIM" "$(t rag_plus_infinity_note)" "$EMBED_SVC_MODEL" "$C_RESET" >&2
      else
        printf '%s%s (%s)%s\n' "$C_DIM" "$(t rag_plus_ollama_note)" "$EMBED_MODEL" "$C_RESET" >&2
      fi ;;
    basic)
      ENABLE_QDRANT="true"; ENABLE_EMBEDDINGS="true" ;;
  esac
  return 0
}

# Bundled local LLM (Ollama) is on.
ollama_enabled() { [ "${LOCAL_LLM:-none}" = "ollama" ]; }
# Point the memory backend (cognee/graphiti) at the bundled Ollama when no external LLM
# endpoint was given — so memory works locally without a cloud API key. Embeddings also fall back to
# Ollama when RAG-plus's Infinity service isn't up.
resolve_local_llm() {
  ollama_enabled || return 0
  [ -n "${GPU_MODE:-}" ] || GPU_MODE="$(gpu_runtime)"   # autodetect for non-interactive installs
  if [ -z "${MEMORY_LLM_URL:-}" ]; then
    MEMORY_LLM_URL="http://ollama:11434/v1"
    [ -n "${MEMORY_LLM_KEY:-}" ] || MEMORY_LLM_KEY="ollama"   # OpenAI clients want a non-empty key
    MEMORY_LLM_MODEL="$OLLAMA_MODEL"
  fi
  printf '%sLLM: bundled Ollama (%s) — memory uses local endpoint%s\n' "$C_DIM" "$OLLAMA_MODEL" "$C_RESET" >&2
  return 0
}

# Docker MCP Gateway is on.
mcp_gateway_enabled() { [ "${MCP_GATEWAY:-false}" = "true" ]; }
mcp_gateway_sse_url() { mcp_gateway_enabled && printf 'http://mcp-gateway:%s/sse' "${MCP_GATEWAY_PORT:-8811}"; }

# A self-hosted memory backend (its own container) is up.
memory_self_host() { case "${MEMORY_MODE:-stub}" in cognee|graphiti) return 0 ;; *) return 1 ;; esac; }
# The SSE/MCP endpoint of the ACTIVE memory backend — seeded into OpenHands + Open WebUI so the
# agents and chat share one memory. cognee/graphiti run as the `memory` service; mem0 is cloud;
# stub is the built-in python MCP (mcp:9000).
memory_sse_url() {
  case "${MEMORY_MODE:-stub}" in
    cognee|graphiti) printf 'http://memory:%s/sse' "${MEMORY_PORT:-8000}" ;;
    mem0)            [ -n "${MEM0_MCP_URL:-}" ] && printf '%s' "$MEM0_MCP_URL" ;;
    *)               mcp_enabled && printf '%s' "${MCP_SSE_URL:-http://mcp:9000/sse}" ;;
  esac
}
# Resolve PSAI_MEMORY. cognee/graphiti replace the keyword-only stub as the shared memory MCP.
resolve_memory_mode() {
  case "${MEMORY_MODE:-stub}" in
    cognee|graphiti)
      ENABLE_MCP="false"   # the real memory backend is the MCP now — don't also run the stub
      printf '%smemory: %s (self-host) — LLM model %s%s%s\n' "$C_DIM" "$MEMORY_MODE" \
        "$MEMORY_LLM_MODEL" "$([ -z "${MEMORY_LLM_KEY:-}" ] && printf ' (no LLM key yet — set PSAI_MEMORY_LLM_KEY)')" "$C_RESET" >&2 ;;
    mem0|none|stub) : ;;
    *) MEMORY_MODE="stub" ;;
  esac
  return 0
}

compose_openhands() {
  [ "$ENABLE_AGENTS" = "true" ] || return 0
  resolve_openhands_socket
  local sandbox_vols="$STACK_DIR/data/projects:/workspace:rw"
  local oh_docker_env="" oh_sock_vol="" oh_depends="" oh_model="" oh_mcp_vol=""
  if [ "$OPENHANDS_DOCKER_MODE" = "dind" ]; then
    # Share only the nested daemon's unix socket with OpenHands. The images keep
    # /var/run as a symlink to /run, so mount the shared volume on /run in both
    # containers; OpenHands still finds /var/run/docker.sock through the symlink.
    oh_docker_env="      - DOCKER_HOST=unix:///var/run/docker.sock"
    oh_sock_vol="      - dind-run:/run"
    oh_depends="    depends_on: [dind]"
  else
    oh_sock_vol="      - $DOCKER_SOCK:/var/run/docker.sock"
    # Mounting the host docker socket INTO the agent sandbox = host root for agent-authored
    # code. AGENTS_DOCKER is an explicit operator override, so allow it but warn hard on public.
    if [ "$AGENTS_DOCKER" = "true" ]; then
      sandbox_vols="$sandbox_vols,$DOCKER_SOCK:/var/run/docker.sock"
      [ "$DEPLOY_PROFILE" = "public" ] && printf '%s%s%s\n' "$C_YELLOW" "$(t agents_docker_public_warn)" "$C_RESET" >&2
    fi
  fi
  [ -n "${OPENHANDS_LLM_MODEL:-}" ] && oh_model="      - LLM_MODEL=$OPENHANDS_LLM_MODEL"
  openhands_mcp_config_active && oh_mcp_vol="      - ../openhands-config/config.toml:/app/config.toml:ro"
  cat >> "$(COMPOSE_FILE)" <<EOF

  openhands:
    image: $OPENHANDS_IMAGE
    container_name: ${SAFE_STACK_NAME}-openhands
    restart: unless-stopped
    pull_policy: missing
    # NB: OpenHands is an agent runtime that manages users + spawns sandbox
    # containers via the docker socket — it must keep its capabilities. Dropping
    # them (cap_drop ALL) strips CAP_DAC_OVERRIDE and root can't even stat its own
    # /app/entrypoint.sh ("permission denied" at runc init). The stateless services
    # (openwebui/searxng/caddy) stay locked down; this one cannot be.
$oh_depends
    extra_hosts:
      - "host.docker.internal:host-gateway"
    environment:
      - SANDBOX_RUNTIME_CONTAINER_IMAGE=${SAFE_STACK_NAME}_${OPENHANDS_SANDBOX_IMAGE_SUFFIX}
      - SANDBOX_VOLUMES=$sandbox_vols
      - SANDBOX_USER_ID=$(id -u)
      - WORKSPACE_MOUNT_PATH=$STACK_DIR/data/projects
      - WORKSPACE_BASE=/workspace
      - SANDBOX_ENABLE_GPU=false
      - SEARXNG_INSTANCE=http://searxng:8080
      - LOG_ALL_EVENTS=true
      - DO_NOT_TRACK=true
$oh_model
$oh_docker_env
$(stack_env_lines)
    volumes:
$oh_sock_vol
$oh_mcp_vol
      - ../data/openhands-state:/.openhands
      - ../data/projects:/workspace
EOF
  if [ "$OPENHANDS_DOCKER_MODE" = "dind" ]; then
    cat >> "$(COMPOSE_FILE)" <<EOF

  dind:
    image: $DIND_IMAGE
    container_name: ${SAFE_STACK_NAME}-dind
    privileged: true
    restart: unless-stopped
    command:
      - dockerd
      - --host=unix:///var/run/docker.sock
      - --storage-driver=overlay2
    environment:
      - DOCKER_TLS_CERTDIR=
$(stack_env_lines)
    volumes:
      - dind-data:/var/lib/docker
      - dind-run:/run
      - ../openhands-sandbox:/psai-openhands-sandbox:ro
      - $STACK_DIR/data/projects:$STACK_DIR/data/projects
EOF
  fi
}

# Assemble the whole compose file.
write_compose() {
  compose_header
  compose_caddy
  compose_openwebui
  compose_searxng
  compose_forgejo
  compose_openhands
  append_qdrant_service
  append_embed_service
  append_ingest_service
  append_mcp_service
  append_cognee_service
  append_graphiti_service
  append_ollama_service
  append_mcp_gateway_service
  append_mcpo_service
  append_litellm_service
  append_eval_service
  append_pentest_service
  append_proxy_service stack
  append_proxy_service web
  append_ollama_networks
  append_named_volumes
}

append_named_volumes() {
  { [ "${ENABLE_AGENTS:-false}" = "true" ] && [ "${OPENHANDS_DOCKER_MODE:-host}" = "dind" ]; } || return 0
  cat >> "$(COMPOSE_FILE)" <<'EOF'

volumes:
  dind-data:
  dind-run:
EOF
}

# ───────────────────────────── OpenHands sandbox ─────────────────────────────
write_openhands_sandbox_dockerfile() {
  cat > "$STACK_DIR/openhands-sandbox/Dockerfile" <<'EOF'
FROM nikolaik/python-nodejs:python3.12-nodejs22
SHELL ["/bin/bash", "-euo", "pipefail", "-c"]
RUN apt-get update && apt-get install -y --no-install-recommends \
    bash ca-certificates curl wget git git-lfs openssh-client jq \
    ripgrep fd-find unzip zip p7zip-full build-essential cmake make \
    pkg-config sqlite3 shellcheck docker.io docker-compose \
    && rm -rf /var/lib/apt/lists/*
RUN python -m pip install --no-cache-dir --upgrade \
    pip setuptools wheel virtualenv pipx uv \
    numpy pandas scipy pytest ruff black mypy bandit pip-audit \
    requests httpx[socks] pysocks beautifulsoup4 lxml playwright
RUN python -m playwright install --with-deps chromium || python -m playwright install chromium || true
RUN npm install -g --force pnpm typescript tsx eslint prettier yarn
WORKDIR /workspace
EOF
  compute_egress_endpoints
  if egress_web_enabled && web_via_proxy; then
    sandbox_proxy_env_lines >> "$STACK_DIR/openhands-sandbox/Dockerfile"
  fi
}

build_openhands_sandbox() {
  [ "$ENABLE_AGENTS" = "true" ] || return 0
  write_openhands_sandbox_dockerfile
  local img
  img="${SAFE_STACK_NAME}_${OPENHANDS_SANDBOX_IMAGE_SUFFIX}"
  if [ "${OPENHANDS_DOCKER_MODE:-host}" = "dind" ]; then
    docker image inspect "$img" >/dev/null 2>&1 \
      || build_openhands_sandbox_image "$img" \
      || true
    return 0
  fi
  build_openhands_sandbox_image "$img"
}

build_openhands_sandbox_image() {
  local img="$1" timeout rc
  timeout="${PSAI_SANDBOX_BUILD_TIMEOUT:-1800}"

  # The Dockerfile is intentionally plain. Prefer the legacy builder because Docker 29
  # BuildKit can leave this build stuck forever at "exporting layers" on small hosts.
  run_with_timeout "$timeout" env DOCKER_BUILDKIT=0 docker build -t "$img" "$STACK_DIR/openhands-sandbox"
  rc=$?
  if [ "$rc" -eq 0 ]; then
    return 0
  fi
  printf '%sopenhands sandbox: legacy docker build failed (rc=%s), retrying with BuildKit%s\n' "$C_YELLOW" "$rc" "$C_RESET" >&2
  run_with_timeout "$timeout" docker build -t "$img" "$STACK_DIR/openhands-sandbox"
}

wait_dind_ready() {
  [ "$ENABLE_AGENTS" = "true" ] || return 0
  [ "${OPENHANDS_DOCKER_MODE:-host}" = "dind" ] || return 0
  local i
  i=0
  while [ "$i" -lt 90 ]; do
    if compose exec -T dind docker info >/dev/null 2>&1; then return 0; fi
    sleep 2
    i=$((i + 1))
  done
  return 1
}

build_openhands_sandbox_dind() {
  [ "$ENABLE_AGENTS" = "true" ] || return 0
  [ "${OPENHANDS_DOCKER_MODE:-host}" = "dind" ] || return 0
  local img
  img="${SAFE_STACK_NAME}_${OPENHANDS_SANDBOX_IMAGE_SUFFIX}"
  write_openhands_sandbox_dockerfile
  wait_dind_ready || return 1
  if ! compose exec -T dind docker image inspect "$img" >/dev/null 2>&1; then
    if docker image inspect "$img" >/dev/null 2>&1; then
      docker save "$img" | compose exec -T dind docker load
    else
      compose exec -T dind docker build -t "$img" /psai-openhands-sandbox
    fi
  fi
  compose exec -T dind docker image inspect "$img" >/dev/null
  compose up -d --force-recreate --no-deps openhands
}

select_openhands_image() {
  [ "$ENABLE_AGENTS" = "true" ] || return 0
  if [ -n "${OPENHANDS_IMAGE_DEFAULT:-}" ]; then OPENHANDS_IMAGE="$OPENHANDS_IMAGE_DEFAULT"; return 0; fi
  if [ -n "${OPENHANDS_IMAGE:-}" ] && docker image inspect "$OPENHANDS_IMAGE" >/dev/null 2>&1; then return 0; fi
  local v="${OPENHANDS_VERSION:-1.8.0}" img
  for img in \
    "ghcr.io/all-hands-ai/openhands:$v" \
    "docker.all-hands.dev/all-hands-ai/openhands:$v" \
    "ghcr.io/openhands/openhands:$v"; do
    if docker pull "$img" >/dev/null 2>&1; then OPENHANDS_IMAGE="$img"; return 0; fi
  done
  printf '%s\n' "OpenHands $v not found; falling back to :latest (UNPINNED)." >&2
  for img in \
    "ghcr.io/all-hands-ai/openhands:latest" \
    "docker.all-hands.dev/all-hands-ai/openhands:latest"; do
    if docker pull "$img" >/dev/null 2>&1; then OPENHANDS_IMAGE="$img"; return 0; fi
  done
  echo 'OpenHands image pull failed.'; return 1
}

# ───────────────────────────── self-copy + PATH link ─────────────────────────────
copy_self_into_stack() {
  local bindir="$STACK_DIR/bin" dest old
  mkdir -p "$bindir"; dest="$bindir/$MGMT_NAME"
  old="$(legacy_mgmt_name)"
  [ "$old" = "$MGMT_NAME" ] || rm -f "$bindir/$old" 2>/dev/null || true
  # Don't clobber ourselves when invoked from the installed copy (rebuild/update):
  # rm+cp would delete the running script and the cp source would vanish.
  if ! [ "$SCRIPT_PATH" -ef "$dest" ] 2>/dev/null; then
    rm -f "$dest"; cp "$SCRIPT_PATH" "$dest"; chmod +x "$dest"
  fi
  link_command_on_path "$dest"
}

# Force Caddy to reload after a config change. A plain `compose up -d` leaves an
# unchanged caddy service running with its old in-memory config; force-recreate
# makes a fresh container that reads the regenerated Caddyfile.
reload_caddy() { compose up -d --force-recreate --no-deps caddy >/dev/null 2>&1 || true; }
legacy_mgmt_name() { printf '%s_%s' ai stack; }
remove_legacy_command_links() {
  local old d
  old="$(legacy_mgmt_name)"
  [ "$old" = "$MGMT_NAME" ] && return 0
  for d in /opt/homebrew/bin /usr/local/bin "$HOME/.local/bin" "$HOME/bin"; do
    [ -L "$d/$old" ] && rm -f "$d/$old" 2>/dev/null || true
  done
}
link_command_on_path() {
  local src="$1" d sudo_cmd=""
  remove_legacy_command_links
  for d in /opt/homebrew/bin /usr/local/bin "$HOME/.local/bin" "$HOME/bin"; do
    [ -d "$d" ] && [ -w "$d" ] && ln -sf "$src" "$d/$MGMT_NAME" 2>/dev/null && return 0
  done
  [ "$(id -u)" = "0" ] || sudo_cmd="sudo"
  if can_use_sudo && [ -d /usr/local/bin ]; then
    $sudo_cmd ln -sf "$src" "/usr/local/bin/$MGMT_NAME" 2>/dev/null && return 0
  fi
  mkdir -p "$HOME/.local/bin" 2>/dev/null && ln -sf "$src" "$HOME/.local/bin/$MGMT_NAME" 2>/dev/null && return 0
  return 0
}

run_with_timeout() {
  local seconds="$1" pid i rc
  shift
  case "$seconds" in ''|*[!0-9]*) seconds=0 ;; esac
  [ "$seconds" -le 0 ] && { "$@"; return $?; }
  "$@" &
  pid=$!
  i=0
  while kill -0 "$pid" 2>/dev/null; do
    if [ "$i" -ge "$seconds" ]; then
      kill_process_tree TERM "$pid"
      sleep 2
      kill_process_tree KILL "$pid"
      wait "$pid" 2>/dev/null || true
      return 124
    fi
    sleep 1
    i=$((i + 1))
  done
  rc=0; wait "$pid" || rc=$?
  return $rc
}

kill_process_tree() {
  local signal="$1" pid="$2" child
  if command -v pgrep >/dev/null 2>&1; then
    for child in $(pgrep -P "$pid" 2>/dev/null || true); do
      kill_process_tree "$signal" "$child"
    done
  fi
  kill "-$signal" "$pid" 2>/dev/null || true
}

compose_up_core() {
  local services core s rc
  if ! ingest_enabled; then
    compose up -d --build --remove-orphans
    rc=$?
    [ "$rc" -eq 0 ] && build_openhands_sandbox_dind
    return $rc
  fi
  services="$(compose config --services 2>/dev/null || true)"
  core=""
  for s in $services; do
    case "$s" in ingest-docling|ingest-tika) ;; *) core="$core $s" ;; esac
  done
  # shellcheck disable=SC2086
  if [ -n "$core" ]; then compose up -d --build --remove-orphans $core
  else compose up -d --build --remove-orphans; fi
  rc=$?
  [ "$rc" -eq 0 ] && build_openhands_sandbox_dind
  return $rc
}

compose_up_ingest() {
  ingest_enabled || return 0
  run_with_timeout "${PSAI_INGEST_START_TIMEOUT:-900}" compose up -d --no-deps ingest-docling ingest-tika
}

prune_disabled_services() {
  local rm=""
  [ "$ENABLE_OPENWEBUI" = "true" ] || rm="$rm openwebui"
  [ "$ENABLE_SEARCH"    = "true" ] || rm="$rm searxng"
  [ "$ENABLE_GIT"       = "true" ] || rm="$rm forgejo"
  [ "$ENABLE_AGENTS"    = "true" ] || rm="$rm openhands"
  [ "$ENABLE_QDRANT"    = "true" ] || rm="$rm qdrant"
  embed_enabled  || rm="$rm embed"
  ingest_enabled || rm="$rm ingest-docling ingest-tika"
  memory_self_host || rm="$rm memory falkordb"
  ollama_enabled || rm="$rm ollama ollama-raw ollama-pull"
  mcp_gateway_enabled || rm="$rm mcp-gateway"
  owui_bridge_enabled || rm="$rm mcpo"
  llm_gateway_enabled || rm="$rm litellm"
