# ───────────────────────────── orchestrator ─────────────────────────────
write_all_configs() {
  save_config
  # Bring up stack-vault first so generated secrets go into RAM, not a file on disk.
  # If the vault is required (strict) but can't unseal, fail rather than silently
  # writing plaintext secrets to disk.
  if vault_enabled; then
    vault_present || build_vault || true
    vault_start || { printf '%svault required but not unsealed — aborting%s\n' "$C_RED" "$C_RESET" >&2; return 1; }
  fi
  prepare_dirs_and_secrets
  compute_egress_endpoints
  configure_egress_secrets stack
  configure_egress_secrets web
  compute_egress_endpoints
  write_searxng_settings
  write_mcp_stub
  write_ollama_proxy_files
  write_litellm_config
  write_pentest_dockerfile
  write_openhands_mcp_config
  write_mcpo_config
  generate_local_ca_and_cert
  select_openhands_image
  save_config
  write_caddyfile
  render_runtime_env
  write_compose
  copy_self_into_stack
  reseal_blob
}

# Reversible runtime secrets the containers need (session keys), kept OUT of the
# compose file. Rendered from the vault and SHREDDED on stop, so when the stack is
# sealed no secret value persists on disk — only the encrypted vault blob does.
# Zero-disk: on Linux the file is backed by tmpfs (/dev/shm) with a symlink in compose/,
# so the plaintext session keys live in RAM, never on the SSD.
runtime_env_file()   { printf '%s/compose/.runtime.env' "$STACK_DIR"; }
# Private, per-uid tmpfs dir (0700) — NOT a predictable file directly under the world-
# writable /dev/shm. A local attacker can't plant a symlink inside a 0700 dir we own, and
# runtime_tmpfs_prepare refuses if the dir was pre-created by someone else.
runtime_tmpfs_dir()  { printf '/dev/shm/.psai-%s' "$(id -u)"; }
runtime_tmpfs_path() { printf '%s/%s.runtime.env' "$(runtime_tmpfs_dir)" "${SAFE_STACK_NAME:-psai}"; }
runtime_use_tmpfs() {
  [ "${RUNTIME_TMPFS:-true}" = "true" ] || return 1
  detect_os 2>/dev/null || true
  [ "${OS_TYPE:-}" = "linux" ] && [ -d /dev/shm ]
}
# Ensure the private tmpfs dir exists and is ours. Returns 1 (→ caller falls back to the
# on-disk 0600 file) if it exists but isn't a plain directory we own.
runtime_tmpfs_prepare() {
  local d; d="$(runtime_tmpfs_dir)"
  if [ -e "$d" ] || [ -L "$d" ]; then
    { [ -d "$d" ] && [ ! -L "$d" ] && [ -O "$d" ]; } || {
      printf '%sruntime: %s not a dir we own — using on-disk env%s\n' "$C_YELLOW" "$d" "$C_RESET" >&2; return 1; }
  else
    mkdir -m 700 "$d" 2>/dev/null || return 1
  fi
  chmod 700 "$d" 2>/dev/null || true
}
render_runtime_env() {
  mkdir -p "$STACK_DIR/compose"
  local target; target="$(runtime_env_file)"
  if runtime_use_tmpfs && runtime_tmpfs_prepare; then
    target="$(runtime_tmpfs_path)"
    rm -f "$target" 2>/dev/null || true            # drop any planted file/symlink (we own the 0700 parent)
    rm -f "$(runtime_env_file)" 2>/dev/null || true
    ln -sf "$target" "$(runtime_env_file)"         # compose env_file follows the symlink into RAM
  fi
  # Never write THROUGH an unexpected symlink at the real target (the on-disk path).
  if [ -L "$target" ]; then
    printf '%sruntime: refusing to write through symlink %s%s\n' "$C_YELLOW" "$target" "$C_RESET" >&2; return 1
  fi
  # NOTE: SEARXNG_SECRET is intentionally NOT emitted here — the searxng base image
  # never consumes it. SearXNG's session key is written straight into settings.yml by
  # write_searxng_settings (from the same vault secret). Only WEBUI_SECRET_KEY is a real
  # runtime env consumed by its container.
  ( umask 077; {
      printf '# generated from stack-vault — shredded on stop, do not commit\n'
      [ "$ENABLE_OPENWEBUI" = "true" ] && printf 'WEBUI_SECRET_KEY=%s\n' "$(secret_get webui_secret)"
      if ollama_enabled; then
        local ok; ok="$(secret_get ollama_api_key api_key_gen)"
        printf 'OLLAMA_API_KEY=%s\n' "$ok"
        [ "${LLM_GATEWAY:-false}" = "true" ] || printf 'OPENAI_API_KEY=%s\n' "$ok"
        case "${EMBED_URL:-}" in
          http://ollama:11434*) printf 'RAG_OPENAI_API_KEY=%s\nEMBED_API_KEY=%s\n' "$ok" "$ok" ;;
        esac
        case "${MEMORY_MODE:-stub}" in
          cognee) printf 'LLM_API_KEY=%s\n' "$ok" ;;
          graphiti) printf 'OPENAI_API_KEY=%s\n' "$ok" ;;
        esac
      elif [ -n "${EMBED_API_KEY:-}" ]; then
        printf 'RAG_OPENAI_API_KEY=%s\n' "$EMBED_API_KEY"
      fi
      # Pinned MCP gateway token — the gateway requires it, and OpenHands + mcpo present it.
      mcp_gateway_enabled && printf 'MCP_GATEWAY_AUTH_TOKEN=%s\n' "$(secret_get mcp_gateway_token api_key_gen)"
    } > "$target" )
  chmod 600 "$target" 2>/dev/null || true
}
shred_runtime_env() {
  local link f; link="$(runtime_env_file)"; f="$link"
  [ -L "$link" ] && f="$(readlink "$link" 2>/dev/null)"
  for x in "$f" "$link"; do
    [ -n "$x" ] || continue
    rm -P "$x" 2>/dev/null || shred -u "$x" 2>/dev/null || rm -f "$x" 2>/dev/null || true
  done
}
# ───────────────────────────── qdrant + mcp ─────────────────────────────
# Qdrant = optional SHARED vector memory for Open WebUI + OpenHands (+ agents over
# WG in multi-node). When enabled you can also bring up OUR OWN MCP server — a
# working stub today (health + SSE placeholder, wired to Qdrant), so the only thing
# left to add later is the actual tool logic in mcp/server.py.
mcp_enabled() { [ "${ENABLE_MCP:-false}" = "true" ] && [ "${ENABLE_QDRANT:-false}" = "true" ]; }
MCP_SSE_URL="http://mcp:9000/sse"
QDRANT_URL="http://qdrant:6333"

append_qdrant_service() {
  [ "$ENABLE_QDRANT" = "true" ] || return 0
  cat >> "$STACK_DIR/compose/docker-compose.yml" <<EOF

  qdrant:
    image: $QDRANT_IMAGE
    container_name: ${SAFE_STACK_NAME}-qdrant
    restart: unless-stopped
    security_opt: [ "no-new-privileges:true" ]
    environment:
      - QDRANT__TELEMETRY_DISABLED=true
    volumes:
      - ../data/qdrant:/qdrant/storage
    healthcheck:
      test: ["CMD-SHELL", "bash -c ':> /dev/tcp/127.0.0.1/6333' 2>/dev/null || exit 1"]
      interval: 15s
