  litellm:
    image: $LITELLM_IMAGE
    container_name: ${SAFE_STACK_NAME}-litellm
    restart: unless-stopped
    env_file:
      - .runtime.env
    command: ["--config", "/app/config.yaml", "--port", "4000"]
$proxy_env
