# True when the agents should get an MCP config.toml — a real memory MCP (cognee/graphiti
# or the stub) and/or the Docker MCP Gateway is active. Used BOTH to write the file and to
# mount it into OpenHands. Gating the mount on mcp_enabled alone silently dropped it for
# cognee/graphiti memory (where ENABLE_MCP=false), so the agents never got memory/tools.
openhands_mcp_config_active() {
  [ "${ENABLE_AGENTS:-false}" = "true" ] || return 1
  [ -n "$(memory_sse_url)" ] || [ -n "$(mcp_gateway_sse_url)" ]
}

# OpenHands reads [mcp].sse_servers from /app/config.toml.
write_openhands_mcp_config() {
  mkdir -p "$STACK_DIR/openhands-config"
  # Seed every active MCP source — the memory backend (stub mcp:9000 / cognee-graphiti
  # memory:8000 / mem0 cloud) AND the Docker MCP Gateway (tool servers) — so the agents get
  # shared memory + verified tools over the same config.
  local list="" u
  u="$(memory_sse_url)";      [ -n "$u" ] && list="\"$u\""
  # The gateway is token-gated: pass the pinned token as api_key so OpenHands sends
  # Authorization: Bearer … (a bare URL string would get 401).
  u="$(mcp_gateway_sse_url)"
  if [ -n "$u" ]; then
    [ -n "$list" ] && list="$list, "
    list="$list{url = \"$u\", api_key = \"$(secret_get mcp_gateway_token api_key_gen)\"}"
  fi
  if openhands_mcp_config_active && [ -n "$list" ]; then
    cat > "$STACK_DIR/openhands-config/config.toml" <<EOF
[mcp]
sse_servers = [$list]
EOF
  else
    rm -f "$STACK_DIR/openhands-config/config.toml" 2>/dev/null || true
  fi
}
# ─────────────────────────── multi-node (master + isolated agents) ───────────────────────────
# master_node_0 (WG .1) is the control plane: centralized management + state
# collection over a WireGuard-only SSH tunnel. Each agent_worker_<N> (WG .{2+N}) runs
# an OpenHands-only stack with its own SearXNG + proxy-web egress, reachable only
# inside WireGuard; web access is opt-in. The master pulls the agent's data home and
# can share its Qdrant (vector memory) with the agents over WG.
master_wg_ip()  { printf '%s.1' "$REMOTE_WG_NET"; }
agent_wg_ip()   { printf '%s.%s' "$REMOTE_WG_NET" "$(( 2 + ${AGENT_INDEX:-0} ))"; }
kms_wg_ip()     { printf '%s' "${PSAI_KMS_WG:-${REMOTE_WG_NET}.254}"; }   # external KMS node
master_label()  { printf 'master_node_0'; }
agent_label()   { printf 'agent_worker_%s' "${1:-${AGENT_INDEX:-0}}"; }

RA_KEY="" RA_PASSFILE="" RA_MODE="install" RA_OPEN_MIN=""

# Persist SSH host keys (trust-on-first-use). With UserKnownHostsFile=/dev/null,
# `accept-new` had nothing to compare against on the next connect, so every reconnect
# blindly trusted whatever key answered — no protection if a key changed under us. A
# per-stack known_hosts pins the host key on first contact and verifies it after. The
# WG paths used StrictHostKeyChecking=no (silently accept anything) — also raised to
# accept-new so a changed agent key is refused.
ra_known_hosts() {
  local d="${STACK_DIR:-$HOME/.psai}/secrets"
  mkdir -p "$d" 2>/dev/null || true
  printf '%s/known_hosts' "$d"
}
ra_ssh() {
  local h="$RA_USER@$RA_HOST" kh; kh="$(ra_known_hosts)"
  if [ -n "$RA_KEY" ]; then ssh -i "$RA_KEY" -p "$RA_PORT" -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$h" "$@"
  else sshpass -f "$RA_PASSFILE" ssh -p "$RA_PORT" -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$h" "$@"; fi
}
ra_scp() {
  local kh; kh="$(ra_known_hosts)"
  if [ -n "$RA_KEY" ]; then scp -O -i "$RA_KEY" -P "$RA_PORT" -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$1" "$RA_USER@$RA_HOST:$2"
  else sshpass -f "$RA_PASSFILE" scp -O -P "$RA_PORT" -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$1" "$RA_USER@$RA_HOST:$2"; fi
}
ra_wg_ssh() {
  local h kh; h="$RA_USER@$(agent_wg_ip)"; kh="$(ra_known_hosts)"
  if [ -n "$RA_KEY" ]; then ssh -i "$RA_KEY" -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$h" "$@"
  else sshpass -f "$RA_PASSFILE" ssh -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$kh" "$h" "$@"; fi
}

ensure_sshpass() {
  command_exists sshpass && return 0
  [ -n "$RA_KEY" ] && return 0
  detect_os
  case "$OS_TYPE" in
    macos) brew install hudochenkov/sshpass/sshpass >/dev/null 2>&1 || brew install sshpass >/dev/null 2>&1 ;;
    linux) local S=""; [ "$(id -u)" = 0 ] || S="sudo"; $S apt-get install -y -qq sshpass >/dev/null 2>&1 ;;
  esac
  command_exists sshpass
}

ra_parse_args() {
  while [ $# -gt 0 ]; do
    case "$1" in
      --host) RA_HOST="$2"; shift 2 ;;
      --port) RA_PORT="$2"; shift 2 ;;
      --user) RA_USER="$2"; shift 2 ;;
      --key)  RA_KEY="${2/#\~/$HOME}"; shift 2 ;;
      --open-ssh) RA_MODE="open-ssh"; RA_OPEN_MIN="${2:-}"; case "$RA_OPEN_MIN" in ''|*[!0-9]*) RA_OPEN_MIN=""; shift ;; *) shift 2 ;; esac ;;
      --domain) AGENT_DOMAIN="$2"; shift 2 ;;
      --email)  AGENT_ACME_EMAIL="$2"; shift 2 ;;
      *) shift ;;
    esac
  done
  [ -n "$RA_HOST" ] || RA_HOST="$(ask "$(t ra_host)" '')"
  [ -n "$RA_HOST" ] || return 1
  RA_PORT="${RA_PORT:-22}"; RA_USER="${RA_USER:-root}"
  if [ -z "$RA_KEY" ]; then
    RA_PASSFILE="$(mktemp)"; chmod 600 "$RA_PASSFILE"
    printf '%s: ' "$(t ra_pass)"; stty -echo 2>/dev/null; IFS= read -r _p || true; stty echo 2>/dev/null; printf '\n'
    printf '%s' "$_p" > "$RA_PASSFILE"; unset _p
  fi
  return 0
}

# "Server matches and is ready" — check the agent host can run the stack.
ra_check_requirements() {
  printf '%s...\n' "$(t ra_check)"
  local rep; rep="$(ra_ssh 'set -e
  os=$(uname -s)
  mem=$(awk "/MemTotal/{print int(\$2/1024)}" /proc/meminfo 2>/dev/null || echo 0)
  disk=$(df -m / | awk "NR==2{print \$4}")
  apt=$(command -v apt-get >/dev/null 2>&1 && echo yes || echo no)
  dock=$(command -v docker >/dev/null 2>&1 && echo yes || echo no)
  echo "$os|$mem|$disk|$apt|$dock"' 2>/dev/null)" || return 1
  local os mem disk apt dock; IFS='|' read -r os mem disk apt dock <<EOF
$rep
EOF
  [ "$os" = "Linux" ] || return 1
  [ "${mem:-0}" -ge 1500 ] 2>/dev/null || return 1
  [ "${disk:-0}" -ge 8000 ] 2>/dev/null || return 1
  [ "$apt" = "yes" ] || [ "$dock" = "yes" ] || return 1
  printf '  %s%s%s  (RAM %sMB · disk %sMB)\n' "$C_GREEN" "$(t ra_check_ok)" "$C_RESET" "$mem" "$disk"
  return 0
}

remote_agents() {
  load_config || { echo "$(t no_env)"; return 1; }
  ensure_path_brew
  ra_parse_args "$@" || { echo "$(t ra_host)"; return 1; }
  ensure_sshpass || { echo "$(t ra_sshpass_need)"; rm -f "$RA_PASSFILE"; return 1; }
  if [ "$RA_MODE" = "open-ssh" ]; then ra_open_ssh; rm -f "$RA_PASSFILE"; return $?; fi

  printf '%s...\n' "$(t ra_connect)"
  ra_ssh 'echo ok' >/dev/null 2>&1 || { echo "$(t ra_ssh_fail)"; rm -f "$RA_PASSFILE"; return 1; }
  ra_check_requirements || { echo "$(t ra_check_fail)"; rm -f "$RA_PASSFILE"; return 1; }
  ra_collect_options

  # Install Docker on the agent from Docker's official apt repo with a pinned signed-by GPG
  # key (apt verifies packages) — not `curl get.docker.com | sh` (arbitrary unverified code).
  ra_ssh 'set -e
if ! command -v docker >/dev/null 2>&1; then
  export DEBIAN_FRONTEND=noninteractive
  apt-get update -qq
  apt-get install -y -qq ca-certificates curl
  install -m 0755 -d /etc/apt/keyrings
  . /etc/os-release
  curl -fsSL "https://download.docker.com/linux/$ID/gpg" -o /etc/apt/keyrings/docker.asc
  chmod a+r /etc/apt/keyrings/docker.asc
  echo "deb [arch=$(dpkg --print-architecture) signed-by=/etc/apt/keyrings/docker.asc] https://download.docker.com/linux/$ID $VERSION_CODENAME stable" > /etc/apt/sources.list.d/docker.list
  apt-get update -qq
  apt-get install -y -qq docker-ce docker-ce-cli containerd.io docker-buildx-plugin docker-compose-plugin
fi
systemctl enable --now docker 2>/dev/null || true
docker --version' >/dev/null 2>&1 || { echo "$(t ra_docker_fail)"; rm -f "$RA_PASSFILE"; return 1; }

  # KMS: when the master runs the vault, the agent runs one too — unsealed by the
  # KMS over WG. Generate the agent's key (K, the vault passphrase) + auth token (T)
  # in the keys store (master vault, or the external KMS node) BEFORE installing, so
  # the agent's vault.enc is encrypted with K; the key never lands on the agent's disk.
  local agent_vault="false" K="" T=""
  if vault_enabled; then
    agent_vault="true"
    if [ -n "${KMS_HOST:-}" ]; then
      K="$(random_secret)"; printf '%s' "$K" | kms_store_put "agent_unseal_${AGENT_INDEX}"
      T="$(random_secret)"; printf '%s' "$T" | kms_store_put "kms_token_${AGENT_INDEX}"
    else
      K="$(secret_get agent_unseal_${AGENT_INDEX} random_secret)"
      T="$(secret_get kms_token_${AGENT_INDEX} random_secret)"
    fi
    ra_ship_vault_src
  fi

  printf '%s...\n' "$(t ra_install)"
  ra_scp "$SCRIPT_PATH" "/root/${MGMT_NAME}.sh"
  local oh_git="false"; [ "$ISOLATE_GIT" = "true" ] && oh_git="true"
  # The agent is a lean OpenHands node — explicitly turn the new advanced components OFF so the
  # everything-on `install --defaults` doesn't bloat it (each PSAI_* override wins in apply_defaults).
  local renv="PSAI_LANG=${UI_LANG:-en} PSAI_NODE_MODE=single PSAI_OPENWEBUI=false PSAI_AGENTS=true PSAI_SEARCH=true \
PSAI_GIT=$oh_git PSAI_QDRANT=false PSAI_EGRESS_WEB='$AGENT_EGRESS' PSAI_WEB_VIA_PROXY=true \
PSAI_RAG=off PSAI_MEMORY=none PSAI_LLM=none PSAI_MCP_GATEWAY=false PSAI_LLM_GATEWAY=false PSAI_EVAL=false PSAI_DUAL=false"
  if [ "$agent_vault" = "true" ]; then
    # The vault passphrase K is passed on STDIN, not in the command line: PSAI_VAULT_PASS=$(cat)
    # is evaluated on the agent, so K never appears in the agent's argv / `ps` / environ
    # listing. (Earlier this inlined PSAI_VAULT_PASS='$K', exposing it to any local user.)
    renv="$renv PSAI_PROFILE=strict PSAI_VAULT_PASS=\$(cat) PSAI_VAULT_SRC=\$HOME/vault-src"
  else
    renv="$renv PSAI_PROFILE=default"
  fi
  if [ "$AGENT_WEB" = "true" ] && [ -n "$AGENT_DOMAIN" ]; then
    renv="$renv PSAI_DEPLOY=public PSAI_PUBLIC_DOMAIN='$AGENT_DOMAIN' PSAI_ACME_EMAIL='$AGENT_ACME_EMAIL'"
  else
    renv="$renv PSAI_DEPLOY=local"
  fi
  if [ "$agent_vault" = "true" ]; then
    printf '%s' "$K" | ra_ssh "$renv bash /root/${MGMT_NAME}.sh install --defaults" || { echo "$(t ra_agent_fail)"; rm -f "$RA_PASSFILE"; return 1; }
  else
    ra_ssh "$renv bash /root/${MGMT_NAME}.sh install --defaults" </dev/null || { echo "$(t ra_agent_fail)"; rm -f "$RA_PASSFILE"; return 1; }
  fi

  setup_wg_tunnel || { echo "$(t ra_wg_fail)"; rm -f "$RA_PASSFILE"; return 1; }
  ra_install_mgmt_key
  [ "$SHARED_MEMORY" = "true" ] && start_qdrant_wg_bridge
  [ "$agent_vault" = "true" ] && ra_setup_kms "$T"
  ra_harden_vps2
  ra_install_failback
  ra_lockdown_public_ssh

  ISOLATE_AGENTS="true"; AGENT_PUBLIC_IP="$RA_HOST"; AGENT_WG_IP="$(agent_wg_ip)"
  [ "$ISOLATE_GIT" = "true" ] && ENABLE_GIT="false"
  ra_register_agent
  save_config 2>/dev/null || true
  printf '%s%s%s\n' "$C_GREEN" "$(t ra_done)" "$C_RESET"
  ra_print_endpoints
  rm -f "$RA_PASSFILE"
}

ra_collect_options() {
  [ -n "$AGENT_EGRESS" ] || AGENT_EGRESS="tor"
  if [ "$AGENT_WEB" = "true" ]; then
    [ -n "$AGENT_DOMAIN" ] || AGENT_DOMAIN="$(ask "$(t q_agent_domain)" '')"
    if [ -n "$AGENT_DOMAIN" ]; then
      AGENT_DOMAIN="$(normalize_zone "$AGENT_DOMAIN")"
      printf '  %s%s%s\n    %s%s.%s  A  →  %s%s\n' "$C_DIM" "$(t pub_arecord)" "$C_RESET" "$C_DIM" "$AGENT_SUB" "$AGENT_DOMAIN" "$RA_HOST" "$C_RESET"
      [ -n "$AGENT_ACME_EMAIL" ] || AGENT_ACME_EMAIL="$(ask "$(t pub_email)" "$ACME_EMAIL")"
    else AGENT_WEB="false"; fi
  fi
}

ra_register_agent() {
  local entry kept; entry="${AGENT_INDEX}:${RA_HOST}:$(agent_wg_ip):${AGENT_DOMAIN:-}"
  # shellcheck disable=SC2086
  kept="$(printf '%s\n' $AGENT_SERVERS | grep -v "^${AGENT_INDEX}:" 2>/dev/null | tr '\n' ' ')"
  AGENT_SERVERS="$(printf '%s %s' "$kept" "$entry" | tr -s ' ' | sed 's/^ //;s/ $//')"
}

ra_print_endpoints() {
  local awg; awg="$(agent_wg_ip)"
  printf '  %s %s  ⇄  WireGuard  ⇄  %s %s\n' "$(master_label)" "$(master_wg_ip)" "$(agent_label)" "$awg"
  printf '  public: %s%s%s   wg: %s%s%s (ssh %s@%s)\n' "$C_B" "$RA_HOST" "$C_RESET" "$C_B" "$awg" "$C_RESET" "$RA_USER" "$awg"
  if [ "$AGENT_WEB" = "true" ] && [ -n "$AGENT_DOMAIN" ]; then printf '  agents: https://%s.%s\n' "$AGENT_SUB" "$AGENT_DOMAIN"
  else printf '  agents: %shttp://%s:3000%s (WG only)\n' "$C_B" "$awg" "$C_RESET"; fi
}

setup_wg_tunnel() {
  printf '%s...\n' "WireGuard"
  command_exists wg || { detect_os; case "$OS_TYPE" in macos) brew install wireguard-tools >/dev/null 2>&1 ;; linux) { [ "$(id -u)" = 0 ] || S=sudo; }; ${S:-} apt-get install -y -qq wireguard-tools >/dev/null 2>&1 ;; esac; }
  command_exists wg || return 1
  ra_ssh 'command -v wg >/dev/null 2>&1 || (apt-get update -qq && DEBIAN_FRONTEND=noninteractive apt-get install -y -qq wireguard wireguard-tools) >/dev/null 2>&1; command -v wg >/dev/null 2>&1' || return 1
  local wgdir="$STACK_DIR/secrets/wg"; mkdir -p "$wgdir"; chmod 700 "$wgdir"
  local m_priv m_pub a_priv a_pub m_ep mwg awg
  mwg="$(master_wg_ip)"; awg="$(agent_wg_ip)"
  m_priv="$(cat "$wgdir/master.key" 2>/dev/null)"; [ -n "$m_priv" ] || { m_priv="$(wg genkey)"; ( umask 077; printf '%s' "$m_priv" > "$wgdir/master.key" ); }
  m_pub="$(printf '%s' "$m_priv" | wg pubkey)"
  a_priv="$(ra_ssh 'cat /etc/wireguard/agent.key 2>/dev/null || { k=$(wg genkey); umask 077; printf %s "$k" > /etc/wireguard/agent.key; printf %s "$k"; }')"
  a_pub="$(printf '%s' "$a_priv" | wg pubkey)"
  m_ep="$(ask "$(t q_master_ep)" "$(host_ip)")"
  ra_ssh "mkdir -p /etc/wireguard; cat > /etc/wireguard/wg0.conf <<EOF
[Interface]
Address = ${awg}/24
PrivateKey = ${a_priv}
[Peer]
PublicKey = ${m_pub}
Endpoint = ${m_ep}:${REMOTE_WG_PORT}
AllowedIPs = ${REMOTE_WG_NET}.0/24
PersistentKeepalive = 25
EOF
chmod 600 /etc/wireguard/wg0.conf; wg-quick down wg0 2>/dev/null; wg-quick up wg0 2>/dev/null; systemctl enable wg-quick@wg0 2>/dev/null || true" || return 1
  cat > "$wgdir/wg0.conf" <<EOF
[Interface]
Address = ${mwg}/24
PrivateKey = ${m_priv}
ListenPort = ${REMOTE_WG_PORT}
[Peer]
PublicKey = ${a_pub}
AllowedIPs = ${awg}/32
PersistentKeepalive = 25
EOF
  chmod 600 "$wgdir/wg0.conf"
  detect_os
  if [ "$OS_TYPE" = "linux" ]; then
    local S=""; [ "$(id -u)" = 0 ] || S=sudo
    $S cp "$wgdir/wg0.conf" /etc/wireguard/wg0.conf
    $S wg-quick down wg0 2>/dev/null; $S wg-quick up wg0 2>/dev/null; $S systemctl enable wg-quick@wg0 2>/dev/null || true
  else
    printf '  %smacOS: bring the master tunnel up via WireGuard.app / wg-quick%s\n' "$C_YELLOW" "$C_RESET"
  fi
}

# Peer an external KMS node into the fleet WireGuard at .254 (hub-and-spoke: master is
# the hub). The master gets a route to the KMS (to populate the keys store); IP
# forwarding on the master lets agents (spokes) reach the KMS (spoke) through it. The
# KMS peer is APPENDED to the master conf so it doesn't clobber agent peers.
# FIRST CUT — needs a 3-host (master + agent + KMS) live test.
setup_wg_kms_tunnel() {
  printf '%s (KMS node)...\n' "WireGuard"
  command_exists wg || { detect_os; case "$OS_TYPE" in macos) brew install wireguard-tools >/dev/null 2>&1 ;; linux) { [ "$(id -u)" = 0 ] || S=sudo; }; ${S:-} apt-get install -y -qq wireguard-tools >/dev/null 2>&1 ;; esac; }
  command_exists wg || return 1
  ra_ssh 'command -v wg >/dev/null 2>&1 || (apt-get update -qq && DEBIAN_FRONTEND=noninteractive apt-get install -y -qq wireguard wireguard-tools) >/dev/null 2>&1; command -v wg >/dev/null 2>&1' || return 1
  local wgdir="$STACK_DIR/secrets/wg"; mkdir -p "$wgdir"; chmod 700 "$wgdir"
  local m_priv m_pub k_priv k_pub m_ep mwg kwg
  mwg="$(master_wg_ip)"; kwg="$(kms_wg_ip)"
  m_priv="$(cat "$wgdir/master.key" 2>/dev/null)"; [ -n "$m_priv" ] || { m_priv="$(wg genkey)"; ( umask 077; printf '%s' "$m_priv" > "$wgdir/master.key" ); }
  m_pub="$(printf '%s' "$m_priv" | wg pubkey)"
  k_priv="$(ra_ssh 'cat /etc/wireguard/kms.key 2>/dev/null || { k=$(wg genkey); umask 077; printf %s "$k" > /etc/wireguard/kms.key; printf %s "$k"; }')"
  k_pub="$(printf '%s' "$k_priv" | wg pubkey)"
  m_ep="$(ask "$(t q_master_ep_kms)" "$(host_ip)")"
  # KMS node tunnel: master as peer, full subnet so it can reach (and be reached by) agents.
  ra_ssh "mkdir -p /etc/wireguard; cat > /etc/wireguard/wg0.conf <<EOF
[Interface]
Address = ${kwg}/24
PrivateKey = ${k_priv}
[Peer]
PublicKey = ${m_pub}
Endpoint = ${m_ep}:${REMOTE_WG_PORT}
AllowedIPs = ${REMOTE_WG_NET}.0/24
PersistentKeepalive = 25
EOF
chmod 600 /etc/wireguard/wg0.conf; wg-quick down wg0 2>/dev/null; wg-quick up wg0 2>/dev/null; systemctl enable wg-quick@wg0 2>/dev/null || true" || return 1
  # Append the KMS as a peer to the master conf (idempotent; keeps existing agent peers).
  if ! grep -q "$k_pub" "$wgdir/wg0.conf" 2>/dev/null; then
    cat >> "$wgdir/wg0.conf" <<EOF
[Peer]
PublicKey = ${k_pub}
AllowedIPs = ${kwg}/32
PersistentKeepalive = 25
EOF
  fi
  detect_os
  if [ "$OS_TYPE" = "linux" ]; then
    local S=""; [ "$(id -u)" = 0 ] || S=sudo
    $S sysctl -w net.ipv4.ip_forward=1 >/dev/null 2>&1 || true   # hub forwarding for spoke<->spoke
    $S cp "$wgdir/wg0.conf" /etc/wireguard/wg0.conf
    $S wg-quick down wg0 2>/dev/null; $S wg-quick up wg0 2>/dev/null || true
  else
    printf '  %smacOS master: re-apply wg0 to add the KMS peer%s\n' "$C_YELLOW" "$C_RESET"
  fi
}

ra_install_mgmt_key() {
  local kf="$STACK_DIR/secrets/wg/mgmt.key"
  mkdir -p "$STACK_DIR/secrets/wg"; chmod 700 "$STACK_DIR/secrets/wg"
  [ -f "$kf" ] || ssh-keygen -t ed25519 -N '' -f "$kf" -C "psai-mgmt-${SAFE_STACK_NAME}" >/dev/null 2>&1 || return 0
  local pub; pub="$(cat "$kf.pub" 2>/dev/null)"; [ -n "$pub" ] || return 0
  ra_ssh "mkdir -p ~/.ssh; chmod 700 ~/.ssh; grep -qF '$pub' ~/.ssh/authorized_keys 2>/dev/null || printf '%s\n' '$pub' >> ~/.ssh/authorized_keys; chmod 600 ~/.ssh/authorized_keys" >/dev/null 2>&1 || true
}

# Publish the master's Qdrant onto the WG address so agents share one vector store.
start_qdrant_wg_bridge() {
  [ "$ENABLE_QDRANT" = "true" ] || return 0
  docker rm -f "${SAFE_STACK_NAME}-wg-bridge" >/dev/null 2>&1 || true
  local net; net="$(docker network ls --format '{{.Name}}' | grep -E "${SAFE_STACK_NAME}.*default" | head -1)"
  [ -n "$net" ] || return 0
  docker run -d --name "${SAFE_STACK_NAME}-wg-bridge" --restart unless-stopped \
    --network "$net" "$ALPINE_IMAGE" sh -c \
    'apk add --no-cache socat >/dev/null 2>&1; socat TCP-LISTEN:6333,fork,reuseaddr TCP:qdrant:6333' >/dev/null 2>&1 || true
}

# Ship the stack-vault source to the agent so it can build its own (per-arch) binary.
# Small (Cargo.toml + main.rs); a prebuilt per-arch binary in the release is the
# production path (see PLAN).
ra_ship_vault_src() {
  local src=""
  for d in "$SCRIPT_DIR/vault" "$SCRIPT_DIR/../vault"; do [ -f "$d/Cargo.toml" ] && { src="$d"; break; }; done
  [ -n "$src" ] || return 0
  # Prefer a matching prebuilt for the agent's arch — ship it straight to bin/ so the
  # agent needs no Rust toolchain (build_vault then sees it present and skips building).
  local aarch tag pre; aarch="$(ra_ssh 'uname -m' 2>/dev/null | tr -d '[:space:]')"
  case "$aarch" in x86_64|amd64) tag=x86_64 ;; aarch64|arm64) tag=aarch64 ;; *) tag="$aarch" ;; esac
  pre="$src/dist/stack-vault-linux-$tag"
  if [ -x "$pre" ]; then
    ra_ssh 'mkdir -p ~/psai/bin' >/dev/null 2>&1 || true
    ra_scp "$pre" 'psai/bin/stack-vault'
    ra_ssh 'chmod +x ~/psai/bin/stack-vault' >/dev/null 2>&1 || true
    printf '  %sshipped prebuilt stack-vault (linux-%s)%s\n' "$C_DIM" "$tag" "$C_RESET"
  fi
  # Always ship source too as a fallback (used only if no prebuilt was placed).
  ra_ssh 'mkdir -p ~/vault-src/src' >/dev/null 2>&1 || true
  # scp remote paths are relative to the remote home, so no '~/' needed.
  ra_scp "$src/Cargo.toml" 'vault-src/Cargo.toml'
  ra_scp "$src/src/main.rs" 'vault-src/src/main.rs'
}

# Configure the agent to unseal from the KMS (master, or an external KMS node when
# PSAI_KMS_HOST is set): write secrets/kms.conf (token only — the key never lands here),
# register the agent's hardware fingerprint in the keys store (so a disk clone on other
# hardware is refused), start the local KMS unless an external node owns it, open the
# KMS port to the WG subnet. <T> is the per-agent auth token (kms_token_<N>).
ra_setup_kms() {
  local T="$1" addr port adir fp; addr="$(vault_kms_addr)"; port="$(vault_kms_port)"; adir="psai"
  vault_kms_start
  ra_ssh "mkdir -p ~/$adir/secrets; umask 077; cat > ~/$adir/secrets/kms.conf <<EOF
KMS_ADDR=${addr}
KMS_ID=${AGENT_INDEX}
KMS_TOKEN=${T}
EOF
chmod 600 ~/$adir/secrets/kms.conf" >/dev/null 2>&1 || true
  # Identity binding: read the agent's hardware fingerprint (same context the agent's
  # vault runs in) and store it in the keys store as agent_fp_<N>. Strong binding (DMI
  # product_uuid) needs the agent stack to run as root; otherwise it binds to machine-id.
  # home-relative path (no '~/'): a command containing '/' runs from the remote $HOME.
  fp="$(ra_ssh "$adir/bin/stack-vault fingerprint" 2>/dev/null | tr -d '[:space:]')"
  if [ -n "$fp" ]; then
    printf '%s' "$fp" | kms_store_put "agent_fp_${AGENT_INDEX}"
    printf '  %sHW fingerprint registered for %s%s\n' "$C_DIM" "$(agent_label)" "$C_RESET"
  else
    printf '  %sno HW fingerprint from %s — KMS unseal will not be hardware-bound%s\n' "$C_YELLOW" "$(agent_label)" "$C_RESET"
  fi
  detect_os
  if [ "$OS_TYPE" = "linux" ]; then local S=""; [ "$(id -u)" = 0 ] || S=sudo; $S ufw allow from "${REMOTE_WG_NET}.0/24" to any port "$port" proto tcp >/dev/null 2>&1 || true; fi
  printf '  %sKMS unseal configured for %s%s\n' "$C_DIM" "$(agent_label)" "$C_RESET"
}

# Rotate an agent's unseal key from the master. Generates a fresh K, tells the agent's
# running vault to RESEAL its blob under K (no secret values change), then adopts K in
# the master keys store (agent_unseal_<idx>) so the next KMS unseal uses it. Reachable
# over WireGuard; the agent vault must be unsealed (running) for the reseal. KMS-side
# rotation (rekey from a standalone KMS node) is planned — see TODO.md.
ra_rekey() {
  local idx=0 rest=""
  while [ $# -gt 0 ]; do
    case "$1" in --idx) idx="$2"; shift 2 ;; *) rest="$rest $1"; shift ;; esac
  done
  AGENT_INDEX="$idx"
  load_config 2>/dev/null || true
  # Default target = the agent's WG IP from the registry, unless --host was given.
  case " $rest " in
    *" --host "*) : ;;
    *) local wg; wg="$(printf '%s\n' $AGENT_SERVERS | awk -F: -v i="$idx" '$1==i{print $3}' | head -1)"
       [ -n "$wg" ] && RA_HOST="$wg" ;;
  esac
  ensure_sshpass || true
  # shellcheck disable=SC2086
  ra_parse_args $rest || return 1
  vault_enabled || { printf '%svault disabled — nothing to rotate%s\n' "$C_YELLOW" "$C_RESET" >&2; return 1; }
  vault_up || vault_start || { printf '%smaster vault not available%s\n' "$C_RED" "$C_RESET" >&2; return 1; }
  printf '%sRotating unseal key for %s%s\n' "$C_B" "$(agent_label "$idx")" "$C_RESET"
  local newk; newk="$(random_secret)"
  # 1) reseal the agent's blob under the new key (its vault adopts K in RAM too). The new
  #    key goes on STDIN (reseal reads it) — never in the command line, so it can't be read
  #    from the agent's `ps`/environ.
  if printf '%s' "$newk" | ra_ssh "psai/bin/stack-vault reseal --socket psai/vault.sock" >/dev/null 2>&1; then
    # 2) adopt K in the keys store (master vault or external KMS node) so the next
    #    KMS unseal of this agent uses it.
    printf '%s' "$newk" | kms_store_put "agent_unseal_${idx}"
    printf '  %srotated: agent blob re-sealed, agent_unseal_%s updated%s\n' "$C_GREEN" "$idx" "$C_RESET"
  else
    printf '  %sFAILED: agent reseal did not run (is its vault unsealed / reachable?) — master key unchanged%s\n' "$C_RED" "$C_RESET" >&2
    return 1
  fi
}

# State collection: pull a health/log snapshot from every registered node into the
# master's data/state/<idx>/ dir over WireGuard. Safe to schedule (cron). Complements
# the data pull — this is the "centralized state collection" the master is meant to do.
# Uses RA_KEY when set (ideal for cron); otherwise prompts once for a shared password.
ra_collect_state() {
  load_config 2>/dev/null || true
  [ -n "$AGENT_SERVERS" ] || { printf '%sno agents registered%s\n' "$C_DIM" "$C_RESET"; return 0; }
  if [ -z "${RA_KEY:-}" ] && [ -z "${RA_PASSFILE:-}" ]; then
    ensure_sshpass || true
    RA_PASSFILE="$(mktemp)"; chmod 600 "$RA_PASSFILE"
    printf '%s: ' "$(t ra_pass)"; stty -echo 2>/dev/null; IFS= read -r _p || true; stty echo 2>/dev/null; printf '\n'
    printf '%s' "$_p" > "$RA_PASSFILE"; unset _p
  fi
  RA_USER="${RA_USER:-root}"
  local base="$STACK_DIR/data/state" ts; base="${base}"; ts="$(date +%Y%m%d-%H%M%S)"; mkdir -p "$base"
  local e idx ip wg dom dir snap
  for e in $AGENT_SERVERS; do
    IFS=':' read -r idx ip wg dom <<EOF
$e
EOF
    [ -n "$wg" ] || continue
    AGENT_INDEX="$idx"                       # ra_wg_ssh targets agent_wg_ip from this
    dir="$base/$idx"; mkdir -p "$dir"; snap="$dir/$ts.txt"
    {
      printf '# agent_worker_%s  wg=%s  collected=%s\n\n## docker ps\n' "$idx" "$wg" "$ts"
      ra_wg_ssh 'docker ps --format "{{.Names}}\t{{.Status}}\t{{.Image}}" 2>/dev/null' 2>/dev/null
      printf '\n## host\n'
      ra_wg_ssh 'uptime; echo; df -h / | tail -1; free -m 2>/dev/null | sed -n 1,2p' 2>/dev/null
      printf '\n## recent logs (tail 40 / container)\n'
      ra_wg_ssh 'for c in $(docker ps --format "{{.Names}}" 2>/dev/null); do echo "=== $c ==="; docker logs --tail 40 "$c" 2>&1 | tail -40; done' 2>/dev/null
    } > "$snap" 2>/dev/null
    if [ -s "$snap" ]; then
      ln -sf "$ts.txt" "$dir/latest.txt" 2>/dev/null
      # Keep the 10 newest snapshots. Names are <ts>.txt so the glob expands oldest-first;
      # delete from the front until 10 remain (skip the latest.txt symlink).
      local keep=10 count=0 f
      for f in "$dir"/*.txt; do { [ -f "$f" ] && [ ! -L "$f" ]; } && count=$((count + 1)); done
      for f in "$dir"/*.txt; do
        [ "$count" -le "$keep" ] && break
        { [ -f "$f" ] && [ ! -L "$f" ]; } || continue
        rm -f "$f"; count=$((count - 1))
      done
      printf '  %sagent_worker_%s%s → %s%s%s\n' "$C_B" "$idx" "$C_RESET" "$C_DIM" "$snap" "$C_RESET"
    else
      rm -f "$snap"; printf '  %sagent_worker_%s unreachable%s\n' "$C_YELLOW" "$idx" "$C_RESET"
    fi
  done
}

# Provision an external KMS node: a minimal host that runs only stack-vault + the KMS
# daemon and holds the keys store, separate from the master, so a compromised master
# does not expose every agent's key. It joins the fleet WireGuard net (default .254).
# Afterwards the master + agents fetch unseal from it (PSAI_KMS_HOST). FIRST CUT — the
# node's WireGuard peering and a two-host live e2e are the remaining steps (TODO.md).
ra_install_kms_node() {
  ensure_sshpass || true
  ra_parse_args "$@" || return 1
  vault_enabled || { printf '%sstrict profile (vault) required for a KMS node%s\n' "$C_YELLOW" "$C_RESET" >&2; return 1; }
  local kwg pass aarch tag pre src=""
  kwg="$(kms_wg_ip)"
  for d in "$SCRIPT_DIR/vault" "$SCRIPT_DIR/../vault"; do [ -f "$d/Cargo.toml" ] && { src="$d"; break; }; done
  [ -n "$src" ] || { printf '%sno vault source to ship%s\n' "$C_RED" "$C_RESET" >&2; return 1; }
  printf '%sProvisioning KMS node at %s (wg %s)%s\n' "$C_B" "$RA_HOST" "$kwg" "$C_RESET"
  setup_wg_kms_tunnel || { printf '%sWireGuard peering of the KMS node failed%s\n' "$C_RED" "$C_RESET" >&2; return 1; }
  aarch="$(ra_ssh 'uname -m' 2>/dev/null | tr -d '[:space:]')"
  case "$aarch" in x86_64|amd64) tag=x86_64 ;; aarch64|arm64) tag=aarch64 ;; *) tag="$aarch" ;; esac
  pre="$src/dist/stack-vault-linux-$tag"
  ra_ssh 'mkdir -p ~/psai/bin ~/psai/secrets ~/psai/data/logs' >/dev/null 2>&1 || true
  if [ -x "$pre" ]; then
    ra_scp "$pre" 'psai/bin/stack-vault'
  else
    ra_ssh 'mkdir -p ~/vault-src/src' >/dev/null 2>&1 || true
    ra_scp "$src/Cargo.toml" 'vault-src/Cargo.toml'; ra_scp "$src/src/main.rs" 'vault-src/src/main.rs'
    # Build from the shipped source using the distro's cargo (apt) rather than piping
    # rustup's installer into a shell. A prebuilt binary (above) is the preferred path.
    ra_ssh 'command -v cargo >/dev/null 2>&1 || { export DEBIAN_FRONTEND=noninteractive; apt-get update -qq && apt-get install -y -qq cargo >/dev/null 2>&1; }; cd ~/vault-src && cargo build --release >/dev/null 2>&1 && cp target/release/stack-vault ~/psai/bin/stack-vault' >/dev/null 2>&1 || true
  fi
  ra_ssh 'chmod +x ~/psai/bin/stack-vault' >/dev/null 2>&1 || true
  pass="$(random_secret)"   # the KMS node's own unseal passphrase — the operator keeps it
  ra_ssh "PSAI_VAULT_PASS='$pass' nohup psai/bin/stack-vault serve --socket psai/vault.sock --blob psai/vault.enc >>psai/data/logs/vault.log 2>&1 & sleep 1; nohup psai/bin/stack-vault kms --listen ${kwg}:$(vault_kms_port) --socket psai/vault.sock >>psai/data/logs/vault.log 2>&1 &" >/dev/null 2>&1 || true
  KMS_HOST="$kwg"; KMS_SSH_USER="$RA_USER"; KMS_SSH_KEY="$RA_KEY"; save_config 2>/dev/null || true
  printf '  %sKMS node up.%s export %sPSAI_KMS_HOST=%s%s for agent installs.\n' "$C_GREEN" "$C_RESET" "$C_B" "$kwg" "$C_RESET"
  printf '  %skeep the KMS node passphrase safe: %s%s\n' "$C_YELLOW" "$pass" "$C_RESET"
  printf '  %sremaining: peer the node into the fleet WireGuard + two-host live test (TODO.md)%s\n' "$C_DIM" "$C_RESET"
}

ra_harden_vps2() {
  printf '%s...\n' "hardening agent"
  ra_ssh "cat > /etc/sysctl.d/99-psai.conf <<'SYS'
$(cis_sysctl_lines)
SYS
sysctl --system >/dev/null 2>&1 || true
mkdir -p /etc/ssh/sshd_config.d
cat > /etc/ssh/sshd_config.d/99-psai.conf <<'SSHD'
$(cis_sshd_lines)
SSHD
systemctl reload ssh 2>/dev/null || systemctl reload sshd 2>/dev/null || true
DEBIAN_FRONTEND=noninteractive apt-get install -y -qq ufw >/dev/null 2>&1 || true" || true
  local web_rules=""
  [ "$AGENT_WEB" = "true" ] && web_rules="ufw allow 80/tcp >/dev/null 2>&1 || true; ufw allow 443/tcp >/dev/null 2>&1 || true"
  ra_ssh "ufw allow ${REMOTE_WG_PORT}/udp >/dev/null 2>&1 || true
$web_rules
ufw allow from ${REMOTE_WG_NET}.0/24 to any port 22 proto tcp >/dev/null 2>&1 || true
ufw allow 22/tcp >/dev/null 2>&1 || true
ufw default deny incoming >/dev/null 2>&1 || true
ufw default allow outgoing >/dev/null 2>&1 || true
ufw --force enable >/dev/null 2>&1 || true" || true
}

ra_install_failback() {
  local mins="${SSH_FAILBACK_MIN:-10}"; case "$mins" in ''|*[!0-9]*) mins=10 ;; esac
  ra_ssh "cat > /etc/systemd/system/psai-ssh-open.service <<'U1'
[Unit]
Description=psai open public SSH at boot (failback)
After=network-online.target
Wants=network-online.target
[Service]
Type=oneshot
ExecStart=/usr/sbin/ufw allow 22/tcp
[Install]
WantedBy=multi-user.target
U1
cat > /etc/systemd/system/psai-ssh-lock.service <<'U2'
[Unit]
Description=psai re-lock public SSH
[Service]
Type=oneshot
ExecStart=/bin/sh -c 'ufw delete allow 22/tcp || true'
U2
cat > /etc/systemd/system/psai-ssh-lock.timer <<U3
[Unit]
Description=psai lock public SSH ${mins} min after boot
[Timer]
OnBootSec=${mins}min
Unit=psai-ssh-lock.service
[Install]
WantedBy=timers.target
U3
systemctl daemon-reload >/dev/null 2>&1 || true
systemctl enable psai-ssh-open.service >/dev/null 2>&1 || true
systemctl enable psai-ssh-lock.timer >/dev/null 2>&1 || true" || true
}

ra_lockdown_public_ssh() {
  if ra_wg_ssh 'echo ok' >/dev/null 2>&1; then
    ra_ssh 'ufw delete allow 22/tcp >/dev/null 2>&1 || true' || true
    printf '  %sSSH-over-WG verified — public SSH dropped%s\n' "$C_GREEN" "$C_RESET"
  else
    printf '  %sSSH-over-WG not verified — leaving public SSH open%s\n' "$C_YELLOW" "$C_RESET"
  fi
}

ra_open_ssh() {
  local mins="${RA_OPEN_MIN:-$SSH_FAILBACK_MIN}"; case "$mins" in ''|*[!0-9]*) mins=10 ;; esac
  ra_wg_ssh 'echo ok' >/dev/null 2>&1 || { printf '%sno WG tunnel%s\n' "$C_RED" "$C_RESET"; return 1; }
  ra_wg_ssh "ufw allow 22/tcp >/dev/null 2>&1 || true
systemd-run --on-active=${mins}min --unit=psai-open-ssh-revert /bin/sh -c 'ufw delete allow 22/tcp || true' >/dev/null 2>&1 || true" || true
  printf '%spublic SSH open for %s min%s\n' "$C_GREEN" "$mins" "$C_RESET"
}

# Fleet: list registered agents + per-agent control over WG.
fleet_menu() {
  load_config || { echo "$(t no_env)"; return 1; }
  sub_header "$(t d_fleet)"
  [ -n "$AGENT_SERVERS" ] || { printf '  (no agents)\n'; return 0; }
  local e idx ip wg dom
  for e in $AGENT_SERVERS; do
    IFS=':' read -r idx ip wg dom <<EOF
$e
EOF
    printf '  %sagent_worker_%s%s  public %s  wg %s  %s\n' "$C_B" "$idx" "$C_RESET" "$ip" "$wg" "${dom:-WG-only}"
  done
  printf '\n  %s%s start|stop|status%s · %s%s agents --open-ssh N%s\n' \
    "$C_DIM" "$MGMT_NAME" "$C_RESET" "$C_DIM" "$MGMT_NAME" "$C_RESET"
}
# ───────────────────────────── install flow (steps 0–5) ─────────────────────────────

# Optional: choose your own admin password. When set it becomes the Caddy basic-auth gate
# for the web UIs (Open WebUI/OpenHands/Qdrant) — bcrypt-hashed into the Caddyfile, the
# plaintext stored only in the secret store (the vault when sealed), never beside the config.
ask_admin_password() {
  [ "$NONINTERACTIVE" = "1" ] && return 0
  confirm "$(t admin_pw_q)" 'N' || return 0
  read_secret_confirmed ADMIN_PASSWORD_PLAIN "$(t pw_label)"
  return 0
}

# STEP 1 — node.
choose_node() {
  printf '\n%s%s%s\n' "$C_B" "$(t step1_title)" "$C_RESET"
  menu_line "$(t node_q)" s "$(t node_single)" m "$(t node_multi)"
  local c; c="$(ask "$(t node_q)" 's')"
  case "$(printf '%s' "$c" | tr -d '[][:space:]' | tr 'A-Z' 'a-z')" in
    m|multi|multiple) NODE_MODE="multi" ;;
    *)                NODE_MODE="single" ;;
  esac
  if [ "$NODE_MODE" = "multi" ]; then
    printf '  %s%s%s\n' "$C_DIM" "$(t node_multi_note)" "$C_RESET"
    printf '  %s%s%s\n' "$C_DIM" "$(t node_multi_pub)" "$C_RESET"
    DEPLOY_PROFILE="public"; ENABLE_AGENTS="true"
  fi
  prompt_set STACK_NAME "$(t q_stack_name)" "$DEFAULT_STACK_NAME"
  SAFE_STACK_NAME="$(safe_name "$STACK_NAME")"; [ -z "$SAFE_STACK_NAME" ] && SAFE_STACK_NAME="$DEFAULT_STACK_NAME"
  prompt_set STACK_DIR "$(t q_stack_dir)" "$(default_stack_dir_for "$SAFE_STACK_NAME")"
  STACK_DIR="${STACK_DIR/#\~/$HOME}"
  prompt_set ADMIN_USER "$(t q_admin_user)" "$DEFAULT_ADMIN_USER"
  ask_admin_password
  return 0   # never let a trailing non-zero abort the installer under set -e
}

# STEP 2 — deployment profile.
choose_deploy_profile() {
  if [ "$NODE_MODE" = "multi" ]; then DEPLOY_PROFILE="public"; else
    printf '\n%s%s%s\n' "$C_B" "$(t step2_title)" "$C_RESET"
    menu_line "$(t prof_q)" l "$(t prof_local)" p "$(t prof_public)"
    local c; c="$(ask "$(t prof_q)" 'l')"
    case "$(printf '%s' "$c" | tr -d '[][:space:]' | tr 'A-Z' 'a-z')" in
      p|public|pub) DEPLOY_PROFILE="public" ;;
      *)            DEPLOY_PROFILE="local" ;;
    esac
  fi
  if [ "$DEPLOY_PROFILE" = "public" ]; then ask_public_domain; fi
  return 0   # MUST end 0: under `set -e` a non-zero return here (e.g. the local-profile
             # case where the public check is false) aborts the whole installer.
}

ask_public_domain() {
  prompt_set PUBLIC_DOMAIN "$(t pub_domain_q)" ""
  if [ -z "$PUBLIC_DOMAIN" ]; then
    TLS_MODE="self"; printf '  %s%s%s\n' "$C_YELLOW" "$(t pub_noip)" "$C_RESET"; return 0
  fi
  PUBLIC_DOMAIN="$(normalize_zone "$PUBLIC_DOMAIN")"; TLS_MODE="le"
  prompt_set ACME_EMAIL "$(t pub_email)" "$ACME_EMAIL"
  # A-record reminder + best-effort check against the host IP.
  printf '  %s%s%s\n    %sai.%s  A  →  %s%s\n' "$C_DIM" "$(t pub_arecord)" "$C_RESET" "$C_DIM" "$PUBLIC_DOMAIN" "$(host_ip)" "$C_RESET"
  local got; got="$(check_arecord "psai.$PUBLIC_DOMAIN")"
  if [ -n "$got" ]; then printf '  %s%s (%s)%s\n' "$C_GREEN" "$(t pub_arecord_ok)" "$got" "$C_RESET"
  else printf '  %s%s%s\n' "$C_YELLOW" "$(t pub_arecord_no)" "$C_RESET"; fi
}

# AI section: check the hardware, then offer a bundled local LLM (Ollama) + a model that fits.
# Sets LOCAL_LLM (ollama/none) + OLLAMA_MODEL + GPU_MODE so the memory backend and chat use it.
choose_local_ai() {
  GPU_MODE="$(gpu_runtime)"
  printf '\n  %s%s%s\n' "$C_B$C_CYAN" "$(t ai_title)" "$C_RESET"
  if [ "$GPU_MODE" = "nvidia" ]; then printf '  %s%s%s\n' "$C_GREEN" "$(t ai_gpu_nvidia)" "$C_RESET"
  else
    detect_os
    [ "$OS_TYPE" = "macos" ] && printf '  %s%s%s\n' "$C_YELLOW" "$(t ai_cpu_mac)" "$C_RESET" \
                              || printf '  %s%s%s\n' "$C_YELLOW" "$(t ai_cpu_linux)" "$C_RESET"
  fi
  if ! confirm "$(t q_local_ai)" 'Y'; then LOCAL_LLM="none"; return 0; fi
  LOCAL_LLM="ollama"
  local def; def="$(gpu_default_model)"
  if confirm "$(t q_ai_model_def) $def?" 'Y'; then OLLAMA_MODEL="$def"
  else OLLAMA_MODEL="$(ask "$(t q_ai_model)" "$def")"; [ -z "$OLLAMA_MODEL" ] && OLLAMA_MODEL="$def"; fi
  printf '  %s%s%s\n' "$C_DIM" "$(t ai_pull_note)" "$C_RESET"
  return 0
}

# Force every additional/advanced component off — the answer when the operator declines extras.
extras_default_off() {
  ENABLE_QDRANT="false"; RAG_MODE="off"; ENABLE_EMBEDDINGS="false"; SHARED_MEMORY="false"
  MEMORY_MODE="none"; ENABLE_MCP="false"; LOCAL_LLM="none"
  MCP_GATEWAY="false"; LLM_GATEWAY="false"; ENABLE_EVAL="false"; ENABLE_PENTEST="false"
  return 0
}

# STEP 3 — components. Core (chat/agents/search/git) default yes; everything else lives behind
# the "additional components?" gate (default no).
choose_components() {
  printf '\n%s%s%s\n' "$C_B" "$(t step3_title)" "$C_RESET"
  confirm "$(t q_openwebui)" 'Y' && ENABLE_OPENWEBUI="true" || ENABLE_OPENWEBUI="false"
  if [ "$NODE_MODE" = "multi" ]; then ENABLE_AGENTS="true"   # agents are the point of multi-node
  else confirm "$(t q_agents)" 'Y' && ENABLE_AGENTS="true" || ENABLE_AGENTS="false"; fi
  if [ "$ENABLE_AGENTS" = "true" ]; then
    confirm "$(t q_web_oh)" 'Y' && AGENT_WEB="true" || AGENT_WEB="false"
    [ "$NODE_MODE" = "multi" ] && prompt_set OPENHANDS_LLM_MODEL "$(t q_oh_model)" "$OPENHANDS_LLM_MODEL"
  fi
  confirm "$(t q_search)" 'Y' && ENABLE_SEARCH="true" || ENABLE_SEARCH="false"
  if confirm "$(t q_git)" 'Y'; then
    ENABLE_GIT="true"; prompt_set GIT_SSH_PORT "$(t q_git_ssh_port)" "$DEFAULT_GIT_SSH_PORT"
    # multi: git lives on master OR moves to the agent worker node (one git either way).
    [ "$NODE_MODE" = "multi" ] && { confirm "$(t q_git_on_agent)" 'N' && ISOLATE_GIT="true" || ISOLATE_GIT="false"; }
  else ENABLE_GIT="false"; GIT_SSH_PORT="$DEFAULT_GIT_SSH_PORT"; fi

  # ── Additional / advanced components ──────────────────────────────────────────────
  # One gate, default OFF, so a plain install stays simple (chat + agents + search + git).
  # Yes → vector memory / RAG-plus, a memory backend + local LLM, MCP/LLM gateways, eval.
  if ! confirm "$(t q_extras)" 'N'; then extras_default_off; return 0; fi
  printf '  %s%s%s\n' "$C_B$C_CYAN" "$(t q_extras_title)" "$C_RESET"
  choose_local_ai   # AI section: hardware check → bundle Ollama + a fitting model (memory reuses it)
  # Shared vector memory.
  if [ "$NODE_MODE" = "multi" ]; then
    confirm "$(t ra_shared_q)" 'N' && { SHARED_MEMORY="true"; ENABLE_QDRANT="true"; } || SHARED_MEMORY="false"
  else
    if confirm "$(t q_qdrant)" 'N'; then
      ENABLE_QDRANT="true"
      printf '  %s%s%s\n' "$C_DIM" "$(t q_rag_plus_hint)" "$C_RESET"
      confirm "$(t q_rag_plus)" "$(rag_plus_default_answer)" && RAG_MODE="plus" || RAG_MODE="basic"
    else ENABLE_QDRANT="false"; RAG_MODE="off"; fi
  fi
  if [ "$ENABLE_QDRANT" = "true" ]; then
    # In rag-plus the local embed service handles embeddings — don't also ask for the built-in.
    [ "$RAG_MODE" = "plus" ] || { confirm "$(t q_embeddings)" 'N' && ENABLE_EMBEDDINGS="true" || ENABLE_EMBEDDINGS="false"; }
  else ENABLE_EMBEDDINGS="false"; fi
  # Memory backend (shared by chat + agents). One selector replaces the old MCP-stub toggle.
  if [ "$ENABLE_AGENTS" = "true" ] || [ "$ENABLE_OPENWEBUI" = "true" ]; then
    printf '  %s%s%s\n' "$C_DIM" "$(t q_memory_hint)" "$C_RESET"
    local mc; mc="$(ask "$(t q_memory)" "$([ "$ENABLE_QDRANT" = "true" ] && printf stub || printf none)")"
    case "$(printf '%s' "$mc" | tr -d '[:space:]' | tr 'A-Z' 'a-z')" in
      cognee)   MEMORY_MODE="cognee"; ENABLE_MCP="false" ;;
      graphiti) MEMORY_MODE="graphiti"; ENABLE_MCP="false" ;;
      mem0)     MEMORY_MODE="mem0"; ENABLE_MCP="false" ;;
      stub)     if [ "$ENABLE_QDRANT" = "true" ]; then MEMORY_MODE="stub"; ENABLE_MCP="true"
                else printf '  %s%s%s\n' "$C_YELLOW" "$(t q_memory_stub_needs_qdrant)" "$C_RESET"; MEMORY_MODE="none"; ENABLE_MCP="false"; fi ;;
      *)        MEMORY_MODE="none"; ENABLE_MCP="false" ;;
    esac
    case "$MEMORY_MODE" in
      cognee|graphiti)
        # Bundle a local LLM (Ollama, no cloud key) or point at an external endpoint (LM Studio/cloud).
        if [ "$LOCAL_LLM" = "ollama" ] || confirm "$(t q_bundle_ollama)" 'Y'; then LOCAL_LLM="ollama"
        else
          printf '  %s%s%s\n' "$C_DIM" "$(t q_ext_llm_hint)" "$C_RESET"
          [ -n "$MEMORY_LLM_URL" ] || MEMORY_LLM_URL="$(ask "$(t q_memory_llm_url)" '')"
          [ -n "$MEMORY_LLM_KEY" ] || MEMORY_LLM_KEY="$(ask "$(t q_memory_llm_key)" '')"
        fi ;;
      mem0) [ -n "$MEM0_MCP_URL" ] || MEM0_MCP_URL="$(ask "$(t q_mem0_url)" '')" ;;
    esac
  else ENABLE_MCP="false"; MEMORY_MODE="none"; fi
  # Verified tool servers for the agents (Docker MCP Gateway). Needs the host socket.
  if [ "$ENABLE_AGENTS" = "true" ]; then
    printf '  %s%s%s\n' "$C_DIM" "$(t q_gateway_hint)" "$C_RESET"
    confirm "$(t q_gateway)" 'N' && MCP_GATEWAY="true" || MCP_GATEWAY="false"
    confirm "$(t q_litellm)" 'N' && LLM_GATEWAY="true" || LLM_GATEWAY="false"
    confirm "$(t q_eval)" 'N' && ENABLE_EVAL="true" || ENABLE_EVAL="false"
  else MCP_GATEWAY="false"; LLM_GATEWAY="false"; ENABLE_EVAL="false"; fi
  if confirm "$(t q_pentest)" 'N'; then printf '  %s%s%s\n' "$C_RED" "$(t pentest_warn)" "$C_RESET"; ENABLE_PENTEST="true"; else ENABLE_PENTEST="false"; fi
  return 0   # never let a trailing non-zero abort the installer under set -e
}

# STEP 5 — zone & domains. Local zone stays the default (lan); a public domain fixes the
# zone. Local deployments may skip domains entirely → services on localhost ports.
choose_zone() {
  printf '\n%s%s%s\n' "$C_B" "$(t step5_title)" "$C_RESET"
  if [ "$DEPLOY_PROFILE" = "public" ] && [ -n "${PUBLIC_DOMAIN:-}" ]; then
    DOMAIN_ZONE="$PUBLIC_DOMAIN"
  else
    # Local: domains are optional. Decline → reach services on http://localhost:PORT.
    if ! confirm "$(t q_use_domains)" 'Y'; then
      NO_DOMAIN="true"; DOMAIN_ZONE="localhost"
      printf '  %s%s%s\n' "$C_DIM" "$(t dom_localhost_note)" "$C_RESET"
      set_default_domains
      print_active_domains
      return 0
    fi
    DOMAIN_ZONE="$DEFAULT_DOMAIN_ZONE"
  fi
  printf '  %s: %s%s%s\n' "$(t q_zone_def)" "$C_B" "$DOMAIN_ZONE" "$C_RESET"
  set_default_domains
  confirm_domains_loop
  if ! caddy_use_acme && [ "${TLS_MODE:-}" != "own" ]; then
    prompt_set CERT_YEARS "$(t cert_lifetime)" "$DEFAULT_CERT_YEARS"
    printf '%s' "$CERT_YEARS" | grep -Eq '^[0-9]+$' || CERT_YEARS="$DEFAULT_CERT_YEARS"
  else CERT_YEARS="$DEFAULT_CERT_YEARS"; fi
  return 0   # never let a trailing non-zero abort the installer under set -e
}

show_summary() {
  printf '\n%s%s%s\n' "$C_B" "$(t sum_header)" "$C_RESET"
  printf '  %-14s %s\n' "$(t sum_name):"    "$STACK_NAME"
  printf '  %-14s %s\n' "$(t sum_dir):"     "$STACK_DIR"
  printf '  %-14s %s\n' "$(t sum_node):"    "$NODE_MODE"
  printf '  %-14s %s\n' "$(t sum_profile):" "$DEPLOY_PROFILE"
  printf '  %-14s %s\n' "$(t sec_q):"       "$SECURITY_PROFILE"
  printf '  %-14s %s\n' "$(t sum_zone):"    "$DOMAIN_ZONE"
  printf '  %-14s %s · %s · %s · %s · %s · %s\n' "Components:" \
    "OpenWebUI=$(bool_label "$ENABLE_OPENWEBUI")" "OpenHands=$(bool_label "$ENABLE_AGENTS")" \
    "Search=$(bool_label "$ENABLE_SEARCH")" "Git=$(bool_label "$ENABLE_GIT")" \
    "Qdrant=$(bool_label "$ENABLE_QDRANT")" "MCP=$(bool_label "$ENABLE_MCP")"
  [ "${RAG_MODE:-off}" != "off" ] && printf '  %-14s %s\n' "RAG:" "$RAG_MODE"
  case "${MEMORY_MODE:-stub}" in stub|none) : ;; *) printf '  %-14s %s\n' "Memory:" "$MEMORY_MODE" ;; esac
  [ "${LOCAL_LLM:-none}" = "ollama" ] && printf '  %-14s ollama (%s)\n' "LLM:" "$OLLAMA_MODEL"
  [ "${MCP_GATEWAY:-false}" = "true" ] && printf '  %-14s %s\n' "MCP gateway:" "$MCP_GATEWAY_SERVERS"
  { [ "${LLM_GATEWAY:-false}" = "true" ] || [ "${ENABLE_EVAL:-false}" = "true" ]; } && \
    printf '  %-14s %s%s\n' "Ops:" "$([ "$LLM_GATEWAY" = true ] && printf 'LiteLLM ')" "$([ "$ENABLE_EVAL" = true ] && printf 'Langfuse')"
  printf '  %-14s stack=%s  web=%s\n' "Proxies:" "$EGRESS_STACK" "$EGRESS_WEB"
  print_active_domains
  printf '\n'
}

install_prompt_flow() {
  # The prompt phase is pure UI — it collects input and sets variables, it does not write
  # files or touch docker. `set -Eeuo pipefail` (armed globally) is unforgiving here: any
  # menu/preview helper whose last statement is a `cond && cmd` (false on the common path)
  # returns non-zero and, called as a bare command, aborts the whole installer mid-prompt.
  # Disable errexit for the collection, re-arm it before the real install work begins.
  set +e
  header_install
  step0_env || { printf '%s\n' "$(t install_cancel)"; set -e; exit 1; }   # STEP 0
  choose_node                 # STEP 1
  choose_deploy_profile       # STEP 2
  choose_components           # STEP 3
  choose_security_profile     # STEP 4
  choose_zone                 # STEP 5
  ask_proxies                 # two egress proxies (default direct)
  show_summary
  set -e                      # re-arm before perform_install does the real work
  confirm "$(t q_start_install)" 'Y' || { echo "$(t install_cancel)"; exit 0; }
}

apply_defaults_noninteractive() {
  STACK_NAME="${STACK_NAME:-$DEFAULT_STACK_NAME}"
  SAFE_STACK_NAME="$(safe_name "$STACK_NAME")"; [ -z "$SAFE_STACK_NAME" ] && SAFE_STACK_NAME="$DEFAULT_STACK_NAME"
  STACK_DIR="${STACK_DIR:-$(default_stack_dir_for "$SAFE_STACK_NAME")}"; STACK_DIR="${STACK_DIR/#\~/$HOME}"
  ADMIN_USER="${ADMIN_USER:-$DEFAULT_ADMIN_USER}"
  # `install --defaults` = a COMPLETE LOCAL stack: NO security profile, EVERY component on,
  # reachable both by the .lan domains AND on localhost ports. Each value still honours an
  # explicit PSAI_* override (so the multi-node agent install, which sets them, is unaffected).
  if [ "$NODE_MODE" != "multi" ]; then
    DEPLOY_PROFILE="${PSAI_DEPLOY:-local}"
    SECURITY_PROFILE="${PSAI_PROFILE:-none}"
    ENABLE_OPENWEBUI="${PSAI_OPENWEBUI:-true}"; ENABLE_AGENTS="${PSAI_AGENTS:-true}"
    ENABLE_SEARCH="${PSAI_SEARCH:-true}"; ENABLE_GIT="${PSAI_GIT:-true}"
    RAG_MODE="${PSAI_RAG:-plus}"; MEMORY_MODE="${PSAI_MEMORY:-cognee}"; LOCAL_LLM="${PSAI_LLM:-ollama}"
    OLLAMA_MODEL="${PSAI_OLLAMA_MODEL:-$(gpu_default_model)}"   # platform-aware local default
    MCP_GATEWAY="${PSAI_MCP_GATEWAY:-true}"; LLM_GATEWAY="${PSAI_LLM_GATEWAY:-true}"; ENABLE_EVAL="${PSAI_EVAL:-true}"
    [ "$DEPLOY_PROFILE" = "local" ] && DUAL_ACCESS="${PSAI_DUAL:-true}"
  fi
  [ "$NODE_MODE" = "multi" ] && { DEPLOY_PROFILE="public"; ENABLE_AGENTS="true"; }
  resolve_security_profile
  GIT_SSH_PORT="${GIT_SSH_PORT:-$DEFAULT_GIT_SSH_PORT}"
  if [ "$DEPLOY_PROFILE" = "public" ] && [ -n "${PUBLIC_DOMAIN:-}" ]; then DOMAIN_ZONE="$PUBLIC_DOMAIN"; else DOMAIN_ZONE="${DOMAIN_ZONE:-$DEFAULT_DOMAIN_ZONE}"; fi
  [ -z "${PUBLIC_DOMAIN:-}" ] && [ "$DEPLOY_PROFILE" = "public" ] && TLS_MODE="self"
  set_default_domains
  CERT_YEARS="${CERT_YEARS:-$DEFAULT_CERT_YEARS}"
  compute_egress_endpoints
}

perform_install() {
  if [ "$NONINTERACTIVE" = "1" ] || [ "$ASSUME_DEFAULTS" = "1" ]; then
    NONINTERACTIVE="1"; apply_defaults_noninteractive
    check_dependencies || return 1
  else
    install_prompt_flow
  fi

  resolve_oh_mode   # public/multi → dind unless PSAI_OH_MODE pinned (persisted by write_all_configs)
  resolve_rag_mode  # PSAI_RAG=plus → Qdrant + local embeddings/reranker + Docling/Tika ingest
  resolve_local_llm    # PSAI_LLM=ollama → bundle a local LLM; point memory at it
  resolve_memory_mode  # PSAI_MEMORY=cognee/graphiti/mem0 → real memory backend (replaces the stub)
  if [ "${MCP_GATEWAY:-false}" = "true" ] && [ "$DEPLOY_PROFILE" = "public" ]; then
    printf '%s%s%s\n' "$C_YELLOW" "$(t gateway_public_warn)" "$C_RESET"
  fi
  if [ "${ENABLE_AGENTS:-false}" = "true" ] && [ "${AGENTS_DOCKER:-false}" = "true" ] && [ "$DEPLOY_PROFILE" = "public" ]; then
    printf '%s%s%s\n' "$C_YELLOW" "$(t agents_docker_public_warn)" "$C_RESET"
  fi
  if ollama_enabled && [ "$DEPLOY_PROFILE" = "public" ]; then
    printf '%s%s%s\n' "$C_YELLOW" "$(t ollama_auth_proxy_warn)" "$C_RESET"
  fi
  capture_docker_context   # pin the docker daemon (Colima vs Docker Desktop) for later runs

  detect_os
  [ "$OS_TYPE" = "macos" ] && printf '\n%s%s%s\n' "$C_YELLOW" "$(t mac_admin_note)" "$C_RESET"

  if [ -f "$STACK_DIR/.stack.env" ] && [ "$NONINTERACTIVE" != "1" ]; then
    printf '\n'; confirm "$(t q_overwrite)" 'Y' || exit 0
  fi

  # Unseal stack-vault BEFORE any secret is generated, so nothing plaintext hits disk.
  # Run in the foreground (it may prompt for the passphrase) — not inside run_step.
  if vault_enabled; then
    mkdir -p "$STACK_DIR/bin" "$STACK_DIR/data/logs"
    vault_present || build_vault || true
    vault_start || { printf '%svault required but not unsealed — aborting%s\n' "$C_RED" "$C_RESET"; return 1; }
  fi

  if ingest_enabled; then STEP_TOTAL=6; else STEP_TOTAL=5; fi
  STEP_NUM=0
  run_step "$(t step_dirs)"     prepare_dirs_and_secrets
  run_step "$(t step_configs)"  write_all_configs
  run_step "$(t step_sandbox)"  build_openhands_sandbox
  run_step "$(t step_compose)"  validate_compose

  # /etc/hosts (local profile).
  if [ "$DEPLOY_PROFILE" != "public" ]; then
    if can_use_sudo; then
      [ "$NONINTERACTIVE" = "1" ] || confirm "$(t q_add_hosts)" 'Y' && add_hosts_entries
    else print_hosts_command; fi
  fi

  run_step "$(t step_up)" compose_up_core
  if ingest_enabled; then
    if ! run_step "$(t step_ingest)" compose_up_ingest; then
      printf '%s%s%s\n' "$C_YELLOW" "$(t ingest_deferred)" "$C_RESET" >&2
    fi
  fi
  prune_disabled_services

  # Apply the security profile to the host. Firewall + CIS hardening need admin. If we don't
  # have it, say so loudly instead of leaving the saved profile (SEC_FIREWALL=true) claiming a
  # firewall that was never enabled — and verify it actually came up when we did try.
  if [ "$SEC_CIS" = "true" ] || [ "$SEC_FIREWALL" = "true" ]; then
    if can_use_sudo; then
      harden_host
      if [ "$SEC_FIREWALL" = "true" ] && [ "$(firewall_status)" != "on" ]; then
        printf '%s%s sudo %s harden%s\n' "$C_YELLOW" "$(t harden_fw_pending)" "$MGMT_NAME" "$C_RESET"
      fi
    else
      printf '%s%s sudo %s harden%s\n' "$C_YELLOW" "$(t harden_no_admin)" "$MGMT_NAME" "$C_RESET"
    fi
  fi
  [ "$SEC_WATCHDOG" = "true" ] && watchdog_enable >/dev/null 2>&1

  # Trust the local CA when we can (so HTTPS just works).
  CA_TRUSTED="false"
  if ! caddy_use_acme && can_use_sudo; then
    do_trust_ca >/dev/null 2>&1 && CA_TRUSTED="true"
  fi

  # Multi-node: provision the agent worker node(s) now that the master is up.
  if [ "$NODE_MODE" = "multi" ] && [ "$NONINTERACTIVE" != "1" ] && type remote_agents >/dev/null 2>&1; then
    remote_agents || true
  fi

  finish_message
}

finish_message() {
  local mgmt="$STACK_DIR/bin/$MGMT_NAME"
  printf '\n'; banner_stack
  printf '\n%s%s %s%s\n' "$C_B" "$C_GREEN" "$(t fin_done)" "$C_RESET"
  line
  printf '  %s:\n    %s%s%s %s\n    %s%s%s\n' "$(t fin_manage)" \
    "$C_B" "$MGMT_NAME" "$C_RESET" "$(t fin_cmd_hint)" "$C_DIM" "$mgmt" "$C_RESET"
  printf '%s' "$MGMT_NAME" | copy_to_clipboard 2>/dev/null && printf '    %s↑ copied%s\n' "$C_DIM" "$C_RESET"
  printf '  %s:\n    %s/secrets/passwords.txt\n' "$(t fin_secrets)" "$STACK_DIR"
  if ! caddy_use_acme && ! no_domain; then printf '  %s:\n    %s/secrets/certificates/root.crt\n' "$(t fin_ca)" "$STACK_DIR"; fi
  if [ "${SEAL_ENABLED:-false}" = "true" ]; then
    printf '  %s: %s%s%s (%s)\n' "$(t d_seal)" "$C_GREEN" "$(seal_status_label)" "$C_RESET" "$SEAL_MODE"
  fi
  line
  printf '  %s:\n' "$(t fin_next)"
  if no_domain; then
    printf '    1. %s%s%s\n' "$C_GREEN" "$(t dom_localhost_note)" "$C_RESET"
    print_active_domains
    return 0
  fi
  if [ "$CA_TRUSTED" = "true" ] || caddy_use_acme; then printf '    1. %sroot CA ok%s\n' "$C_GREEN" "$C_RESET"
  else printf '    1. trust root.crt:\n'; print_trust_ca_command; fi
  printf '    2. %s  →  https://%s\n' "$(t fin_open)" "$(main_host)"
  [ "$ENABLE_GIT" = "true" ] && printf '    3. %s%s%s  →  https://%s\n' "$C_YELLOW" "$(t fin_git_note)" "$C_RESET" "$GIT_DOMAIN"
  return 0   # never let a trailing false test make a successful install report failure
}
# ───────────────────────────── lifecycle ─────────────────────────────
# Multi-node helpers (no-ops unless agents are isolated).
iso_active() { [ "${ISOLATE_AGENTS:-false}" = "true" ]; }
iso_vps2_ssh() {
  local k="$STACK_DIR/secrets/wg/mgmt.key"; [ -f "$k" ] || return 1
  # Pin the agent's host key on first contact (persisted known_hosts) rather than
  # StrictHostKeyChecking=no, which trusted any key on every connect.
  ssh -i "$k" -o ConnectTimeout=8 -o BatchMode=yes -o StrictHostKeyChecking=accept-new \
    -o UserKnownHostsFile="$(ra_known_hosts)" "${RA_USER:-root}@$(agent_wg_ip)" "$@"
}
iso_wg_up()   { detect_os; [ "$OS_TYPE" = "linux" ] || return 0; local S=""; [ "$(id -u)" = 0 ] || S=sudo; $S wg-quick up wg0 2>/dev/null || true; }
iso_wg_down() { detect_os; [ "$OS_TYPE" = "linux" ] || return 0; local S=""; [ "$(id -u)" = 0 ] || S=sudo; $S wg-quick down wg0 2>/dev/null || true; }

start_stack() {
  load_config || exit 1; ensure_path_brew
  if vault_enabled; then vault_start || return 1; else ensure_unsealed || return 1; fi
  render_runtime_env   # re-render secret env from the vault (shredded on last stop)
  start_colima_if_needed
  iso_active && iso_wg_up
  iso_active && vault_enabled && vault_kms_start   # serve agent unseal keys over WG
  compose up -d
  if iso_active; then iso_vps2_ssh "$MGMT_NAME start" >/dev/null 2>&1 || printf '%sagent worker node unreachable%s\n' "$C_YELLOW" "$C_RESET"; fi
}
stop_stack() {
  load_config || exit 1; ensure_path_brew
  iso_active && { iso_vps2_ssh "$MGMT_NAME stop" >/dev/null 2>&1 || true; }
  compose stop
  shred_runtime_env   # remove the rendered secret env from disk
  if vault_enabled; then vault_kms_stop; vault_seal; elif seal_enabled && ! is_sealed; then seal_wipe; fi
  iso_active && iso_wg_down
}
status_stack()  { load_config || exit 1; ensure_path_brew; compose ps; }
restart_stack() { load_config || exit 1; ensure_path_brew; compose restart; }
logs_stack()    { load_config || exit 1; ensure_path_brew; local svc="${1:-}"; if [ -n "$svc" ]; then compose logs -f --tail=200 "$svc"; else compose logs -f --tail=200; fi; }

uninstall_usage() {
  printf '%s\n' "$(t un_usage)"
}

uninstall_note() {
  printf '  %s- %s%s\n' "$C_DIM" "$1" "$C_RESET"
}

uninstall_command_links() {
  local dry="$1" d
  [ "$dry" = "true" ] || remove_legacy_command_links
  for d in /opt/homebrew/bin /usr/local/bin "$HOME/.local/bin" "$HOME/bin"; do
    if [ -L "$d/$MGMT_NAME" ]; then
      uninstall_note "$d/$MGMT_NAME"
      [ "$dry" = "true" ] || rm -f "$d/$MGMT_NAME" 2>/dev/null || true
    fi
  done
}

uninstall_compose_down() {
  local dry="$1" volumes="$2" vol_flag=""
  [ "$volumes" = "true" ] && vol_flag="-v"
  if [ ! -f "$STACK_DIR/compose/docker-compose.yml" ]; then return 0; fi
  uninstall_note "docker compose down ${vol_flag:+$vol_flag }--remove-orphans"
  [ "$dry" = "true" ] && return 0
  command_exists docker || return 0
  # shellcheck disable=SC2086
  compose down $vol_flag --remove-orphans >/dev/null 2>&1 || true
}

uninstall_stack() {
  local yes="false" remove_data="false" remove_volumes="false" dry="false" arg
  while [ $# -gt 0 ]; do
    arg="$1"; shift || true
    case "$arg" in
      --yes|-y) yes="true" ;;
      --data|--purge) remove_data="true" ;;
      --keep-data) remove_data="false" ;;
      --volumes|-v) remove_volumes="true" ;;
      --dry-run|--dry) dry="true" ;;
      --dir)
        [ $# -gt 0 ] || { uninstall_usage; return 1; }
        STACK_DIR="${1/#\~/$HOME}"; shift || true ;;
      --help|-h) uninstall_usage; return 0 ;;
      *) printf '%s: %s\n' "$(t un_unknown)" "$arg"; uninstall_usage; return 1 ;;
    esac
  done

  load_config || { echo "$(t no_env)"; return 1; }
  ensure_path_brew
  printf '\n%s%s%s\n  %s\n' "$C_RED$C_B" "$(t un_warn)" "$C_RESET" "$STACK_DIR"
  if [ "$yes" != "true" ]; then
    confirm "$(t un_confirm)" 'N' || { echo "$(t cancelled)"; return 0; }
    [ "$remove_volumes" = "true" ] || { confirm "$(t q_rm_volumes)" 'N' && remove_volumes="true"; }
    [ "$remove_data" = "true" ] || { confirm "$(t un_data)" 'N' && remove_data="true"; }
  fi

  [ "$dry" = "true" ] && printf '  %s%s%s\n' "$C_YELLOW" "$(t un_dry)" "$C_RESET"
  uninstall_compose_down "$dry" "$remove_volumes"
  uninstall_note "$(t un_runtime)"
  if [ "$dry" != "true" ]; then
    shred_runtime_env
    vault_seal   # stop the secrets daemon (wipes its RAM)
    docker rm -f "${SAFE_STACK_NAME}-wg-bridge" >/dev/null 2>&1 || true
    iso_active && iso_wg_down
  fi

  uninstall_note "$(t un_hosts)"
  [ "$dry" = "true" ] || remove_hosts_entries
  uninstall_note "$(t un_links)"
  uninstall_command_links "$dry"
  uninstall_note "$(t un_cron)"
  [ "$dry" = "true" ] || cron_remove >/dev/null 2>&1 || true
  uninstall_note "$(t un_watchdog)"
  [ "$dry" = "true" ] || watchdog_disable >/dev/null 2>&1 || true
  uninstall_note "$(t un_seal)"
  [ "$dry" = "true" ] || rm -f "$(seal_keyfile)" 2>/dev/null || true

  if [ "$remove_data" = "true" ]; then
    uninstall_note "$(t un_data_rm)"
    [ "$dry" = "true" ] || rm -rf "$STACK_DIR" 2>/dev/null || true
    printf '%s%s%s\n' "$C_GREEN" "$(t un_done)" "$C_RESET"
  else
    printf '%s %s%s%s\n' "$(t un_kept)" "$C_B" "$STACK_DIR" "$C_RESET"
  fi
}

update_rebuild() {
  load_config || exit 1; ensure_path_brew; start_colima_if_needed
  check_dependencies || return 1
  select_openhands_image
  write_all_configs
  build_openhands_sandbox
  compose_up_core
  if ingest_enabled; then compose_up_ingest || printf '%s%s%s\n' "$C_YELLOW" "$(t ingest_deferred)" "$C_RESET" >&2; fi
  prune_disabled_services
}
rebuild_only() {
  load_config || exit 1; ensure_path_brew; start_colima_if_needed
  select_openhands_image
  write_all_configs
  build_openhands_sandbox
  compose_up_core
  if ingest_enabled; then compose_up_ingest || printf '%s%s%s\n' "$C_YELLOW" "$(t ingest_deferred)" "$C_RESET" >&2; fi
  prune_disabled_services
}
# ───────────────────────────── operator dashboard ─────────────────────────────
check_update_status() { UPDATE_AVAILABLE="${UPDATE_AVAILABLE:-false}"; }

# service|image|state|health for every container; cached so render is cheap.
COMP_LIST=""
collect_components() {
  COMP_LIST=""
  command_exists docker || return 0
  [ -f "$STACK_DIR/compose/docker-compose.yml" ] || return 0
  COMP_LIST="$( cd "$STACK_DIR/compose" 2>/dev/null && \
    docker compose -f docker-compose.yml ps -a --format '{{.Service}}|{{.Image}}|{{.State}}|{{.Health}}|{{.ExitCode}}' 2>/dev/null )" || COMP_LIST=""
}

# Operator table: context line, column header, one row per container. Column widths are
# computed from the data so long names (ingest-docling) / images don't shift the table.
render_components() {
  section_header "$(t sec_components)"
  [ -n "$COMP_LIST" ] || { printf '    %s(%s)%s\n' "$C_DIM" "$(t st_stopped)" "$C_RESET"; return 0; }
  local svc img st health code dot nw=4 iw=5 l
  while IFS='|' read -r svc img st health code; do
    [ -n "$svc" ] || continue
    img="${img##*/}"
    l=${#svc}; [ "$l" -gt "$nw" ] && nw="$l"
    l=${#img}; [ "$l" -gt "$iw" ] && iw="$l"
  done <<EOF
$COMP_LIST
EOF
  nw=$((nw + 1)); iw=$((iw + 1))
  printf '    %s%-3s %-*s %-*s %-9s %s%s\n' "$C_DIM" "" "$nw" "NAME" "$iw" "IMAGE" "STATE" "HEALTH" "$C_RESET"
  while IFS='|' read -r svc img st health code; do
    [ -n "$svc" ] || continue
    img="${img##*/}"      # short image + tag
    # green = running; dim = a one-shot that finished cleanly (exit 0, e.g. ollama-pull);
    # red = a real failure (non-zero exit / dead); yellow = transitional (created/restarting).
    case "$st" in
      running) dot="${C_GREEN}●${C_RESET}" ;;
      exited)  case "${code:-0}" in 0|'') dot="${C_DIM}●${C_RESET}" ;; *) dot="${C_RED}●${C_RESET}" ;; esac ;;
      dead)    dot="${C_RED}●${C_RESET}" ;;
      *)       dot="${C_YELLOW}●${C_RESET}" ;;
    esac
    [ -z "$health" ] && health="-"
    printf '    %s   %s%-*s%s %-*s %-9s %s\n' "$dot" "$C_B" "$nw" "$svc" "$C_RESET" "$iw" "$img" "$st" "$health"
  done <<EOF
$COMP_LIST
EOF
  return 0
}

# Network map: the two egress proxies + their routes.
proxy_label() {
  case "$1" in
    none) printf '%s' "$(t px_direct)" ;; tor) printf 'Tor' ;; wireguard) printf 'WireGuard' ;;
    vless) printf 'VLESS' ;; adguardvpn) printf 'AdGuard VPN' ;; tailscale) printf 'Tailscale' ;;
    *) printf '%s' "$1" ;;
  esac
}
render_netmap() {
  section_header "$(t sec_netmap)"
  printf '    %s%-13s%s %s%s%s  %s(LLM + %s)%s\n' "$C_DIM" "proxy-stack:" "$C_RESET" "$C_CYAN" "$(proxy_label "$EGRESS_STACK")" "$C_RESET" \
    "$C_DIM" "$(t d_update)" "$C_RESET"
  printf '    %s%-13s%s %s%s%s  %s(web worker)%s\n' "$C_DIM" "proxy-web:" "$C_RESET" "$C_CYAN" "$(proxy_label "$EGRESS_WEB")" "$C_RESET" "$C_DIM" "$C_RESET"
  if iso_active; then
    printf '    %s%-13s%s ⇄ WG ⇄  %s%s%s  %s(%s)%s\n' "$C_DIM" "agents:" "$C_RESET" "$C_B" "${AGENT_WG_IP:-?}" "$C_RESET" "$C_DIM" "${AGENT_PUBLIC_IP:-?}" "$C_RESET"
  fi
}

render_secrets() {
  section_header "$(t sec_secrets)"
  local sc="$C_DIM" label store="seal"
  if vault_enabled; then
    store="$(vault_role_label)"; label="$(vault_status_label)"; vault_up && sc="$C_GREEN" || sc="$C_YELLOW"
  else
    label="$(seal_status_label)"
    if seal_enabled; then if is_sealed; then sc="$C_GREEN"; else sc="$C_YELLOW"; fi; fi
  fi
  printf '    %sadmin:%s %s%s%s    %s %s%s:%s %s%s%s\n' "$C_DIM" "$C_RESET" "$C_B" "${ADMIN_USER:-admin}" "$C_RESET" \
    "$(status_dot "$sc")" "$C_DIM" "$store" "$C_RESET" "$sc" "$label" "$C_RESET"
}

header_stack() {
  clear_screen
  banner_stack
  render_context
  collect_runtime; collect_components
  render_runtime
  render_components
  render_netmap
  render_secrets
  printf '\n'
}

# ───────────────────────────── menus ─────────────────────────────
installed_menu() {
  load_config || return 1
  ensure_lang; check_update_status
  while true; do
    header_stack
    printf '  %s%s%s\n\n' "$C_B$C_CYAN" "$(t dash_manage)" "$C_RESET"
    menu_line "$(t dash_run)"  1 "$(t d_start)" 2 "$(t d_stop)" 3 "$(t d_restart)" 4 "$(t d_status)" 5 "$(t d_logs)"
    menu_line "$(t dash_data)" b "$(t d_backup)" r "$(t d_restore)" u "$(t d_update)" g "$(t d_rebuild)" a "$(t d_components)"
    menu_line "$(t dash_net)"  s "$(t d_security)" p "$(t d_proxy)" w "$(t d_watchdog)" e "$(t d_seal)" t "trust-ca" h "hosts"
    iso_active && menu_line "" f "$(t d_fleet)"
    menu_line "$(t dash_settings)" l "$(t d_lang)" '?' "$(t d_help)" q "$(t quit)"
    printf '\n%s: ' "$(t menu_choice_cmd)"
    local c=""; IFS= read -r c || exit 0
    # Accept a hotkey OR a typed command (start, stop, backup, security, …).
    case "$(trim "$c" | tr 'A-Z' 'a-z')" in
      1|start)            start_stack; pause ;;
      2|stop)             stop_stack; pause ;;
      3|restart)          restart_stack; pause ;;
      4|status)           status_stack; pause ;;
      5|logs)             logs_stack ;;
      b|backup)           backup_stack; pause ;;
      r|restore)          restore_stack; pause ;;
      u|update)           update_rebuild; pause ;;
      g|rebuild)          rebuild_only; pause ;;
      a|components|upgrade) component_manager; pause ;;
      s|security)         security_menu; pause ;;
      p|proxy|proxies)    proxy_menu; pause ;;
      w|watchdog)         watchdog_menu; pause ;;
      e|seal|unseal)      if vault_enabled; then { vault_up && seal_now || unseal_now; }; elif seal_enabled && ! is_sealed; then seal_now; else unseal_now; fi; pause ;;
      f|fleet)            iso_active && fleet_menu; pause ;;
      t|trust-ca|trustca) trust_ca; pause ;;
      h|hosts|add-hosts)  add_hosts_entries; pause ;;
      l|lang|language)    choose_lang ;;
      \?|help)            print_help; pause ;;
      q|quit|exit)        exit 0 ;;
      "")                 : ;;
      *)                  echo "$(t no_such_item)"; pause ;;
    esac
  done
}

bootstrap_menu() {
  ensure_lang; check_update_status
  while true; do
    header_install
    printf '  %s%s%s\n\n' "$C_DIM" "$(t bm_hint)" "$C_RESET"
    printf '  %s[1]%s %s\n' "$C_CYAN" "$C_RESET" "$(t bm_new)"
    printf '  %s[2]%s %s\n' "$C_CYAN" "$C_RESET" "$(t bm_restore)"
    printf '  %s[3]%s %s\n' "$C_CYAN" "$C_RESET" "$(t bm_upgrade)"
    printf '  %s[4]%s %s\n' "$C_CYAN" "$C_RESET" "$(t bm_selfupdate)"
    printf '  %s[5]%s %s\n\n' "$C_CYAN" "$C_RESET" "$(t bm_lang)"
    printf '  %s[q]%s %s\n\n' "$C_CYAN" "$C_RESET" "$(t quit)"
    printf '%s: ' "$(t menu_choice)"
    local c=""; IFS= read -r c || exit 0
    case "$(trim "$c")" in
      1) perform_install; pause ;;
      2) restore_stack; pause ;;
      3) component_manager; pause ;;
      4) self_update; pause ;;
      5) choose_lang ;;
      q|Q) exit 0 ;;
      *) echo "$(t no_such_item)"; pause ;;
    esac
  done
}

# ── component manager: toggle install/remove ──
cm_row() {
  local box="[ ]" tag=""
  [ "$2" = "true" ] && box="[x]"
  if [ "$2" != "$3" ]; then [ "$2" = "true" ] && tag="${C_GREEN}$(t cm_add)${C_RESET}" || tag="${C_RED}$(t cm_del)${C_RESET}"
  elif [ "$3" = "true" ]; then tag="${C_DIM}$(t cm_have)${C_RESET}"; fi
  printf '  %s %s[%s]%s %-22s %s\n' "$box" "$C_CYAN" "$1" "$C_RESET" "$4" "$tag"
}
component_manager() {
  load_config || { header_install; STACK_DIR="$(ask "Stack path" "$(default_stack_dir_for "$DEFAULT_STACK_NAME")")"; load_config || { echo "$(t no_env)"; return 1; }; }
  local t_owui="$ENABLE_OPENWEBUI" t_oh="$ENABLE_AGENTS" t_sx="$ENABLE_SEARCH" t_git="$ENABLE_GIT" t_qd="$ENABLE_QDRANT" t_mcp="$ENABLE_MCP"
  local o_owui="$t_owui" o_oh="$t_oh" o_sx="$t_sx" o_git="$t_git" o_qd="$t_qd" o_mcp="$t_mcp"
  while true; do
    sub_header "$(t cm_title)"
    cm_row 1 "$t_owui" "$o_owui" "Open WebUI"
    cm_row 2 "$t_oh"   "$o_oh"   "OpenHands"
    cm_row 3 "$t_sx"   "$o_sx"   "SearXNG"
    cm_row 4 "$t_git"  "$o_git"  "Forgejo (git)"
    cm_row 5 "$t_qd"   "$o_qd"   "Qdrant"
    cm_row 6 "$t_mcp"  "$o_mcp"  "MCP server"
    printf '\n%s\n%s: ' "$(t cm_hint)" "$(t menu_choice)"
    local line n; read_user_line line; line="$(trim "$line")"
    case "$line" in
      q|Q) return 0 ;; "") break ;;
      *) for n in $line; do case "$n" in
           1) [ "$t_owui" = true ] && t_owui=false || t_owui=true ;;
           2) [ "$t_oh" = true ] && t_oh=false || t_oh=true ;;
           3) [ "$t_sx" = true ] && t_sx=false || t_sx=true ;;
           4) [ "$t_git" = true ] && t_git=false || t_git=true ;;
           5) [ "$t_qd" = true ] && t_qd=false || t_qd=true ;;
           6) [ "$t_mcp" = true ] && t_mcp=false || t_mcp=true ;;
         esac; done ;;
    esac
  done
  if [ "$t_owui$t_oh$t_sx$t_git$t_qd$t_mcp" = "$o_owui$o_oh$o_sx$o_git$o_qd$o_mcp" ]; then echo "$(t cm_nochange)"; return 0; fi
  ENABLE_OPENWEBUI="$t_owui"; ENABLE_AGENTS="$t_oh"; ENABLE_SEARCH="$t_sx"; ENABLE_GIT="$t_git"; ENABLE_QDRANT="$t_qd"; ENABLE_MCP="$t_mcp"
  [ "$ENABLE_QDRANT" = "true" ] || ENABLE_MCP="false"
  set_default_domains
  confirm "$(t q_start_install)" 'Y' || return 0
  check_dependencies || return 1
  write_all_configs; build_openhands_sandbox
  compose up -d --build --remove-orphans
  prune_disabled_services; reload_caddy
}

# ── security: switch profile (within the current deploy profile) + per-toggle ──
security_menu() {
  load_config || { echo "$(t no_env)"; return 1; }
  sub_header "$(t d_security)"
  printf '  %s: %s%s%s\n' "$(t sec_q)" "$C_B" "$SECURITY_PROFILE" "$C_RESET"
  choose_security_profile
  apply_security_to_host
  save_config
}
apply_security_to_host() {
  { [ "$SEC_CIS" = "true" ] || [ "$SEC_FIREWALL" = "true" ]; } && can_use_sudo && harden_host
  [ "$SEC_CIS" = "false" ] && [ "$SEC_FIREWALL" = "false" ] && can_use_sudo && harden_host --off
  if [ "$SEC_WATCHDOG" = "true" ]; then watchdog_enable >/dev/null 2>&1; else watchdog_disable >/dev/null 2>&1; fi
  write_all_configs >/dev/null 2>&1 || true
}

# ── proxy management: enable/disable + configure each, then apply ──
proxy_menu() {
  load_config || { echo "$(t no_env)"; return 1; }
  while true; do
    sub_header "$(t px_title)"
    printf '  %s[1]%s proxy-stack  %s%s%s  %s(%s)%s\n' "$C_CYAN" "$C_RESET" "$C_B" "$(proxy_label "$EGRESS_STACK")" "$C_RESET" "$C_DIM" "$(t px_stack)" "$C_RESET"
    printf '  %s[2]%s proxy-web    %s%s%s  %s(%s)%s\n' "$C_CYAN" "$C_RESET" "$C_B" "$(proxy_label "$EGRESS_WEB")" "$C_RESET" "$C_DIM" "$(t px_web)" "$C_RESET"
    printf '  %s[3]%s %s: %s\n' "$C_CYAN" "$C_RESET" "$(t px_local_q)" "$(bool_label "$ROUTE_LOCAL_LLM")"
    printf '  %s[a]%s apply   %s[b]%s %s\n\n%s: ' "$C_CYAN" "$C_RESET" "$C_CYAN" "$C_RESET" "$(t m_back)" "$(t menu_choice)"
    local c; IFS= read -r c || return 0
    case "$(trim "$c")" in
      1) choose_egress_slot stack '0'; configure_egress_secrets stack ;;
      2) choose_egress_slot web '0'; configure_egress_secrets web ;;
      3) [ "$ROUTE_LOCAL_LLM" = "true" ] && ROUTE_LOCAL_LLM="false" || ROUTE_LOCAL_LLM="true" ;;
      a) compute_egress_endpoints; write_all_configs; build_openhands_sandbox; compose up -d --build --remove-orphans; prune_disabled_services; reload_caddy; return 0 ;;
      b|"") return 0 ;;
      *) : ;;
    esac
  done
}

watchdog_menu() {
  load_config || { echo "$(t no_env)"; return 1; }
  sub_header "$(t d_watchdog)"
  printf '  %s: %s%s%s\n\n' "$(t sec_wd_l)" "$C_B" "$(watchdog_state)" "$C_RESET"
  menu_line "" 1 "$(t on)" 2 "$(t off)" b "$(t m_back)"
  printf '%s: ' "$(t menu_choice)"
  local c; IFS= read -r c || return 0
  case "$(trim "$c")" in 1) watchdog_enable ;; 2) watchdog_disable ;; *) : ;; esac
}

print_help() {
  local cmd="$MGMT_NAME" w=40
  printf '%s%s%s v%s %s\n\n' "$C_B" "$PRODUCT_NAME" "$C_RESET" "$STACK_VERSION" "$STACK_CHANNEL"
  printf '  Usage: %s%s%s [command]\n  No command — interactive menu.\n\n' "$C_B" "$cmd" "$C_RESET"
  printf "    %-${w}s install (interactive)\n"  "$cmd install"
  printf "    %-${w}s install with defaults\n"  "$cmd install --defaults"
  printf "    %-${w}s start / stop / restart\n" "$cmd start|stop|restart"
  printf "    %-${w}s container status / logs\n" "$cmd status|logs [svc]"
  printf "    %-${w}s update images and rebuild\n" "$cmd update"
  printf "    %-${w}s install/remove components\n" "$cmd upgrade"
  printf "    %-${w}s backup / restore (7z)\n" "$cmd backup|restore"
  printf "    %-${w}s egress proxies\n"        "$cmd proxy"
  printf "    %-${w}s security profile\n"      "$cmd security"
  printf "    %-${w}s secrets seal / unseal\n" "$cmd seal|unseal"
  printf "    %-${w}s isolate agents on a VPS (WireGuard)\n" "$cmd agents --host IP"
  printf "    %-${w}s uninstall stack (data kept)\n" "$cmd uninstall [--data|--dry-run]"
  printf "    %-${w}s language ru|en\n"        '--lang ru|en'
  printf '\n'
}
usage() { print_help; }
# ───────────────────────────── backup / restore ─────────────────────────────
# Encrypted 7z archive of .stack.env + secrets + data. Password = the seal pass
# (auto/manual) when sealing is on, else a prompt.
backup_pass() {
  if seal_enabled; then seal_pass; else
    local p; printf 'Backup password: ' >&2; stty -echo 2>/dev/null; IFS= read -r p; stty echo 2>/dev/null; printf '\n' >&2; printf '%s' "$p"
  fi
}

backup_stack() {
  load_config || { echo "$(t no_env)"; return 1; }
  ensure_path_brew; sevenzip_detect
  [ -n "$SEVENZIP_BIN" ] || { echo '7z not found.'; return 1; }
  local dir="${1:-$STACK_DIR/backups}"; mkdir -p "$dir"
  local out; out="$dir/${SAFE_STACK_NAME}_$(date +%Y%m%d_%H%M%S).7z"
  local pass; pass="$(backup_pass)"
  ( cd "$STACK_DIR" && "$SEVENZIP_BIN" a -t7z -mhe=on -p"$pass" "$out" \
      .stack.env secrets data compose >/dev/null 2>&1 ) || { echo 'backup failed'; return 1; }
  ( cd "$dir" && shasum -a 256 "$(basename "$out")" > "$out.sha256" 2>/dev/null ) || true
  printf '%s%s%s %s\n' "$C_GREEN" "$(t done_word)" "$C_RESET" "$out"
}

restore_stack() {
  ensure_path_brew; sevenzip_detect
  [ -n "$SEVENZIP_BIN" ] || { echo '7z not found.'; return 1; }
  local arc="${1:-}" dst="${2:-}"
  [ -n "$arc" ] || arc="$(ask "$(t q_backup_path)" '')"
  [ -f "${arc/#\~/$HOME}" ] || { echo "Archive not found."; return 1; }
  arc="${arc/#\~/$HOME}"
  [ -n "$dst" ] || dst="$(ask "$(t q_restore_into)" "$(default_stack_dir_for "$DEFAULT_STACK_NAME")")"
  dst="${dst/#\~/$HOME}"; mkdir -p "$dst"
  local pass; printf 'Backup password: ' >&2; stty -echo 2>/dev/null; IFS= read -r pass; stty echo 2>/dev/null; printf '\n' >&2
  "$SEVENZIP_BIN" x -p"$pass" -o"$dst" "$arc" -y >/dev/null 2>&1 || { echo 'restore failed (wrong password?)'; return 1; }
  STACK_DIR="$dst"; load_config || true
  printf '%s%s%s %s\n' "$C_GREEN" "$(t done_word)" "$C_RESET" "$dst"
  printf '  %s%s start%s\n' "$C_DIM" "$MGMT_NAME" "$C_RESET"
}
# ───────────────────────────── cron / self-update / checks ─────────────────────────────
# Docker image auto-update (weekly): pull + recreate changed containers.
cron_marker() { printf 'psai-autoupdate:%s' "$SAFE_STACK_NAME"; }

cron_install() {
  load_config || { echo "$(t no_env)"; return 1; }
  detect_os
  local cmd="$STACK_DIR/bin/$MGMT_NAME update"
  case "$OS_TYPE" in
    linux) ( crontab -l 2>/dev/null | grep -v "$(cron_marker)"; printf '0 4 * * 0 %s >/dev/null 2>&1 # %s\n' "$cmd" "$(cron_marker)" ) | crontab - ;;
    macos) ( crontab -l 2>/dev/null | grep -v "$(cron_marker)"; printf '0 4 * * 0 %s >/dev/null 2>&1 # %s\n' "$cmd" "$(cron_marker)" ) | crontab - 2>/dev/null || true ;;
  esac
  printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
}
cron_remove() {
  load_config 2>/dev/null || true
  crontab -l 2>/dev/null | grep -v "$(cron_marker)" | crontab - 2>/dev/null || true
  printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
}

# Pull the latest installer from the public RAW url (when configured) and replace
# the in-stack copy. No-op with a clear note until REPO_RAW_URL is filled.
sha256_of() { ( shasum -a 256 "$1" 2>/dev/null || sha256sum "$1" ) | awk '{print $1}'; }

self_update() {
  [ -n "${REPO_RAW_URL:-}" ] || { printf 'self-update: REPO_RAW_URL not set (fill it for the public release).\n'; return 0; }
  local tmp; tmp="$(mktemp)"
  curl -fsSL "$REPO_RAW_URL" -o "$tmp" || { echo 'download failed'; rm -f "$tmp"; return 1; }
  bash -n "$tmp" || { echo 'downloaded file failed syntax check'; rm -f "$tmp"; return 1; }

  # Verify against versions.json. The signed manifest is the trust anchor: the sha256
  # lives IN versions.json, so it only means something once the manifest's SSH
  # signature checks out against the PINNED public key. A pubkey fetched (or a sha256
  # taken) from the same place as the payload proves nothing, and `bash -n` is only a
  # SYNTAX check — neither proves authenticity. So a signature anchor is MANDATORY for
  # any applied update: refuse outright unless BOTH the manifest URL and the pinned key
  # are configured (fail closed), then require a valid signature below.
  if [ -z "${REPO_VERSIONS_URL:-}" ] || [ -z "${UPDATE_SIGN_PUBKEY:-}" ]; then
    printf '%sself-update: signature trust anchor not configured (need REPO_VERSIONS_URL + pinned UPDATE_SIGN_PUBKEY) — refusing%s\n' "$C_RED" "$C_RESET"
    rm -f "$tmp"; return 1
  fi
  if [ -n "${REPO_VERSIONS_URL:-}" ]; then
    command_exists ssh-keygen || { echo 'ssh-keygen required to verify the signed manifest — install openssh'; rm -f "$tmp"; return 1; }
    local vjson sig allow; vjson="$(mktemp)"; sig="$(mktemp)"; allow="$(mktemp)"
    curl -fsSL "$REPO_VERSIONS_URL" -o "$vjson" || { echo 'versions.json download failed'; rm -f "$tmp" "$vjson" "$sig" "$allow"; return 1; }
    curl -fsSL "$REPO_VERSIONS_URL.sig" -o "$sig" || { echo 'versions.json.sig download failed'; rm -f "$tmp" "$vjson" "$sig" "$allow"; return 1; }
    # Verify the SSH signature (ssh-keygen -Y) against the PINNED public key. The signed
    # manifest is the trust anchor; the installer_sha256 inside it is only trusted once this
    # passes. Fail closed on any mismatch.
    printf '%s %s\n' "${UPDATE_SIGN_ID:-psai}" "$UPDATE_SIGN_PUBKEY" > "$allow"
    if ! ssh-keygen -Y verify -f "$allow" -I "${UPDATE_SIGN_ID:-psai}" -n "${UPDATE_SIGN_NS:-psai-versions}" -s "$sig" < "$vjson" >/dev/null 2>&1; then
      printf '%sself-update: versions.json signature INVALID — aborting%s\n' "$C_RED" "$C_RESET"; rm -f "$tmp" "$vjson" "$sig" "$allow"; return 1
    fi
    rm -f "$sig" "$allow"
    local want got; want="$(sed -n 's/.*"installer_sha256": *"\([a-f0-9]*\)".*/\1/p' "$vjson" | head -1)"
    got="$(sha256_of "$tmp")"
    if [ -n "$want" ] && [ "$want" != "$got" ]; then
      printf '%sself-update: sha256 mismatch — aborting%s\n' "$C_RED" "$C_RESET"; rm -f "$tmp" "$vjson"; return 1
    fi
    rm -f "$vjson"
  fi

  if load_config 2>/dev/null && [ -d "$STACK_DIR/bin" ]; then cp "$tmp" "$STACK_DIR/bin/$MGMT_NAME"; chmod +x "$STACK_DIR/bin/$MGMT_NAME"; fi
  rm -f "$tmp"; printf '%s%s%s\n' "$C_GREEN" "$(t done_word)" "$C_RESET"
}

# ── diagnostics ──
health_check() {
  load_config || { echo "$(t no_env)"; return 1; }
  ensure_path_brew; collect_components
  printf '%s\n' "${COMP_LIST:-no containers}"
}
install_check() {
  load_config || { echo "$(t no_env)"; return 1; }
  printf 'stack:    %s\n' "$STACK_DIR"
  printf 'compose:  %s\n' "$([ -f "$STACK_DIR/compose/docker-compose.yml" ] && echo ok || echo missing)"
  printf 'caddy:    %s\n' "$([ -f "$STACK_DIR/compose/Caddyfile" ] && echo ok || echo missing)"
  printf 'secrets:  %s\n' "$([ -f "$STACK_DIR/secrets/passwords.txt" ] || seal_enabled && echo ok || echo missing)"
}
security_check() {
  load_config || { echo "$(t no_env)"; return 1; }
  printf 'profile:   %s\n' "$SECURITY_PROFILE"
  printf 'seal:      %s (%s)\n' "$(seal_status_label)" "$SEAL_MODE"
  local fw; fw="$(firewall_status)"
  # Flag the gap between intent and reality: the profile asked for a firewall but it isn't
  # actually up (e.g. install ran without admin) — so the status doesn't quietly look fine.
  if [ "${SEC_FIREWALL:-false}" = "true" ] && [ "$fw" != "on" ]; then
    printf 'firewall:  %s  (profile wants ON — run: sudo %s harden)\n' "$fw" "$MGMT_NAME"
  else
    printf 'firewall:  %s\n' "$fw"
  fi
  printf 'watchdog:  %s\n' "$(watchdog_state)"
}
# ───────────────────────────── main ─────────────────────────────
main() {
  detect_os
  ensure_path_brew
  case "${1:-}" in --lang) UI_LANG="${2:-}"; LANG_FROM_ENV="1"; shift 2 || true ;; esac
  load_lang

  case "${1:-}" in
    install)
      shift || true
      case "${1:-}" in --defaults|-y|--yes) ASSUME_DEFAULTS="1"; NONINTERACTIVE="1" ;; esac
      ensure_lang; perform_install ;;
    start)      start_stack ;;
    stop)       stop_stack ;;
    status)     status_stack ;;
    restart)    restart_stack ;;
    logs)       shift || true; logs_stack "${1:-}" ;;
    update)     ensure_lang; update_rebuild ;;
    rebuild)    ensure_lang; rebuild_only ;;
    upgrade)    ensure_lang; component_manager ;;
    backup)     shift || true; ensure_lang; backup_stack "$@" ;;
    restore)    shift || true; ensure_lang; restore_stack "$@" ;;
    proxy|egress)   ensure_lang; load_config && proxy_menu ;;
    security)   ensure_lang; load_config && security_menu ;;
    seal)       ensure_lang; seal_now ;;
    unseal)     ensure_lang; unseal_now ;;
    watchdog)     ensure_lang; watchdog_menu ;;
    watchdog-on)  ensure_lang; watchdog_enable ;;
    watchdog-off) ensure_lang; watchdog_disable ;;
    harden)       shift || true; ensure_lang; load_config 2>/dev/null; harden_host "${1:-}" ;;
    trust-ca)     ensure_lang; trust_ca ;;
    add-hosts)    load_config || exit 1; ensure_lang; add_hosts_entries ;;
    cron-install) ensure_lang; cron_install ;;
    cron-remove)  ensure_lang; cron_remove ;;
    self-update)  ensure_lang; self_update ;;
    uninstall)    shift || true; ensure_lang; uninstall_stack "$@" ;;
    agents|isolate-agents|remote-agents) shift || true; ensure_lang; remote_agents "$@" ;;
    rekey)        shift || true; ensure_lang; load_config && ra_rekey "$@" ;;
    kms-node)     shift || true; ensure_lang; load_config && ra_install_kms_node "$@" ;;
    state|collect-state) shift || true; ensure_lang; load_config && ra_collect_state "$@" ;;
    fleet)        ensure_lang; load_config && fleet_menu ;;
    health|--health)                 ensure_lang; health_check ;;
    check-install|--check-install)   ensure_lang; install_check ;;
    check-security|--check-security) ensure_lang; security_check ;;
    help|-h|--help)  ensure_lang; print_help ;;
    --version|-v)    echo "$STACK_VERSION $STACK_CHANNEL ($STACK_VERSION_TAG)" ;;
    "")
      if load_config >/dev/null 2>&1; then installed_menu; else bootstrap_menu; fi ;;
    *) usage; exit 1 ;;
  esac
}

# Run only when executed directly (allows sourcing for tests).
if [ "${BASH_SOURCE[0]}" = "${0}" ]; then
  main "$@"
fi
